-- Reorder a photoset. `photo_ids` is the ordered, comma-delimited list of photo
-- ids; photos not named keep their original relative order (so passing a single
-- id moves just that photo to the front). Accepts a list (joined here) or a
-- pre-built string. Returns true on success, or (nil, err) (issue #31).
function M.photosets_reorder_photos(api_key, api_secret, account, photoset_id, photo_ids)
  if not photoset_id or photoset_id == "" then return nil, "missing photoset id" end
  if type(photo_ids) == "table" then photo_ids = table.concat(photo_ids, ",") end
  if not photo_ids or photo_ids == "" then return nil, "missing photo ids" end

  local body, err = M.call(api_key, api_secret, account, "flickr.photosets.reorderPhotos", {
    photoset_id = photoset_id,
    photo_ids = photo_ids,
  })
  if not body then return nil, err end
  return true
end

-- Extract the top-level attributes of an XML open tag's attribute string into a
-- name -> value map, respecting quoting. Naive per-attribute substring matching
-- (`attrs:match('photos="(.-)"')`) is unsafe here: `photos` is a *substring* of
-- `has_requested_photos`, so a `has_requested_photos="…"` attribute would have its
-- value captured as the photo count; and an `id="…"` embedded inside another
-- attribute's quoted value (the defensive nested-id membership shape
-- `has_requested_photos='id="123"'`) would be grabbed as the photoset id,
-- corrupting the id used for membership. Walking name="value"/name='value' pairs
-- and skipping over quoted contents avoids both. (Reachable only via the
-- defensive attribute shapes parse_photosets explicitly supports — live
-- `getList` responses carry membership as child markers — but those shapes must
-- parse correctly when present.)
local function parse_attrs(attrs)
  local out = {}
  -- Single left-to-right pass: each `name=<quote>value<quote>` pair consumes its
  -- whole quoted value (the %2 back-reference matches the opening quote), so a
  -- quote of the other kind inside a value — `has_requested_photos='id="123"'` —
  -- is treated as value content, not a new attribute, and a full attribute name
  -- (`has_requested_photos`) is matched as one token rather than letting its
  -- `photos` tail be read as a separate `photos` attribute. First occurrence of a
  -- name wins.
  for name, _, value in tostring(attrs or ""):gmatch('([%w_:%-]+)%s*=%s*(["\'])(.-)%2') do
    if out[name] == nil then out[name] = value end
  end
  return out
end
M.parse_attrs = parse_attrs

function M.parse_photosets(body)
  local sets = {}
  body = tostring(body or "")
  -- Scan each <photoset ...> open tag, then decide whether it is self-closing
  -- (`<photoset ... />`, no children) or a normal element with an inner body up
  -- to `</photoset>`. The old single-pattern form
  -- (`<photoset%s+([^>]*)>(.-)</photoset>`) silently dropped any self-closing
  -- photoset because it required a closing tag. Harmless against today's live
  -- responses — `flickr.photosets.getList` always returns child elements
  -- (`<title>`/`<description>` and the `<has_photo />`/`<has_requested_photos />`
  -- membership markers), so every set has a closing tag — but a childless
  -- self-closing set would have vanished from the list/membership with no error.
  -- Accept both shapes defensively.
  local pos = 1
  while true do
    local open_s, open_e, attrs = body:find("<photoset%s+([^>]*)>", pos)
    if not open_s then break end
    local inner = ""
    if attrs:sub(-1) == "/" then
      -- Self-closing `<photoset ... />`: strip the trailing slash from attrs,
      -- no inner content. (A self-closing set carries no child markers, so its
      -- membership can only come from a has_requested_photos attribute.)
      attrs = attrs:gsub("%s*/%s*$", "")
      pos = open_e + 1
    else
      local close_s, close_e, content = body:find("(.-)</photoset>", open_e + 1)
      if close_s then
        inner = content
        pos = close_e + 1
      else
        -- Open tag with no matching close: treat as empty-bodied and advance
        -- past the open tag so the scan can't loop forever.
        pos = open_e + 1
      end
    end
    local attr = parse_attrs(attrs)
    local id = attr.id
    local title = inner:match("<title>(.-)</title>") or ""
    if id and id ~= "" then
      local requested = attr.has_requested_photos
        or inner:match("<has_requested_photos>(.-)</has_requested_photos>")
        or ""
      sets[#sets + 1] = {
        id = xml_unescape(id),
        title = xml_unescape(title),
        photos = attr.photos,
        videos = attr.videos,
        has_requested_photos = xml_unescape(requested),
        -- Membership marker. Live responses always use the self-closing
        -- `<has_requested_photos />`, but accept the equivalent empty paired form
        -- `<has_requested_photos></has_requested_photos>` too, so a serialization
        -- change can't silently drop a real membership (matches the "accept
        -- defensive alternate shapes" rule in CLAUDE.md).
        has_requested_photos_marker = (inner:find("<has_requested_photos%s*/>", 1)
          or inner:find("<has_requested_photos%s*>%s*</has_requested_photos>", 1)) ~= nil,
        has_photo_marker = (inner:find("<has_photo%s*/>", 1)
          or inner:find("<has_photo%s*>%s*</has_photo>", 1)) ~= nil,
      }
    end
  end
  return sets
end

local function photoset_has_requested_photo(item, photo_id)
  photo_id = tostring(photo_id or "")
  if photo_id == "" or not item then return false end
  local requested = tostring(item.has_requested_photos or "")
  for id in requested:gmatch("[^,%s]+") do
    if id == photo_id then return true end
  end
  for id in requested:gmatch('id="(.-)"') do
    if id == photo_id then return true end
  end
  for id in requested:gmatch("id='(.-)'") do
    if id == photo_id then return true end
  end
  -- Membership is signalled ONLY by `<has_requested_photos />` (the documented,
  -- live-verified rule in CLAUDE.md). `<has_photo />` is the `sort_groups=has_photo`
  -- ordering hint, not a membership flag: `flickr.photosets.getList` with
  -- `photo_ids` returns ALL of the account's sets (non-matching ones merely sorted
  -- after), so treating `has_photo` as membership could falsely report a set the
  -- photo is not in. `has_photo_marker` is still parsed (it may be useful for
  -- sort-order reasoning) but must not, on its own, count as membership.
  if item.has_requested_photos_marker then return true end
  return false
end
M.photoset_has_requested_photo = photoset_has_requested_photo

function M.parse_page_info(body, container)
  container = container or "photosets"
  local attrs = tostring(body or ""):match("<" .. container .. "%s+([^>]*)>")
  -- pages = nil signals "could not find the <container> wrapper" so paged_call can
  -- distinguish a malformed/unexpected body from a real single-page response.
  -- (A real single page reports pages="1"; Flickr always emits the wrapper, even
  -- for zero results: <photos page="1" pages="0" total="0" />.)
  if not attrs then return 1, nil, nil end
  local page = tonumber(attrs:match('page="(.-)"') or attrs:match("page='(.-)'")) or 1
  local pages = tonumber(attrs:match('pages="(.-)"') or attrs:match("pages='(.-)'")) or 1
  local total = tonumber(attrs:match('total="(.-)"') or attrs:match("total='(.-)'"))
  return page, pages, total
end

function M.paged_call(api_key, api_secret, account, method, args, container, opts)
  opts = opts or {}
  args = args or {}
  if not method or method == "" then return nil, "missing Flickr REST method" end

  local bodies, page_infos = {}, {}
  local page = tonumber(opts.start_page or args.page) or 1
  local per_page = tonumber(opts.per_page or args.per_page) or 500
  local max_pages = tonumber(opts.max_pages) or 0
  local start_page = page
  local pages = page

  while page <= pages do
    if opts.cancelled and opts.cancelled(page) then
      return nil, "cancelled Flickr paged request"
    end

    local page_args = {}
    for k, v in pairs(args) do page_args[k] = v end
    page_args.page = page
    page_args.per_page = per_page

    local body, err
    if opts.public or not (account and account.token and account.secret) then
      body, err = M.public_call(api_key, method, page_args)
    else
      body, err = M.call(api_key, api_secret, account, method, page_args)
    end
    if not body then return nil, err end

    bodies[#bodies + 1] = body
    local current_page, page_count, total = M.parse_page_info(body, container)
    -- A `stat="ok"` body that lacks the <container> wrapper is malformed/truncated
    -- (page_count == nil), on ANY page. Silently returning the pages collected so
    -- far would let callers (notably claim's candidate search and album-membership
    -- refresh) conclude "no match"/under-report memberships from an incomplete set
    -- — and because parse_page_info can't read the page count from a wrapperless
    -- body, a *later* malformed page also contributes zero parsed items with no
    -- error. Fail loudly on any missing wrapper so the shared queue retries the
    -- whole read with backoff (the message is classified transient in queue.lua).
    -- A truncated page-1 OR page-N are both genuine transport/CDN failures here:
    -- every legitimate Flickr page carries its <photos>/<photosets> wrapper.
    if page_count == nil then
      return nil, "unparseable Flickr paged response (missing <" .. container .. "> wrapper)"
    end
    page_infos[#page_infos + 1] = { page = current_page, pages = page_count, total = total }
    if opts.on_page then opts.on_page(body, page_infos[#page_infos], page) end

    pages = page_count or pages
    -- Cap against the *start* page, not the moving counter. `page` increments
    -- below, so clamping to `page + max_pages - 1` would re-raise the ceiling by
    -- one each iteration and defeat the cap entirely (it would walk every page).
    if max_pages > 0 and pages > start_page + max_pages - 1 then
      pages = start_page + max_pages - 1
    end
    page = page + 1
  end

  return bodies, page_infos
end

function M.photosets_get_list(api_key, api_secret, account, user_id, opts)
  if type(user_id) == "table" and opts == nil then
    opts = user_id
    user_id = nil
  end
  opts = opts or {}
  local nsid = user_id or opts.user_id or (account and account.nsid) or nil
  if not nsid or nsid == "" then return nil, "missing user id" end

  local args = { user_id = nsid }
  if opts.photo_ids and opts.photo_ids ~= "" then
    args.photo_ids = opts.photo_ids
    args.sort_groups = opts.sort_groups or "has_photo"
  end

  local all_sets = {}
  local bodies, err = M.paged_call(api_key, api_secret, account, "flickr.photosets.getList", args, "photosets", {
    per_page = opts.per_page or 500,
    public = not (account and account.token and account.secret),
    cancelled = opts.cancelled,
    on_page = function(body)
      for _, item in ipairs(M.parse_photosets(body)) do all_sets[#all_sets + 1] = item end
    end,
  })
  if not bodies then return nil, err end

  return all_sets, table.concat(bodies, "\n")
end

function M.photosets_get_memberships(api_key, api_secret, account, photo_id, user_id)
  if not photo_id or photo_id == "" then return nil, "missing photo id" end
  local sets, body = M.photosets_get_list(api_key, api_secret, account, user_id, {
    photo_ids = photo_id,
    sort_groups = "has_photo",
  })
  if not sets then return nil, body end

  local memberships = {}
  for _, item in ipairs(sets) do
    if photoset_has_requested_photo(item, photo_id) then
      memberships[#memberships + 1] = item
    end
  end
  return memberships, body, sets
end

-- ---------------------------------------------------------------------------
-- Groups / pools (issue #32) — shared community galleries, distinct from
-- albums/photosets. flickr.groups.pools.getGroups lists the groups the
-- authenticated user can post to; add/remove move a photo in/out of a pool.
-- ---------------------------------------------------------------------------

-- Parse a flickr.groups.pools.getGroups response into a list of group items:
--   { nsid, name, photos, privacy, admin, iconserver }
-- Groups are self-closing `<group nsid="…" name="…" … />` elements; accept a
-- non-self-closing form too (defensive, matches the parse_photosets discipline).
function M.parse_groups(body)
  local groups = {}
  body = tostring(body or "")
  for attrs in body:gmatch("<group%s+([^>]*)>") do
    -- Strip a trailing self-closing slash before attribute parsing.
    attrs = attrs:gsub("%s*/%s*$", "")
    local attr = parse_attrs(attrs)
    local nsid = attr.nsid or attr.id
    if nsid and nsid ~= "" then
      groups[#groups + 1] = {
        nsid = xml_unescape(nsid),
        name = xml_unescape(attr.name or ""),
        photos = attr.photos,
        privacy = attr.privacy,
        admin = attr.admin,
        iconserver = attr.iconserver,
      }
    end
  end
  return groups
end

-- List the groups the authenticated user can add photos to. Requires a signed
-- (read) call — getGroups has no public variant. Pages at up to 400 per page
-- (Flickr's max) on the <groups> wrapper. Returns (groups, raw_body) or
-- (nil, err).
function M.groups_pools_get_groups(api_key, api_secret, account, opts)
  opts = opts or {}
  if not (account and account.token and account.secret) then
    return nil, "missing account credentials"
  end

  local all_groups = {}
  local bodies, err = M.paged_call(api_key, api_secret, account, "flickr.groups.pools.getGroups", {}, "groups", {
    per_page = opts.per_page or 400,
    cancelled = opts.cancelled,
    on_page = function(body)
      for _, item in ipairs(M.parse_groups(body)) do all_groups[#all_groups + 1] = item end
    end,
  })
  if not bodies then return nil, err end
  return all_groups, table.concat(bodies, "\n")
end

-- Add a photo to a group's pool (flickr.groups.pools.add). Returns true on
-- success, or (nil, err) — the caller (groups.classify_add) maps the Flickr
-- error code in `err` to an outcome (already-in-pool, pending moderation,
-- per-group/per-user limit, rejected, …).
function M.groups_pools_add(api_key, api_secret, account, group_id, photo_id)
  if not group_id or group_id == "" then return nil, "missing group id" end
  if not photo_id or photo_id == "" then return nil, "missing photo id" end

  local body, err = M.call(api_key, api_secret, account, "flickr.groups.pools.add", {
    group_id = group_id,
    photo_id = photo_id,
  })
  if not body then return nil, err end
  return true
end

-- Remove a photo from a group's pool (flickr.groups.pools.remove). Returns true
-- on success, or (nil, err).
function M.groups_pools_remove(api_key, api_secret, account, group_id, photo_id)
  if not group_id or group_id == "" then return nil, "missing group id" end
  if not photo_id or photo_id == "" then return nil, "missing photo id" end

  local body, err = M.call(api_key, api_secret, account, "flickr.groups.pools.remove", {
