-- Remove the geo (location) data from a photo (flickr.photos.geo.removeLocation).
-- This is the privacy "strip GPS" / "remove location" operation (issue #23).
-- Flickr returns REST error 2 ("Photo has no location information") when the
-- photo was never geotagged; for an idempotent strip that is the desired end
-- state, so we treat code 2 as success (nothing to remove = already stripped).
-- Requires a token with 'write' permission.
function M.photos_geo_remove_location(api_key, api_secret, account, photo_id)
  if not photo_id or photo_id == "" then return nil, "missing photo id" end

  local body, err = M.call(api_key, api_secret, account, "flickr.photos.geo.removeLocation", {
    photo_id = photo_id,
  })
  if not body then
    if tonumber(tostring(err or ""):match("Flickr REST failed %((%d+)%)")) == 2 then
      return true   -- already has no location; the strip is a no-op success
    end
    return nil, err
  end
  return true
end

-- Set who may view the geo data of a photo (flickr.photos.geo.setPerms). All four
-- audience flags are required by Flickr; pass 1/0. Provided for geo-privacy
-- overrides (issue #23) — e.g. keep the location on Flickr but restrict who sees
-- it, rather than removing it outright. Requires 'write' permission.
function M.photos_geo_set_perms(api_key, api_secret, account, photo_id, is_public, is_contact, is_friend, is_family)
  if not photo_id or photo_id == "" then return nil, "missing photo id" end

  local function flag(v) return (v == true or tostring(v) == "1") and "1" or "0" end
  local body, err = M.call(api_key, api_secret, account, "flickr.photos.geo.setPerms", {
    photo_id = photo_id,
    is_public = flag(is_public),
    is_contact = flag(is_contact),
    is_friend = flag(is_friend),
    is_family = flag(is_family),
    _allow_empty = { is_public = true, is_contact = true, is_friend = true, is_family = true },
  })
  if not body then return nil, err end
  return true
end

-- Parse a flickr.photos.upload.checkTickets response into a map keyed by ticket
-- id. Each entry: { id, complete = 0|1|2|nil, photo_id = "..."|nil, invalid }.
-- Flickr's status attribute is historically named `complete` (0 = processing,
-- 1 = done with a photoid, 2 = conversion failed); we also accept `status` for
-- safety. A ticket Flickr did not recognise carries `invalid="1"`.
function M.parse_upload_tickets(body)
  local tickets = {}
  for attrs in tostring(body or ""):gmatch("<ticket%s+([^>]*)>") do
    local id = attrs:match('id="(.-)"') or attrs:match("id='(.-)'")
    if id and id ~= "" then
      local complete = attrs:match('complete="(.-)"') or attrs:match("complete='(.-)'")
        or attrs:match('status="(.-)"') or attrs:match("status='(.-)'")
      local photoid = attrs:match('photoid="(.-)"') or attrs:match("photoid='(.-)'")
      local invalid = attrs:match('invalid="(.-)"') or attrs:match("invalid='(.-)'")
      tickets[xml_unescape(id)] = {
        id = xml_unescape(id),
        complete = complete and tonumber(complete) or nil,
        photo_id = (photoid and photoid ~= "") and xml_unescape(photoid) or nil,
        invalid = invalid ~= nil and invalid ~= "" and invalid ~= "0",
      }
    end
  end
  return tickets
end

-- Parse a flickr.photos.people.getList response into a list of the people tagged
-- on a photo. Each <person .../> carries at least an nsid; username/realname and
-- the optional bounding-box coords (x/y/w/h) are passed through when present.
-- parse_attrs walks quoted name=value pairs, so a realname containing spaces or an
-- attribute whose name is a substring of another is handled safely.
function M.parse_people(body)
  local people = {}
  for attrs in tostring(body or ""):gmatch("<person%s+([^>]*)>") do
    local a = parse_attrs(attrs)
    local nsid = a.nsid
    if nsid and nsid ~= "" then
      people[#people + 1] = {
        nsid = xml_unescape(nsid),
        username = a.username and xml_unescape(a.username) or nil,
        realname = a.realname and xml_unescape(a.realname) or nil,
        added_by = a.added_by and xml_unescape(a.added_by) or nil,
        x = a.x, y = a.y, w = a.w, h = a.h,
      }
    end
  end
  return people
end

-- Parse a flickr.people.findByUsername / findByEmail response. Both return the
-- same shape: <user nsid="12037949632@N01"><username>Stewart</username></user>.
-- Returns { nsid, username } or nil when no user element is present.
function M.parse_find_user(body)
  body = tostring(body or "")
  local nsid = body:match('<user[^>]-nsid="(.-)"') or body:match("<user[^>]-nsid='(.-)'")
  if not nsid or nsid == "" then return nil end
  local username = body:match("<username>(.-)</username>")
  return { nsid = xml_unescape(nsid), username = username and xml_unescape(username) or nil }
end

-- List the people tagged on a photo. flickr.photos.people.getList does not strictly
-- require authentication, but a signed call is used so people on the account's own
-- non-public photos are visible. Idempotent read. Returns (people, body).
function M.people_get_list(api_key, api_secret, account, photo_id)
  if not photo_id or photo_id == "" then return nil, "missing photo id" end
  local body, err = M.call(api_key, api_secret, account, "flickr.photos.people.getList", {
    photo_id = photo_id,
  })
  if not body then return nil, err end
  return M.parse_people(body), body
end

-- Resolve a username to an NSID. Unauthenticated read (public API key). Returns
-- ({ nsid, username }, body) or (nil, err) — a "User not found" (Flickr code 1)
-- surfaces as a normal REST error string.
function M.people_find_by_username(api_key, username)
  username = tostring(username or "")
  if username == "" then return nil, "missing username" end
  local body, err = M.public_call(api_key, "flickr.people.findByUsername", { username = username })
  if not body then return nil, err end
  local user = M.parse_find_user(body)
  if not user then return nil, "Flickr returned no user for that username" end
  return user, body
end

-- Resolve an email address to an NSID. Unauthenticated read (public API key).
-- Returns ({ nsid, username }, body) or (nil, err).
function M.people_find_by_email(api_key, email)
  email = tostring(email or "")
  if email == "" then return nil, "missing email" end
  local body, err = M.public_call(api_key, "flickr.people.findByEmail", { find_email = email })
  if not body then return nil, err end
  local user = M.parse_find_user(body)
  if not user then return nil, "Flickr returned no user for that email" end
  return user, body
end

-- Add a person (by NSID) to a photo. Requires 'write' permission and an HTTP POST
-- (M.call already POSTs). Coordinates are intentionally omitted — Flickr accepts a
-- coordinate-less person tag. Returns true or (nil, err).
function M.people_add(api_key, api_secret, account, photo_id, user_id)
  if not photo_id or photo_id == "" then return nil, "missing photo id" end
  if not user_id or user_id == "" then return nil, "missing user id" end
  local body, err = M.call(api_key, api_secret, account, "flickr.photos.people.add", {
    photo_id = photo_id,
    user_id = user_id,
  })
  if not body then return nil, err end
  return true
end

-- Check the status of one or more asynchronous upload tickets. Unauthenticated
-- (uses the public API key), so it is an idempotent read safe to poll/retry.
function M.upload_check_tickets(api_key, ticket_ids)
  if type(ticket_ids) == "table" then ticket_ids = table.concat(ticket_ids, ",") end
  ticket_ids = tostring(ticket_ids or "")
  if ticket_ids == "" then return nil, "missing upload ticket id(s)" end

  local body, err = M.public_call(api_key, "flickr.photos.upload.checkTickets", {
    tickets = ticket_ids,
  })
  if not body then return nil, err end
  return M.parse_upload_tickets(body), body
end

return M
end

package.preload["dtrmflickr.state"] = function(...)
-- state.lua — per-image Flickr publish state.
--
-- This is the only module that knows how state is persisted. The current
-- backend is image tags because they are Lua-writable, per-image, multi-valued,
-- and survive through XMP sidecars when sidecars are enabled.

local dt = require "darktable"

local M = {}

local PREFIX <const> = "dtrmflickr"

local function tag_name(tag)
  return tag and tag.name or nil
end

local function photo_tag(account_nsid, photo_id)
  return table.concat({ PREFIX, tostring(account_nsid), tostring(photo_id) }, "|")
end

local function set_tag(account_nsid, set_id)
  return table.concat({ PREFIX, tostring(account_nsid), "set", tostring(set_id) }, "|")
end

local function published_tag(account_nsid, kind, stamp)
  if kind == nil then return table.concat({ PREFIX, tostring(account_nsid), "published", tostring(stamp) }, "|") end
  return table.concat({ PREFIX, tostring(account_nsid), "published", tostring(kind), tostring(stamp) }, "|")
end

local function needs_republish_tag(account_nsid)
  return table.concat({ PREFIX, tostring(account_nsid), "needs-republish" }, "|")
end

local function uploaded_tag(account_nsid, stamp)
  return table.concat({ PREFIX, tostring(account_nsid), "uploaded", tostring(stamp) }, "|")
end

local function reason_tag(account_nsid, reason)
  return table.concat({ PREFIX, tostring(account_nsid), "reason", tostring(reason) }, "|")
end

local function fingerprint_tag(account_nsid, field, fingerprint)
  return table.concat({ PREFIX, tostring(account_nsid), "fingerprint", tostring(field), tostring(fingerprint) }, "|")
end

local function valid_component(value)
  value = tostring(value or "")
  return value ~= "" and value:find("|", 1, true) == nil
end

local function assert_component(kind, value)
  assert(valid_component(value), "invalid Flickr " .. kind)
end

local function is_reserved_account_component(value)
  return value == "set" or value == "published" or value == "needs-republish"
    or value == "reason" or value == "uploaded"
end

local function ensure_tag(name)
  return dt.tags.find(name) or dt.tags.create(name)
end

local function image_tags(image)
  if image and image.get_tags then return image:get_tags() end
  return dt.tags.get_tags(image)
end

local function attach(image, tag)
  if image and image.attach_tag then return image:attach_tag(tag) end
  return dt.tags.attach(tag, image)
end

local function detach(image, tag)
  if image and image.detach_tag then return image:detach_tag(tag) end
  return dt.tags.detach(tag, image)
end

function M.is_plugin_tag(name)
  return type(name) == "string" and (name == PREFIX or name:sub(1, #PREFIX + 1) == PREFIX .. "|")
end

function M.now_stamp()
  return os.date("!%Y%m%dT%H%M%SZ")
end

local function normalize_stamp(value)
  value = tostring(value or ""):match("^%s*(.-)%s*$")
  if value == "" then return nil end
  local y, mo, d, h, mi, s = value:match("^(%d%d%d%d)(%d%d)(%d%d)T(%d%d)(%d%d)(%d%d)Z$")
  if y then return y .. mo .. d .. h .. mi .. s end
  y, mo, d, h, mi, s = value:match("^(%d%d%d%d)[:%-](%d%d)[:%-](%d%d)%s+(%d%d):(%d%d):(%d%d)")
  if y then return y .. mo .. d .. h .. mi .. s end
  return nil
end
M.normalize_stamp = normalize_stamp

local function stamp_is_newer(a, b)
  local na = normalize_stamp(a)
  local nb = normalize_stamp(b)
  if not na or not nb then return false end
  return na > nb
end
M.stamp_is_newer = stamp_is_newer

local function compact_stamp(value)
  local n = normalize_stamp(value)
  if not n then return nil end
  return n:sub(1, 8) .. "T" .. n:sub(9, 14) .. "Z"
end
M.compact_stamp = compact_stamp

function M.get_photo_id(image, account_nsid)
  local prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|"
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local id = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    if id and id ~= "" and not id:find("|", 1, true) and not is_reserved_account_component(id) then return id end
  end
  return nil
end

function M.get_any_photo_id(image)
  local prefix = PREFIX .. "|"
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    if name and name:sub(1, #prefix) == prefix then
      local rest = name:sub(#prefix + 1)
      local account_nsid, photo_id = rest:match("^([^|]+)|([^|]+)$")
      if account_nsid and photo_id and not is_reserved_account_component(photo_id) then return account_nsid, photo_id end
    end
  end
  return nil, nil
end

local function valid_publish_kind(kind)
  return kind == "image" or kind == "metadata"
end

local function latest_published_at(image, account_nsid, kind)
  local prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|published|"
  local latest
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local rest = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    local stamp
    if rest then
      if kind then
        stamp = rest:match("^" .. kind .. "|(.+)$")
      else
        local tag_kind, tag_stamp = rest:match("^([^|]+)|(.+)$")
        if valid_publish_kind(tag_kind) then stamp = tag_stamp else stamp = rest end
      end
    end
    if stamp and normalize_stamp(stamp) and (not latest or stamp_is_newer(stamp, latest)) then latest = stamp end
  end
  return latest
end

function M.get_published_at(image, account_nsid, kind)
  if kind then
    return latest_published_at(image, account_nsid, kind)
  end
  return latest_published_at(image, account_nsid, "image")
    or latest_published_at(image, account_nsid, nil)
end

function M.get_image_published_at(image, account_nsid)
  return M.get_published_at(image, account_nsid, "image")
end

function M.get_metadata_published_at(image, account_nsid)
  return M.get_published_at(image, account_nsid, "metadata")
end

function M.clear_published_at(image, account_nsid, kind)
  assert_component("account id", account_nsid)
  local prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|published|"
  local removed = 0
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local rest = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    local matches = false
    if rest then
      if kind == nil then
        matches = true
      else
        matches = rest:sub(1, #kind + 1) == kind .. "|"
      end
    end
    if matches then
      detach(image, tag)
      removed = removed + 1
    end
  end
  return removed
end

-- Flickr upload date/time (issue #21). Stored separately from the publish stamps
-- (which record when *this plugin* last pushed the image/metadata): `uploaded` is
-- Flickr's own authoritative upload time for the photo, captured from getInfo's
-- `dateuploaded`, or approximated by the local publish time on a fresh upload. It
-- is kept as a per-image tag so it survives in XMP sidecars and is filterable via
-- darktable's collections tag filter for sorting/grouping by when a photo went up.
function M.get_uploaded_at(image, account_nsid)
  local prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|uploaded|"
  local latest
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local stamp = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    if stamp and normalize_stamp(stamp) and (not latest or stamp_is_newer(stamp, latest)) then latest = stamp end
  end
  return latest
end

function M.clear_uploaded_at(image, account_nsid)
  assert_component("account id", account_nsid)
  local prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|uploaded|"
  local removed = 0
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    if name and name:sub(1, #prefix) == prefix then
      detach(image, tag)
      removed = removed + 1
    end
  end
  return removed
end

-- Record Flickr's upload date/time for the photo. `stamp` may be a compact stamp
-- (YYYYMMDDTHHMMSSZ) or a MySQL-style datetime; it is normalized to the compact
-- form. Returns the stored stamp, or nil when `stamp` is unparseable (so a bad
-- getInfo value leaves any existing record untouched). Idempotent: a single
-- uploaded tag is kept per account.
function M.set_uploaded_at(image, account_nsid, stamp)
  assert_component("account id", account_nsid)
  stamp = compact_stamp(stamp)
  if not stamp then return nil end
  if M.get_uploaded_at(image, account_nsid) == stamp then return stamp end
  M.clear_uploaded_at(image, account_nsid)
  attach(image, ensure_tag(uploaded_tag(account_nsid, stamp)))
  return stamp
end

local function set_published_kind_at(image, account_nsid, kind, stamp)
  assert_component("account id", account_nsid)
  assert(valid_publish_kind(kind), "invalid Flickr published kind")
  stamp = stamp or M.now_stamp()
  stamp = compact_stamp(stamp)
  assert(stamp, "invalid Flickr published stamp")
  M.clear_published_at(image, account_nsid, kind)
  attach(image, ensure_tag(published_tag(account_nsid, kind, stamp)))
  return stamp
end

function M.set_image_published_at(image, account_nsid, stamp)
  local result = set_published_kind_at(image, account_nsid, "image", stamp)
  M.clear_reason(image, account_nsid, "image")
  return result
end

function M.set_metadata_published_at(image, account_nsid, stamp)
  return set_published_kind_at(image, account_nsid, "metadata", stamp)
end

function M.set_published_at(image, account_nsid, stamp)
  stamp = stamp or M.now_stamp()
  stamp = compact_stamp(stamp)
  assert(stamp, "invalid Flickr published stamp")
  M.set_image_published_at(image, account_nsid, stamp)
  M.set_metadata_published_at(image, account_nsid, stamp)
  M.clear_metadata_reasons(image, account_nsid)
  M.clear_needs_republish(image, account_nsid)
  return stamp
end

-- Re-mark an already-linked image as published/current without re-uploading
-- pixels (issue #17). Fixes up drifted stored state: refreshes the image and
-- metadata publish stamps, clears any needs-republish reasons, and — unlike a
-- bare set_published_at — snapshots the supplied metadata fingerprints so a later
-- evaluate_publish_state compares edits against a real baseline instead of
-- flipping the photo back to "needs-sync"/"unknown". Returns false (without
-- touching anything) when the image is not linked to this account: there is no
-- published photo to re-mark.
function M.mark_published(image, account_nsid, stamp, fingerprints)
  assert_component("account id", account_nsid)
  if not M.get_photo_id(image, account_nsid) then return false end
  local applied = M.set_published_at(image, account_nsid, stamp)
  if fingerprints then M.set_fingerprints(image, account_nsid, fingerprints) end
  return true, applied
end

function M.mark_reason(image, account_nsid, reason)
  assert_component("account id", account_nsid)
  assert_component("reason", reason)
  attach(image, ensure_tag(reason_tag(account_nsid, reason)))
  attach(image, ensure_tag(needs_republish_tag(account_nsid)))
end

function M.clear_reason(image, account_nsid, reason)
  assert_component("account id", account_nsid)
  assert_component("reason", reason)
  local tag = dt.tags.find(reason_tag(account_nsid, reason))
  if not tag then return false end
  detach(image, tag)
  if #M.get_reasons(image, account_nsid) == 0 then M.clear_needs_republish(image, account_nsid) end
  return true
end

local metadata_reasons = {
  keywords = true,
  title_description = true,
  gps = true,
  date_taken = true,
  visibility = true,
  safety = true,
  content_type = true,
  license = true,
  permissions = true,
}

local function known_metadata_reasons()
  local reasons = {}
  for reason in pairs(metadata_reasons) do reasons[#reasons + 1] = reason end
  table.sort(reasons)
  return reasons
end
M.metadata_reasons = known_metadata_reasons

function M.is_metadata_reason(reason)
  return metadata_reasons[tostring(reason or "")] == true
end

function M.classify_reasons(reasons)
  local has_image = false
  local has_metadata = false
  for _, reason in ipairs(reasons or {}) do
    if reason == "image" then has_image = true
    elseif M.is_metadata_reason(reason) then has_metadata = true
    else has_metadata = true end
  end
  if has_image and has_metadata then return "both" end
  if has_image then return "image" end
  if has_metadata then return "metadata" end
  return "none"
end

-- Human-friendly labels for diff reasons, surfaced in the panel (issue #18).
-- `image` is the pixel reupload; the rest mirror the metadata reason keys.
local reason_labels = {
  image = "image pixels",
  keywords = "keywords",
  title_description = "title/description",
  gps = "GPS location",
  date_taken = "date taken",
  visibility = "visibility",
  safety = "safety level",
  content_type = "content type",
  license = "license",
  permissions = "permissions",
}

-- Stable display order: pixels first, then metadata fields in a fixed sequence
-- so the panel breakdown reads the same way every refresh regardless of the
-- alphabetical tag order get_reasons returns.
local reason_order = {
  "image", "title_description", "keywords", "gps", "date_taken",
  "visibility", "safety", "content_type", "license", "permissions",
}
local reason_rank = {}
for i, reason in ipairs(reason_order) do reason_rank[reason] = i end

function M.reason_label(reason)
  reason = tostring(reason or "")
  return reason_labels[reason] or reason
end

-- describe_reasons(reasons) -> friendly, de-duplicated, stably ordered string
-- (e.g. "title/description, GPS location"). Unknown reasons fall through to
-- their raw key and sort after the known ones. Returns "" for an empty set.
function M.describe_reasons(reasons)
  local seen, ordered = {}, {}
  for _, reason in ipairs(reasons or {}) do
    reason = tostring(reason or "")
    if reason ~= "" and not seen[reason] then
      seen[reason] = true
      ordered[#ordered + 1] = reason
    end
  end
  table.sort(ordered, function(a, b)
    local ra, rb = reason_rank[a], reason_rank[b]
    if ra and rb then return ra < rb end
    if ra then return true end
    if rb then return false end
    return a < b
  end)
  local labels = {}
  for _, reason in ipairs(ordered) do labels[#labels + 1] = M.reason_label(reason) end
  return table.concat(labels, ", ")
end

-- describe_reason_tally(tally) -> friendly per-field breakdown with counts
-- (e.g. "title/description (3), GPS location (1)"). `tally` maps reason key ->
-- count; zero/negative counts are skipped. Returns "" when nothing tallied.
function M.describe_reason_tally(tally)
  local keys = {}
  for reason, count in pairs(tally or {}) do
    if (tonumber(count) or 0) > 0 then keys[#keys + 1] = tostring(reason) end
  end
  table.sort(keys, function(a, b)
    local ra, rb = reason_rank[a], reason_rank[b]
    if ra and rb then return ra < rb end
    if ra then return true end
    if rb then return false end
    return a < b
  end)
  local parts = {}
  for _, reason in ipairs(keys) do
    parts[#parts + 1] = string.format("%s (%d)", M.reason_label(reason), tonumber(tally[reason]))
  end
  return table.concat(parts, ", ")
end

function M.clear_metadata_reasons(image, account_nsid)
  local removed = 0
  for reason in pairs(metadata_reasons) do
    if M.clear_reason(image, account_nsid, reason) then removed = removed + 1 end
  end
  return removed
end

local function fingerprint_prefix(account_nsid, field)
  return PREFIX .. "|" .. tostring(account_nsid) .. "|fingerprint|" .. tostring(field) .. "|"
end

function M.get_fingerprint(image, account_nsid, field)
  local prefix = fingerprint_prefix(account_nsid, field)
  local latest
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local value = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    if valid_component(value) then latest = value end
  end
  return latest
end

function M.clear_fingerprint(image, account_nsid, field)
  assert_component("account id", account_nsid)
  assert_component("fingerprint field", field)
  local prefix = fingerprint_prefix(account_nsid, field)
  local removed = 0
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    if name and name:sub(1, #prefix) == prefix then
      detach(image, tag)
      removed = removed + 1
    end
  end
  return removed
end

function M.set_fingerprint(image, account_nsid, field, fingerprint)
  assert_component("account id", account_nsid)
  assert_component("fingerprint field", field)
  assert_component("fingerprint", fingerprint)
  M.clear_fingerprint(image, account_nsid, field)
  attach(image, ensure_tag(fingerprint_tag(account_nsid, field, fingerprint)))
  return fingerprint
end

function M.set_fingerprints(image, account_nsid, fingerprints)
  local changed = 0
  for field, fingerprint in pairs(fingerprints or {}) do
    if fingerprint ~= nil then
      M.set_fingerprint(image, account_nsid, field, fingerprint)
      changed = changed + 1
    end
  end
  return changed
end

function M.metadata_fingerprint_reasons(image, account_nsid, fingerprints)
  local reasons = {}
  for _, reason in ipairs(known_metadata_reasons()) do
    local current = fingerprints and fingerprints[reason] or nil
    if current ~= nil then
      local previous = M.get_fingerprint(image, account_nsid, reason)
      if previous and previous ~= tostring(current) then reasons[#reasons + 1] = reason end
    end
  end
  table.sort(reasons)
  return reasons
end

function M.get_reasons(image, account_nsid)
  local prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|reason|"
  local reasons = {}
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local reason = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    if valid_component(reason) then reasons[#reasons + 1] = reason end
  end
  table.sort(reasons)
  return reasons
end

function M.mark_needs_republish(image, account_nsid)
  M.mark_reason(image, account_nsid, "image")
end

function M.clear_needs_republish(image, account_nsid)
  assert_component("account id", account_nsid)
  local removed = false
  local reason_prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|reason|"
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    if name and name:sub(1, #reason_prefix) == reason_prefix then
      detach(image, tag)
      removed = true
    end
  end
  local tag = dt.tags.find(needs_republish_tag(account_nsid))
  if tag then
    detach(image, tag)
    removed = true
  end
  return removed
end

function M.needs_republish(image, account_nsid)
  local name = needs_republish_tag(account_nsid)
  local reason_prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|reason|"
  for _, tag in ipairs(image_tags(image) or {}) do
    local tagname = tag_name(tag)
    if tagname == name then return true end
    if tagname and tagname:sub(1, #reason_prefix) == reason_prefix then return true end
  end
  return false
end

function M.evaluate_publish_state(image, account_nsid, opts)
  opts = opts or {}
  local photo_id = M.get_photo_id(image, account_nsid)
  if not photo_id then return "unpublished", nil, nil end

  local image_published_at = M.get_image_published_at(image, account_nsid)
  local metadata_published_at = M.get_metadata_published_at(image, account_nsid)
  local published_at = image_published_at or metadata_published_at or M.get_published_at(image, account_nsid)
  local reasons = M.get_reasons(image, account_nsid)
  if #reasons > 0 or M.needs_republish(image, account_nsid) then
    return "needs-republish", published_at, photo_id, reasons
  end
  if not published_at then
    return "unknown", published_at, photo_id, reasons
  end

  local changed_at = image and image.change_timestamp or nil
  local newest_handled_at = image_published_at
  if metadata_published_at and (not newest_handled_at or stamp_is_newer(metadata_published_at, newest_handled_at)) then
    newest_handled_at = metadata_published_at
  end
  if changed_at and newest_handled_at and stamp_is_newer(changed_at, newest_handled_at) then
    local metadata_requeue = M.metadata_fingerprint_reasons(image, account_nsid, opts.metadata_fingerprints)
    if #metadata_requeue > 0 then
      for _, reason in ipairs(metadata_requeue) do M.mark_reason(image, account_nsid, reason) end
      return "needs-republish", published_at, photo_id, M.get_reasons(image, account_nsid)
    end
    M.mark_needs_republish(image, account_nsid)
    return "needs-republish", published_at, photo_id, M.get_reasons(image, account_nsid)
  end

  M.clear_needs_republish(image, account_nsid)
  return "current", published_at, photo_id, reasons
end

function M.set_photo_id(image, account_nsid, photo_id)
  assert_component("account id", account_nsid)
  assert_component("photo id", photo_id)
  local old_id = M.get_photo_id(image, account_nsid)
  if old_id and old_id ~= tostring(photo_id) then
    local old_tag = dt.tags.find(photo_tag(account_nsid, old_id))
    if old_tag then detach(image, old_tag) end
  end
  attach(image, ensure_tag(photo_tag(account_nsid, photo_id)))
end

function M.clear_photo_id(image, account_nsid)
  assert_component("account id", account_nsid)
  local old_id = M.get_photo_id(image, account_nsid)
  if not old_id then return false end
  local old_tag = dt.tags.find(photo_tag(account_nsid, old_id))
  if old_tag then detach(image, old_tag) end
  M.clear_published_at(image, account_nsid)
  M.clear_uploaded_at(image, account_nsid)
  M.clear_needs_republish(image, account_nsid)
  for _, reason in ipairs(known_metadata_reasons()) do M.clear_fingerprint(image, account_nsid, reason) end
  return true
end

function M.get_sets(image, account_nsid)
  assert_component("account id", account_nsid)
  local prefix = PREFIX .. "|" .. tostring(account_nsid) .. "|set|"
  local sets = {}
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    local id = name and name:sub(1, #prefix) == prefix and name:sub(#prefix + 1) or nil
    if valid_component(id) then sets[#sets + 1] = id end
  end
  table.sort(sets)
  return sets
end

function M.add_set(image, account_nsid, set_id)
  assert_component("account id", account_nsid)
  assert_component("set id", set_id)
  attach(image, ensure_tag(set_tag(account_nsid, set_id)))
end

function M.remove_set(image, account_nsid, set_id)
  assert_component("account id", account_nsid)
  assert_component("set id", set_id)
  local tag = dt.tags.find(set_tag(account_nsid, set_id))
  if tag then detach(image, tag) end
end

function M.clear_sets(image, account_nsid)
  local removed = 0
  for _, set_id in ipairs(M.get_sets(image, account_nsid)) do
    M.remove_set(image, account_nsid, set_id)
    removed = removed + 1
  end
  return removed
end

-- Forget everything this plugin stored for `account_nsid` on `image`: the
-- photo-id link, album memberships, published stamps, needs-sync markers,
-- diff reasons, and cached metadata fingerprints. Used both when switching the
-- active account away from an image and when a photo is deleted from Flickr
-- (issue #19), where the local mapping must be removed so the photo reads as
-- unpublished with no stale needs-sync state left behind.
function M.clear_account(image, account_nsid)
  local removed = M.clear_sets(image, account_nsid)
  removed = removed + M.clear_published_at(image, account_nsid)
  removed = removed + M.clear_metadata_reasons(image, account_nsid)
  if M.clear_reason(image, account_nsid, "image") then removed = removed + 1 end
  for _, field in ipairs(known_metadata_reasons()) do
    removed = removed + M.clear_fingerprint(image, account_nsid, field)
  end
  if M.clear_needs_republish(image, account_nsid) then removed = removed + 1 end
  if M.clear_photo_id(image, account_nsid) then removed = removed + 1 end
  return removed
end

function M.clear_other_accounts(image, keep_account_nsid)
  local keep = tostring(keep_account_nsid)
  local accounts = {}
  local prefix = PREFIX .. "|"
  for _, tag in ipairs(image_tags(image) or {}) do
    local name = tag_name(tag)
    if name and name:sub(1, #prefix) == prefix then
      local account_nsid = name:sub(#prefix + 1):match("^([^|]+)|")
      if account_nsid and account_nsid ~= keep then accounts[account_nsid] = true end
    end
  end
  local removed = 0
  for account_nsid in pairs(accounts) do
    removed = removed + M.clear_account(image, account_nsid)
  end
  return removed
end

return M
end

package.preload["dtrmflickr.metadata"] = function(...)
local dt = require "darktable"
local state = require "dtrmflickr.state"

local M = {}

local TAG_FLAG_CATEGORY <const> = 1
local TAG_FLAG_PRIVATE <const> = 2

function M.image_title(image, filename)
  if image and image.title and image.title ~= "" then return image.title end
  if image and image.filename and image.filename ~= "" then return image.filename end
  return tostring(filename or ""):match("[^/\\]+$") or tostring(filename or "")
end

function M.image_date_taken(image)
  local value = image and image.exif_datetime_taken or nil
  value = value and tostring(value):match("^%s*(.-)%s*$") or nil
  if not value or value == "" then return nil end
  local y, mo, d, h, mi, s = value:match("^(%d%d%d%d)[:%-](%d%d)[:%-](%d%d)%s+(%d%d):(%d%d):(%d%d)")
  if not y then return nil end
  -- Flickr date_taken is a timezone-less taken-local-time field. Do not convert
  -- from darktable's EXIF taken time; just normalize to MySQL datetime syntax.
  return string.format("%s-%s-%s %s:%s:%s", y, mo, d, h, mi, s)
end

-- Format a decimal-degree coordinate to 6 fractional digits WITHOUT going
-- through string.format("%.6f"). C's printf "%f" honours LC_NUMERIC, and
-- darktable runs under setlocale(LC_ALL, "") (the user's locale) without forcing
-- LC_NUMERIC=C for the Lua VM — it only resets numerics locally around specific
-- C code. So on a comma-decimal locale (de_DE, fr_FR, ...) "%.6f" would emit
-- "36,084244", and that string is handed straight to flickr.photos.geo.setLocation
-- as lat/lon, corrupting every geotagged upload's GPS. Build the string from
-- integer parts (%d/%06d carry no decimal separator) with a hardcoded ".", so the
-- output is identical on every locale.
local function format_coord6(n)
  local neg = n < 0
  n = math.abs(n)
  local int = math.floor(n)
  local frac = math.floor((n - int) * 1000000 + 0.5)
  if frac >= 1000000 then int = int + 1; frac = frac - 1000000 end
  return string.format("%s%d.%06d", neg and "-" or "", int, frac)
end

local function flickr_coordinate(value, min_value, max_value)
  local n = tonumber(value)
  if not n or n ~= n or n < min_value or n > max_value then return nil end
  return format_coord6(n)
end

function M.image_location(image)
  local lat = flickr_coordinate(image and image.latitude or nil, -90, 90)
  local lon = flickr_coordinate(image and image.longitude or nil, -180, 180)
  if lat == nil or lon == nil then return nil, nil end
  return lat, lon
end

local function image_tags(image)
  local tags = {}
  if image and image.get_tags then
    tags = image:get_tags() or {}
  else
    tags = dt.tags.get_tags(image) or {}
  end
  table.sort(tags, function(a, b) return tostring(a and a.name or "") < tostring(b and b.name or "") end)
  return tags
end

function M.image_tag_names(image)
  local names = {}
  for _, tag in ipairs(image_tags(image)) do
    local name = tag and tag.name or nil
    if name and name ~= "" then names[#names + 1] = name end
  end
  return names
end

function M.tag_matches_filter(tag_name, filter)
  filter = tostring(filter or ""):match("^%s*(.-)%s*$"):lower()
  if filter == "" then return false end
  return tostring(tag_name or ""):lower():find(filter, 1, true) ~= nil
end

-- Split a (possibly hierarchical) tag name into lowercased, trimmed segments.
local function tag_hierarchy_segments(name)
  local segments = {}
  for seg in tostring(name or ""):gmatch("[^|]+") do
    seg = seg:match("^%s*(.-)%s*$"):lower()
    if seg ~= "" then segments[#segments + 1] = seg end
  end
  return segments
end

-- True when `name`'s hierarchy is at or under `root`: the root's segments must be
-- a leading prefix of the tag's segments (case-insensitive). So root "places"
-- matches "Places", "Places|USA", "Places|USA|VA" but NOT "Marketplaces" (segment
-- compare, not substring) and NOT "Travel|Places" (anchored at the top). Used for
-- omitting auto location-keyword hierarchies from published Flickr tags.
function M.tag_under_location_root(name, root)
  local tag = tag_hierarchy_segments(name)
  local prefix = tag_hierarchy_segments(root)
  if #prefix == 0 or #prefix > #tag then return false end
  for i = 1, #prefix do
    if tag[i] ~= prefix[i] then return false end
  end
  return true
end

local function flickr_quote_tag(tag)
  tag = tostring(tag or "")
  if tag:find("%s") then return '"' .. tag .. '"' end
  return tag
end

local function publish_tag_name(name)
  name = tostring(name or ""):match("^%s*(.-)%s*$")
  local leaf = name:match("([^|]+)$")
  leaf = leaf and leaf:match("^%s*(.-)%s*$") or name
  leaf = leaf:gsub('"', ""):match("^%s*(.-)%s*$")
  return leaf ~= "" and leaf or nil
end

local function tag_flags(tag)
  return tonumber(tag and tag.flags or 0) or 0
end

local function tag_is_private_or_category(tag)
  local flags = tag_flags(tag)
  return (flags & (TAG_FLAG_PRIVATE | TAG_FLAG_CATEGORY)) ~= 0
end

local function has_private_category_parent(name)
  name = tostring(name or "")
  local parent = name:match("^(.*)|[^|]+$")
  while parent and parent ~= "" do
    local parent_tag = dt.tags and dt.tags.find and dt.tags.find(parent) or nil
    local flags = tag_flags(parent_tag)
    if (flags & (TAG_FLAG_PRIVATE | TAG_FLAG_CATEGORY)) == (TAG_FLAG_PRIVATE | TAG_FLAG_CATEGORY) then
      return true
    end
    parent = parent:match("^(.*)|[^|]+$")
  end
  return false
end

local function tag_is_publishable_keyword(tag)
  local name = tag and tag.name or nil
  if not name or name == "" then return false end
  if state.is_plugin_tag(name) or name:match("^darktable|") ~= nil then return false end
  if tag_is_private_or_category(tag) then return false end
  if has_private_category_parent(name) then return false end
  return true
end

-- Compute the publishable Flickr keyword leaf names for an image: plugin/state,
-- darktable|..., private/category, filter-excluded, and (when opts.location_roots
-- is set) location-hierarchy tags removed; hierarchical
-- tags reduced to their leaf; duplicates collapsed case-insensitively; sorted
-- alphabetically. Returns (names, truncated_count) where `truncated_count` is the
-- number dropped by opts.max_tags. This is the single source of truth shared by
-- the upload/setTags path (image_keyword_tags) and the reconciler UI.
function M.image_keyword_names(image, excluded_filters, tag_names, opts)
  opts = opts or {}
  local tags = {}
  local seen = {}
  local source_tags = {}
  if tag_names then
    for _, name in ipairs(tag_names) do
      source_tags[#source_tags + 1] = (dt.tags and dt.tags.find and dt.tags.find(name)) or { name = name }
    end
  else
    source_tags = image_tags(image)
  end
  table.sort(source_tags, function(a, b) return tostring(a and a.name or "") < tostring(b and b.name or "") end)

  for _, tag in ipairs(source_tags) do
    local name = tag and tag.name or nil
    if name and name ~= "" then
      local excluded = not tag_is_publishable_keyword(tag)
      for _, filter in ipairs(excluded_filters or {}) do
        if M.tag_matches_filter(name, filter) then excluded = true; break end
      end
      if not excluded then
        for _, root in ipairs(opts.location_roots or {}) do
          if M.tag_under_location_root(name, root) then excluded = true; break end
        end
      end
      if not excluded then
        local publish_name = publish_tag_name(name)
        local key = publish_name and publish_name:lower() or nil
        if publish_name and not seen[key] then
          seen[key] = true
          tags[#tags + 1] = publish_name
        end
      end
    end
  end

  table.sort(tags, function(a, b) return tostring(a):lower() < tostring(b):lower() end)
  local original_count = #tags
  if opts.max_tags and #tags > opts.max_tags then
    local limited = {}
    for i = 1, opts.max_tags do limited[i] = tags[i] end
    tags = limited
  end
  return tags, math.max(0, original_count - #tags)
end

function M.image_keyword_tags(image, excluded_filters, tag_names, opts)
  local tags, truncated = M.image_keyword_names(image, excluded_filters, tag_names, opts)
  local encoded = {}
  for _, tag in ipairs(tags) do encoded[#encoded + 1] = flickr_quote_tag(tag) end
  return #encoded > 0 and table.concat(encoded, " ") or nil, truncated
end

local function fingerprint_hash(value)
  local s = tostring(value == nil and "" or value)
  local h = 2166136261
  for i = 1, #s do
    h = (h ~ s:byte(i)) * 16777619 % 4294967296
  end
  return string.format("%08x", h)
end

local function fingerprint_parts(parts)
  return fingerprint_hash(table.concat(parts or {}, "\31"))
end

-- Decide what a single-image "sync GPS/date taken" panel resend should push,
-- given the master sync flags and the values currently available on the image.
-- Pure (no darktable calls) so the panel action's gating can be tested offline.
-- Returns one of:
--   { disabled = true }  -- neither GPS nor date-taken sync is enabled
--   { nothing = true }   -- enabled, but no value to send (no GPS and/or no date)
--   { send_date = bool, send_gps = bool }  -- at least one field to push
local function nonempty(v)
  return v ~= nil and tostring(v) ~= ""
end

function M.geo_date_resend_plan(sync, date_taken, lat, lon)
  sync = sync or {}
  local enabled_date = sync.date_taken == true
  local enabled_gps = sync.gps == true
  if not enabled_date and not enabled_gps then
    return { disabled = true }
  end
  local send_date = enabled_date and nonempty(date_taken)
  local send_gps = enabled_gps and nonempty(lat) and nonempty(lon)
  if not send_date and not send_gps then
    return { nothing = true }
  end
  return { send_date = send_date or false, send_gps = send_gps or false }
end

-- geo_resend_action(gps_enabled, strip, has_coords): decide what an upload or
-- resend should do with a photo's location (issue #23). Privacy-first: when the
-- "strip GPS on resend" toggle is on it always wins over "sync GPS location", so
-- a (re)upload/resend can never leak coordinates the user asked to strip — even if
-- Flickr auto-geotagged the photo from the file's EXIF. Returns:
--   "remove" — strip is on; call flickr.photos.geo.removeLocation (idempotent).
--   "send"   — GPS sync on, not stripping, and the image carries usable coords;
--              call flickr.photos.geo.setLocation.
--   "skip"   — nothing to do (sync off, or no coords to send).
-- Pure/offline-testable.
function M.geo_resend_action(gps_enabled, strip, has_coords)
  if strip == true then return "remove" end
  if gps_enabled == true and has_coords == true then return "send" end
  return "skip"
end

-- metadata_resend_plan(sync, reasons): decide which metadata-only operations a
-- batch/multi-select resend should push for one photo (issue #18). It sends only
-- fields that BOTH changed (a needs-sync reason is present) AND are enabled by the
-- master sync toggles, so a batch over many photos touches only what drifted and
-- never re-uploads pixels. `reasons` is the per-image reason list from
-- state.evaluate_publish_state (e.g. {"keywords","gps"}); only the four reasons
-- that have a metadata-only Flickr push (title_description, keywords, gps,
-- date_taken) are considered here. Pure/offline-testable.
function M.metadata_resend_plan(sync, reasons)
  sync = sync or {}
  local flagged = {}
  for _, reason in ipairs(reasons or {}) do flagged[reason] = true end
  local plan = {
    send_meta = ((sync.title == true) or (sync.description == true)) and flagged.title_description == true,
    send_tags = (sync.tags == true) and flagged.keywords == true,
    send_date = (sync.date_taken == true) and flagged.date_taken == true,
    -- Privacy-first: "strip GPS on resend" suppresses the metadata-only GPS push so
    -- a batch resend never re-sends coordinates the user asked to strip (issue #23).
    -- Explicit removal is the dedicated "remove Flickr location" panel action.
    send_gps  = (sync.gps == true) and flagged.gps == true and (sync.strip_gps ~= true),
  }
  plan.any = plan.send_meta or plan.send_tags or plan.send_date or plan.send_gps
  return plan
end

-- Convert a Flickr `dateuploaded` value (the UTC epoch-seconds string returned by
-- flickr.photos.getInfo) into a compact UTC stamp matching state.now_stamp()'s
-- format (YYYYMMDDTHHMMSSZ), so it can be stored as the per-image upload-date tag
-- (issue #21). Flickr's dateuploaded is the authoritative server upload time; we
-- normalize it through os.date("!...") so it lands in the same UTC stamp grammar
-- the state module already parses. Returns nil for empty/garbage/non-positive
-- input (e.g. Flickr returning "0" or a malformed value), so callers can simply
-- skip storage when there is nothing real to record. Pure/offline-testable.
function M.flickr_upload_stamp(dateuploaded)
  local n = tonumber(dateuploaded)
  if not n or n ~= n or n <= 0 then return nil end
  n = math.floor(n)
  return os.date("!%Y%m%dT%H%M%SZ", n)
end

-- Human-readable form of a stored upload stamp (or a raw Flickr dateuploaded),
-- for surfacing in the panel: "YYYY-MM-DD HH:MM:SS UTC". Accepts either the
-- compact stamp grammar (YYYYMMDDTHHMMSSZ) or a Flickr epoch-seconds value, and
-- returns nil when neither parses. Pure/offline-testable.
function M.format_upload_datetime(value)
  local s = tostring(value or ""):match("^%s*(.-)%s*$")
  if s == "" then return nil end
  local y, mo, d, h, mi, sec = s:match("^(%d%d%d%d)(%d%d)(%d%d)T(%d%d)(%d%d)(%d%d)Z$")
  if y then
    return string.format("%s-%s-%s %s:%s:%s UTC", y, mo, d, h, mi, sec)
  end
  local stamp = M.flickr_upload_stamp(s)
  if not stamp then return nil end
  return M.format_upload_datetime(stamp)
end

function M.fingerprints_from_values(values)
  values = values or {}
  local privacy = values.privacy or {}
  local safety = values.safety or {}
  local content_type = values.content_type or {}
  local license = values.license or {}
  local permissions = values.permissions or {}
  local fingerprints = {}
  if values.include_keywords or values.tags ~= nil then
    fingerprints.keywords = fingerprint_hash(values.tags or "")
  end
  if values.include_title_description or values.title ~= nil or values.description ~= nil then
    fingerprints.title_description = fingerprint_parts({ values.title or "", values.description or "" })
  end
  if values.include_gps or values.lat ~= nil or values.lon ~= nil then
    fingerprints.gps = fingerprint_parts({ values.lat or "", values.lon or "" })
  end
  if values.include_date_taken or values.date_taken ~= nil then
    fingerprints.date_taken = fingerprint_hash(values.date_taken or "")
  end
  if values.privacy ~= nil then
    fingerprints.visibility = fingerprint_parts({ privacy.is_public or "", privacy.is_friend or "", privacy.is_family or "" })
  end
  if values.safety ~= nil then
    fingerprints.safety = fingerprint_hash(safety.flickr_value or "")
  end
  if values.content_type ~= nil then
    fingerprints.content_type = fingerprint_hash(content_type.flickr_value or "")
  end
  if values.license ~= nil then
    fingerprints.license = fingerprint_hash(license.flickr_value or "")
  end
  if values.permissions ~= nil then
    fingerprints.permissions = fingerprint_parts({ permissions.perm_comment or "", permissions.perm_addmeta or "" })
  end
  return fingerprints
end

return M
end

package.preload["dtrmflickr.claim"] = function(...)
local dt = require "darktable"
local rest = require "dtrmflickr.flickr_rest"
local state = require "dtrmflickr.state"
local metadata = require "dtrmflickr.metadata"
local queue = require "dtrmflickr.queue"

local M = {}

local function remote_attr(body, name)
  return body and (body:match(name .. '="(.-)"') or body:match(name .. "='(.-)'")) or nil
end

local function xml_unescape(s)
  return tostring(s or "")
    :gsub("&#x(%x+);", function(h)
      local n = tonumber(h, 16)
      if not n then return "" end
      local ok, c = pcall(utf8.char, n)
      return ok and c or ""
    end)
    :gsub("&#(%d+);", function(d)
      local n = tonumber(d, 10)
      if not n then return "" end
      local ok, c = pcall(utf8.char, n)
      return ok and c or ""
    end)
    :gsub("&quot;", '"')
    :gsub("&apos;", "'")
    :gsub("&lt;", "<")
    :gsub("&gt;", ">")
    :gsub("&amp;", "&")
end

local function filename_part(value)
  return tostring(value or ""):match("[^/\\]+$") or tostring(value or "")
end

local function basename_part(value)
  local file = filename_part(value)
  return file:match("^(.*)%.[^%.]+$") or file
end

local function normalize_match_text(value)
  value = xml_unescape(value or ""):lower()
  value = value:gsub("^%s+", ""):gsub("%s+$", "")
  return value
end

function M.claim_match_terms(image)
  local terms, seen = {}, {}
  local function add(value)
    value = normalize_match_text(value)
    if value ~= "" and not seen[value] then
      seen[value] = true
      terms[#terms + 1] = value
    end
  end
  add(image and image.filename)
  add(basename_part(image and image.filename))
  add(image and image.title)
  add(basename_part(image and image.title))
  if image and dt.metadata and type(dt.metadata.exists) == "function" then
    local ok_exists, exists = pcall(dt.metadata.exists, "Xmp.xmpMM.PreservedFileName")
    if ok_exists and exists then
      local ok_value, preserved = pcall(function() return image["preserved filename"] end)
      if ok_value and type(preserved) == "string" then
        preserved = preserved:match("^%s*(.-)%s*$")
        add(preserved)
        add(basename_part(preserved))
      end
    end
  end
  return terms
end

function M.parse_search_photos(body)
  local photos = {}
  for attrs in tostring(body or ""):gmatch("<photo%s+([^>]-)/>") do
    photos[#photos + 1] = {
      id = remote_attr(attrs, "id"),
      title = xml_unescape(remote_attr(attrs, "title") or ""),
      datetaken = remote_attr(attrs, "datetaken"),
      dateupload = remote_attr(attrs, "dateupload"),
    }
  end
  for attrs in tostring(body or ""):gmatch("<photo%s+([^>]-)>") do
    if not attrs:match("/%s*$") then
      photos[#photos + 1] = {
        id = remote_attr(attrs, "id"),
        title = xml_unescape(remote_attr(attrs, "title") or ""),
        datetaken = remote_attr(attrs, "datetaken"),
        dateupload = remote_attr(attrs, "dateupload"),
      }
    end
  end
  return photos
end

local function add_candidate(candidates, photo, reason)
  if not photo or not photo.id or photo.id == "" then return end
  local current = candidates[photo.id]
  if not current then
    candidates[photo.id] = {
      id = photo.id,
      title = photo.title,
      datetaken = photo.datetaken,
      dateupload = photo.dateupload,
      reasons = {},
    }
    current = candidates[photo.id]
  end
  current.reasons[reason] = true
end

local function candidate_list(candidates)
  local list = {}
  for _, item in pairs(candidates or {}) do list[#list + 1] = item end
  table.sort(list, function(a, b) return tostring(a.id) < tostring(b.id) end)
  return list
end

local function candidate_title_matches(candidate, terms)
  local title = normalize_match_text(candidate and candidate.title)
  if title == "" then return false end
  local title_base = normalize_match_text(basename_part(title))
  for _, term in ipairs(terms or {}) do
    if title == term or title_base == term then return true end
  end
  return false
end

local function search_existing_candidates(api_key, api_secret, acc, image)
  local candidates, errors = {}, {}
  local transient = nil
  local terms = M.claim_match_terms(image)
  local taken = metadata.image_date_taken(image)

  local function run_search(args, reason)
    args = args or {}
    args.user_id = acc.nsid
    args.media = "photos"
    args.extras = "date_taken,date_upload,original_format"
    local bodies, err = rest.photos_search_all(api_key, api_secret, acc, args, { per_page = 50 })
    if not bodies then
      errors[#errors + 1] = tostring(err)
      -- Remember the first transient/rate-limit failure so the caller can ask
      -- the shared queue to retry the whole claim instead of concluding "no
      -- match" from an incomplete candidate set.
      if not transient and queue.is_retryable(err) then transient = tostring(err) end
      return
    end
    for _, body in ipairs(bodies) do
      for _, photo in ipairs(M.parse_search_photos(body)) do
        add_candidate(candidates, photo, reason)
      end
    end
  end

  if taken then
    run_search({ min_taken_date = taken, max_taken_date = taken, sort = "date-taken-desc" }, "taken")
  end
  for _, term in ipairs(terms) do
    run_search({ text = term, sort = "relevance" }, "text")
  end

  return candidate_list(candidates), terms, taken, errors, transient
end

function M.choose_existing_match(candidates, terms, taken)
  local exact_date = {}
  if taken then
    for _, candidate in ipairs(candidates or {}) do
      if candidate.datetaken == taken or candidate.reasons.taken then exact_date[#exact_date + 1] = candidate end
    end
    if #exact_date == 1 then return exact_date[1], "exact date/time" end
  end

  local title_matches = {}
  for _, candidate in ipairs(candidates or {}) do
    if candidate_title_matches(candidate, terms) and (not taken or candidate.datetaken == taken or candidate.reasons.taken) then
      title_matches[#title_matches + 1] = candidate
    end
  end
  if #title_matches == 1 then
    return title_matches[1], taken and "title/filename + date/time" or "title/filename"
  end

  if #exact_date > 1 then return nil, "ambiguous exact date/time" end
  if #title_matches > 1 then return nil, "ambiguous title/filename" end
  return nil, #candidates > 0 and "no strong unique match" or "no match"
end

-- Parse a single Flickr photo ID from a raw ID or a Flickr URL/permalink. Pure
-- helper shared by the panel's manual-link entry and the batch-claim list parser.
function M.parse_photo_id(value)
  value = tostring(value or ""):match("^%s*(.-)%s*$")
  if value == "" then return nil end
  if value:match("^%d+$") then return value end
  return value:match("[?&]photo_id=(%d+)")
    or value:match("/photos/[^/]+/(%d+)")
    or value:match("/photo%.gne%?id=(%d+)")
    or value:match("(%d%d%d%d%d%d%d%d+)")
end

-- Parse a pasted list of Flickr photo IDs/URLs separated by any mix of
-- whitespace, commas, or semicolons. Order is preserved and duplicates are kept
-- (batch claim maps tokens positionally onto the selection, so dropping a
-- duplicate would silently shift every later pairing). Tokens that contain no
-- recognizable ID are skipped. Issue #16.
function M.parse_photo_id_list(text)
  local ids = {}
  for token in tostring(text or ""):gmatch("[^%s,;]+") do
    local id = M.parse_photo_id(token)
    if id then ids[#ids + 1] = id end
  end
  return ids
end

-- Pair selected images with parsed photo IDs positionally (image[i] -> id[i]).
-- Returns the paired list plus leftover counts so the caller can warn when the
-- list and the selection are different lengths. Pure. Issue #16.
function M.plan_batch_claim(images, ids)
  images = images or {}
  ids = ids or {}
  local paired = {}
  local n = math.min(#images, #ids)
  for i = 1, n do
    paired[i] = { image = images[i], id = ids[i] }
  end
  return {
    pairs = paired,
    image_count = #images,
    id_count = #ids,
    paired = n,
    leftover_ids = #ids - n,
    leftover_images = #images - n,
  }
end

-- Human-readable label for an ambiguous-match candidate, for the panel picker.
-- Title is already XML-unescaped by parse_search_photos; preserve its case. Pure.
function M.format_candidate_label(candidate, index)
  candidate = candidate or {}
  local label = string.format("%d. %s", tonumber(index) or 0, tostring(candidate.id or "?"))
  local title = tostring(candidate.title or ""):match("^%s*(.-)%s*$")
  if title ~= "" then label = label .. " — " .. title end
  local date = candidate.datetaken or candidate.dateupload
  date = date and tostring(date):match("^%s*(.-)%s*$") or ""
  if date ~= "" then label = label .. " (" .. date .. ")" end
  return label
end

-- Run the candidate search and best-match selection for one image without
-- committing a link. The panel uses this to drive the ambiguous-candidate
-- picker (issue #16): when `match` is nil but `candidates` is non-empty, the
-- user chooses one manually. claim_existing_for_image is the auto-claim wrapper.
function M.collect_candidates_for_image(api_key, api_secret, acc, image)
  if state.get_photo_id(image, acc.nsid) then
    return { status = "skipped", reason = "already linked", candidates = {}, errors = {} }
  end
  local candidates, terms, taken, errors, transient = search_existing_candidates(api_key, api_secret, acc, image)
  local match, reason = M.choose_existing_match(candidates, terms, taken)
  return {
    match = match,
    reason = reason,
    candidates = candidates,
    terms = terms,
    taken = taken,
    errors = errors,
    transient = transient,
  }
end

function M.claim_existing_for_image(api_key, api_secret, acc, image)
  local result = M.collect_candidates_for_image(api_key, api_secret, acc, image)
  if result.status == "skipped" then return "skipped", result.reason end
  local match, reason, errors, transient = result.match, result.reason, result.errors, result.transient
  if match then
    state.set_photo_id(image, acc.nsid, match.id)
    return "claimed", string.format("%s (%s)", tostring(match.id), reason)
  end
  -- A transient/rate-limit failure left the candidate set incomplete, so any
  -- "no match"/"skipped"/"ambiguous" verdict here is unreliable. Surface a
  -- (nil, err) failure so the queued job retries the whole claim with backoff
  -- instead of permanently mislinking nothing.
  if transient then return nil, transient end
  -- Any search failure — even a non-retryable one — means the candidate set may
  -- be incomplete, so a negative verdict ("no match"/"ambiguous"/"skipped") here
  -- is not trustworthy: the failed search could have supplied the real match or
  -- added a same-date candidate that flips a unique match to ambiguous. We have
  -- no confident match (a positive one short-circuited above, preserving the
  -- "claim what you found" behaviour), so report the error instead of silently
  -- skipping. The earlier `transient` branch already handles retryable failures;
  -- a non-retryable one won't improve on retry, so surface it as a reported
  -- "error" rather than guessing from a truncated set. (Previously this only
  -- fired when *every* search failed (`#candidates == 0`); a partial failure with
  -- surviving candidates wrongly returned "skipped".)
  if #errors > 0 then return "error", table.concat(errors, "; ") end
  return "skipped", reason
end

return M
end

package.preload["dtrmflickr.queue"] = function(...)
-- queue.lua — small serial scheduler for Flickr API work.
--
-- darktable Lua callbacks are synchronous, but keeping every Flickr operation
-- behind one scheduler gives us one place for pacing, retries/backoff,
-- coalescing, and stale UI checks. Jobs normally run immediately; if a callback
-- enqueues more work while the queue is active, duplicate coalesced pending jobs
-- are replaced.

local M = {}

-- NOTE: os.clock() is wall-clock on Windows (the shipping target) but CPU time
-- on POSIX, so on non-Windows hosts method pacing over-waits (it never sees the
-- real time elapsed during a network/sleep). Hosts that need accurate pacing
-- elsewhere can inject a wall-clock `now_ms` via M.new{ now_ms = ... }.
local function monotonic_ms()
  return math.floor((os.clock() or 0) * 1000)
end

-- Unpack a packed result table preserving exact arity, including nil holes and
-- a trailing nil. Plain table.unpack relies on the ambiguous `#` border and can
-- drop values after an interior nil (e.g. memberships, nil, sets).
local function unpack_result(result)
  if not result then return end
  return table.unpack(result, 1, result.n or #result)
end

local function sleep_ms(sleep_fn, ms)
  if sleep_fn and ms and ms > 0 then sleep_fn(ms) end
end

local function default_retryable(err)
  local s = tostring(err or ""):lower()
  if s == "" then return false end
  -- A Flickr REST error is structured: parse_error formats it as
  -- "Flickr REST failed (<code>): <message>", where <code> is Flickr's numeric
  -- error code and <message> is server text that frequently echoes
  -- user-controlled content (a photo title, a tag, a filename). Classify such
  -- errors *strictly by their code* so an echoed token in the message — a title
  -- that literally contains "(503)", a tag "http 500", etc. — can never be
  -- mistaken for a transport status and wrongly mark a permanent error retryable
  -- (which would burn 3 attempts + backoff on an error that will never improve).
  -- Only 105 ("service currently unavailable", the soft-throttle/overload signal)
  -- and 106 ("write operation failed") are transient; every other Flickr REST
  -- code is a permanent/client error (bad args, permission, not found, …) and
  -- must not retry. Transport-level strings (curl/WinHTTP/MSXML "HTTP NNN …",
  -- "bad gateway", timeouts) have no "failed (<code>)" prefix, so they fall
  -- through to the substring/heuristic rules below. A codeless REST error
  -- ("Flickr REST failed: <msg>", no parens) also falls through unchanged.
  local rest_code = tonumber(s:match("flickr rest failed %((%d+)%)"))
  if rest_code then
    if rest_code == 105 then return true, "rate-limit" end
    if rest_code == 106 then return true, "transient" end
    return false
  end
  if s:find("rate", 1, true) and s:find("limit", 1, true) then return true, "rate-limit" end
  if s:find("too many", 1, true) or s:find("throttle", 1, true) then return true, "rate-limit" end
  if s:find("http 429", 1, true) or s:find("(429)", 1, true) then return true, "rate-limit" end
  -- Flickr REST error 105 is the documented "service currently unavailable"
  -- overload / soft-throttle signal — the REST-body sibling of an HTTP 429 and
  -- the most common transient REST failure under load. Its message text
  -- ("Service currently unavailable") contains none of the substrings matched
  -- below (note: "currently", not "temporarily", so the "temporar" rule misses
  -- it), so match the code and the phrase explicitly and back off like a rate
  -- limit. Sibling of the (106) "write operation failed" rule below.
  if s:find("(105)", 1, true) or s:find("service currently unavailable", 1, true)
    or s:find("service unavailable", 1, true) or s:find("temporarily unavailable", 1, true) then
    return true, "rate-limit"
  end
  -- Transport-level HTTP gateway/server errors (502/503/504) raised by Flickr's
  -- edge or an intermediary proxy/CDN during an outage. These arrive as a raw
  -- HTTP status (from curl/WinHTTP/MSXML) rather than a Flickr REST `<err>` body,
  -- so they carry none of the substrings above and were previously classified
  -- non-retryable — failing an idempotent read/setter on the first attempt
  -- instead of riding out a brief gateway hiccup. 503 ("service unavailable") is
  -- already caught when worded, but a bare numeric `(503)`/`http 503` would slip
  -- through; treat 503 as rate-limit (server overload, longer backoff) and
  -- 502/504 (bad gateway / gateway timeout) as ordinary transient. Non-idempotent
  -- ops (upload, photosets.create) opt out of retry via max_attempts=1, so this
  -- only affects retry-safe reads/setters. Advances the 2026-06-28 followup to
  -- widen the matcher beyond REST error 105.
  if s:find("(503)", 1, true) or s:find("http 503", 1, true) then return true, "rate-limit" end
  if s:find("(502)", 1, true) or s:find("http 502", 1, true) or s:find("bad gateway", 1, true)
    or s:find("(504)", 1, true) or s:find("http 504", 1, true) or s:find("gateway time", 1, true) then
    return true, "transient"
  end
  -- General fallback for any other HTTP status a transport surfaces as a string.
  -- The transports now emit "HTTP NNN ..." for any status >= 400 (curl/MSXML
  -- previously swallowed the code and returned the gateway error page as a fake
  -- success body, so the named 502/503/504 rules above were unreachable in
  -- practice). The named forms still win first; this catches the rest — a 429
  -- anywhere (rate-limit) and any remaining 5xx server error such as 500/507 or a
  -- CDN's 520-524 (transient). Other 4xx stay non-retryable (a real client error
  -- won't improve on retry). Matches both the "http NNN" form we emit and a raw
  -- "HTTP/1.1 NNN" status line a different transport might word.
  local http_code = tonumber(s:match("http (%d%d%d)") or s:match("http/[%d.]+%s+(%d%d%d)"))
  if http_code then
    if http_code == 429 or http_code == 503 then return true, "rate-limit" end
    -- 408 Request Timeout is a genuinely transient, retry-safe gateway/server
    -- response (the request never completed), so retry idempotent reads/setters
    -- on it like any other transient. (The non-idempotent upload/create opt out
    -- via max_attempts=1.) Caught explicitly since it is < 500.
    if http_code == 408 then return true, "transient" end
    if http_code >= 500 then return true, "transient" end
  end
  if s:find("temporar", 1, true) or s:find("timed out", 1, true) or s:find("timeout", 1, true) then return true, "transient" end
  if s:find("connection", 1, true) or s:find("network", 1, true) or s:find("curl", 1, true) then return true, "transient" end
  if s:find("write operation failed", 1, true) or s:find("(106)", 1, true) then return true, "transient" end
  if s:find("empty flickr", 1, true) then return true, "transient" end
  -- A paged read whose first page lacks its <container> wrapper is a
  -- malformed/truncated response. flickr_rest.paged_call surfaces it loudly
  -- ("unparseable Flickr paged response (missing <...> wrapper)") *specifically*
  -- so the read can be retried rather than silently returning an incomplete set
  -- — but that purpose is only honoured if the message is actually classified
  -- retryable here. Without this rule the queue failed it on the first attempt
  -- and claim_existing_for_image concluded "no match" from partial data. Treat
  -- it as transient so the whole paged read (and the claim that depends on it)
  -- retries with backoff.
  if s:find("unparseable", 1, true) and s:find("wrapper", 1, true) then return true, "transient" end
  return false
end

-- Exposed so multi-call helpers (e.g. claim's fan-out of searches inside one
-- queue job) can classify a transient/rate-limit failure and choose to surface
-- it as a retryable `nil, err` instead of swallowing it into a status string.
function M.is_retryable(err)
  return default_retryable(err)
end

local function backoff_delay_ms(job, attempt, reason)
  local base = tonumber(job.retry_base_ms) or 0
  if reason == "rate-limit" and job.rate_limit_base_ms then
    base = tonumber(job.rate_limit_base_ms) or base
  end
  if base <= 0 then return 0 end
  local delay = base * (2 ^ math.max(0, attempt - 1))
  local max_delay = tonumber(job.retry_max_ms) or 0
  if max_delay > 0 and delay > max_delay then delay = max_delay end
  local jitter = job.jitter_ms
  if type(jitter) == "function" then
    delay = delay + (tonumber(jitter(delay, attempt, reason)) or 0)
  elseif jitter then
    local amount = tonumber(jitter) or 0
    if amount > 0 then delay = delay + math.random(0, amount) end
  end
  if delay < 0 then delay = 0 end
  return math.floor(delay)
end

local Queue = {}
Queue.__index = Queue

local function copy_list(list)
  local out = {}
  for i, item in ipairs(list or {}) do
    if type(item) == "table" then
      local copied = {}
      for k, v in pairs(item) do copied[k] = v end
      out[i] = copied
    else
      out[i] = item
    end
  end
  return out
end

function M.new(opts)
  opts = opts or {}
  return setmetatable({
    pending = {},
    running = false,
    last_started = {},
    recent = {},
    sequence = 0,
    -- Attempt count of the most recently *run* job (success or failure), so a
    -- caller can read how many tries the call it just made took. Stale-cancelled
    -- jobs never run their fn and report 0. See Queue:last_attempts.
    last_run_attempts = 0,
    now_ms = opts.now_ms or monotonic_ms,
    sleep_ms = opts.sleep_ms,
    on_wait = opts.on_wait,
    on_event = opts.on_event,
    default_pace_ms = opts.default_pace_ms or 0,
    method_pace_ms = opts.method_pace_ms or {},
    default_max_attempts = opts.default_max_attempts or 1,
    retry_base_ms = opts.retry_base_ms or 0,
    retry_max_ms = opts.retry_max_ms or 0,
    rate_limit_base_ms = opts.rate_limit_base_ms,
    retryable = opts.retryable or default_retryable,
    recent_limit = math.max(0, tonumber(opts.recent_limit) or 25),
    -- Async pump hooks (issue #54). All optional and injected so the queue stays
    -- offline-importable: `spawn` runs the pump loop off the UI thread
    -- (dt.control.dispatch), `pump_yield` releases the control thread between
    -- ticks (dt.control.sleep), `should_stop` aborts the loop on shutdown
    -- (dt.control.ending). `pump_batch` jobs are drained per tick (default 1) and
    -- `pump_tick_ms` is slept between ticks (default 0 — yield only).
    spawn = opts.spawn,
    pump_yield = opts.pump_yield,
    should_stop = opts.should_stop,
    pump_batch = math.max(1, math.floor(tonumber(opts.pump_batch) or 1)),
    pump_tick_ms = math.max(0, math.floor(tonumber(opts.pump_tick_ms) or 0)),
    pump_running = false,
    stats = {
      -- `started` counts *attempts* (incremented once per try inside the retry
      -- loop, so a job retried twice adds 3). `jobs_run` counts *jobs that
      -- executed their fn at least once* (incremented once per job, before the
      -- retry loop) — the number a "jobs run" UI should sum, free of retry
      -- over-counting. Stale-cancelled jobs never run their fn and bump neither.
      enqueued = 0, started = 0, jobs_run = 0, succeeded = 0, coalesced = 0,
      stale = 0, failed = 0, retried = 0, rate_limited = 0, waited_ms = 0, waits = 0,
    },
  }, Queue)
end

function Queue:emit(event, job, fields)
  local cb = (job and job.on_event) or self.on_event
  if not cb then return end
  local payload = {
    event = event,
    id = job and job.id or nil,
    method = job and job.method or nil,
    label = job and job.label or nil,
    pending = #self.pending,
    running = self.running,
  }
  for k, v in pairs(fields or {}) do payload[k] = v end
  pcall(cb, payload)
end

function Queue:record(job, status, fields)
  if self.recent_limit <= 0 then return end
  local entry = {
    id = job.id,
    method = job.method,
    label = job.label,
    status = status,
    attempts = fields and fields.attempts or nil,
    error = fields and fields.error or nil,
    waited_ms = fields and fields.waited_ms or nil,
    finished_ms = self.now_ms(),
  }
  self.recent[#self.recent + 1] = entry
  while #self.recent > self.recent_limit do table.remove(self.recent, 1) end
end

function Queue:pace_for(method, opts)
  if opts and opts.pace_ms ~= nil then return tonumber(opts.pace_ms) or 0 end
  return tonumber(self.method_pace_ms[method]) or tonumber(self.default_pace_ms) or 0
end

function Queue:enqueue(method, fn, opts)
  assert(type(fn) == "function", "queue job must be a function")
  opts = opts or {}
  self.sequence = self.sequence + 1
  local job = {
    id = self.sequence,
    method = tostring(method or "flickr.unknown"),
    fn = fn,
    label = opts.label,
    coalesce_key = opts.coalesce_key,
    stale = opts.stale,
    -- Honour `done` here, not only in Queue:call. enqueue accepts the full opts
    -- bag, so silently dropping `done` was a broken contract: a job enqueued via
    -- Queue:enqueue(method, fn, { done = ... }) and later run by drain() would
    -- never fire its callback. (Latent today — production code routes through
    -- Queue:call — but the option must mean the same thing on both paths.)
    done = opts.done,
    pace_ms = self:pace_for(method, opts),
    max_attempts = math.max(1, tonumber(opts.max_attempts or self.default_max_attempts) or 1),
    retry_base_ms = opts.retry_base_ms ~= nil and opts.retry_base_ms or self.retry_base_ms,
    retry_max_ms = opts.retry_max_ms ~= nil and opts.retry_max_ms or self.retry_max_ms,
    rate_limit_base_ms = opts.rate_limit_base_ms ~= nil and opts.rate_limit_base_ms or self.rate_limit_base_ms,
    retryable = opts.retryable or self.retryable,
    jitter_ms = opts.jitter_ms,
    on_wait = opts.on_wait or self.on_wait,
    on_event = opts.on_event or self.on_event,
    waited_ms = 0,
  }
  self.stats.enqueued = self.stats.enqueued + 1

  if job.coalesce_key then
    for i, pending in ipairs(self.pending) do
      if pending.coalesce_key == job.coalesce_key then
        job.replaced_jobs = pending.replaced_jobs or {}
        job.replaced_jobs[#job.replaced_jobs + 1] = pending
        self.pending[i] = job
        self.stats.coalesced = self.stats.coalesced + 1
        self:emit("coalesced", job, { replaced_id = pending.id })
        return job
      end
    end
  end

  self.pending[#self.pending + 1] = job
  self:emit("enqueued", job)
  return job
end

function Queue:wait(job, ms, why, attempt)
  ms = math.floor(tonumber(ms) or 0)
  if ms <= 0 then return end
  self.stats.waited_ms = self.stats.waited_ms + ms
  self.stats.waits = self.stats.waits + 1
  if job then job.waited_ms = (job.waited_ms or 0) + ms end
  -- Lifecycle `waiting` event for all wait reasons (pace, transient, rate-limit)
  -- so a queued/running/waiting/retrying UI can show a single "waiting Ns
  -- because <why>" state. This complements `retry` (the decision to retry) and
  -- `rate-limit`/`transient` `on_wait` (the human-facing message): pace waits
  -- previously had no event at all, so a UI could not distinguish pace-throttling
  -- from a plain run. The `retry` event still fires first for retry waits.
  self:emit("waiting", job, { ms = ms, why = why, attempt = attempt })
  if job and job.on_wait then job.on_wait(ms, why, job.method, attempt) end
  sleep_ms(self.sleep_ms, ms)
end

function Queue:run_job(job)
  local attempt = 1
  -- Count the job once here (before the retry loop) so `jobs_run` reflects jobs,
  -- not attempts. `stats.started` below still counts every attempt.
  self.stats.jobs_run = self.stats.jobs_run + 1
  while true do
    self:emit("started", job, { attempt = attempt })
    local now = self.now_ms()
    local last = self.last_started[job.method]
    if last and job.pace_ms > 0 then
      self:wait(job, job.pace_ms - (now - last), "pace", attempt)
    end
    self.last_started[job.method] = self.now_ms()
    self.stats.started = self.stats.started + 1

    -- table.pack keeps the exact return arity (including interior/trailing nils),
    -- so multi-value successes like (memberships, nil, sets) survive unpack.
    local packed = table.pack(pcall(job.fn, attempt))
    local ok = packed[1]
    -- Success convention: the job ran AND its first return value is non-nil.
    -- Flickr helpers return a truthy value (id/body/true) on success and
    -- (nil, err) on failure.
    if ok and packed[2] ~= nil then
      local out = table.pack(table.unpack(packed, 2, packed.n))
      self.last_run_attempts = attempt
      self.stats.succeeded = self.stats.succeeded + 1
      self:record(job, "succeeded", { attempts = attempt, waited_ms = job.waited_ms })
      self:emit("succeeded", job, { attempt = attempt })
      return out
    end

    -- Failure: if pcall caught a raised error it is in slot 2; if the job ran
    -- and returned (nil, err) the message is in slot 3 (slot 2 holds the nil
    -- first return). Guarantee a non-nil message so it survives unpack.
    local err = ok and packed[3] or packed[2]
    if err == nil then err = "Flickr queue job returned no result" end
    local retry, reason = false, nil
    if attempt < job.max_attempts and job.retryable then
      retry, reason = job.retryable(err, job.method, attempt)
    end
    if retry then
      self.stats.retried = self.stats.retried + 1
      if reason == "rate-limit" then self.stats.rate_limited = self.stats.rate_limited + 1 end
      self:emit("retry", job, { attempt = attempt, reason = reason, error = err })
      self:wait(job, backoff_delay_ms(job, attempt, reason), reason or "retry", attempt)
      attempt = attempt + 1
    else
      self.last_run_attempts = attempt
      self.stats.failed = self.stats.failed + 1
      self:record(job, "failed", { attempts = attempt, error = err, waited_ms = job.waited_ms })
      self:emit("failed", job, { attempt = attempt, error = err })
      return table.pack(nil, err)
    end
  end
end

-- A `stale`/`done` callback is user/UI code (it reaches into darktable widgets),
-- so it can raise. Never let one of those throws abort the batch or — worse —
-- leave the queue wedged with running=true. Run them under pcall.
local function safe_call(fn, ...)
  if not fn then return end
  pcall(fn, ...)
end

function Queue:finish_job(job)
  local is_stale = false
  if job.stale then
    local ok, res = pcall(job.stale)
    is_stale = ok and res and true or false
  end
  if is_stale then
    -- A stale job never runs its fn, so the "attempts of the last call" is 0.
    self.last_run_attempts = 0
    self.stats.stale = self.stats.stale + 1
    job.result = table.pack(nil, "stale Flickr queue job")
    self:record(job, "stale", { attempts = 0, error = job.result[2], waited_ms = job.waited_ms })
    self:emit("stale", job, { error = job.result[2] })
  else
    job.result = self:run_job(job)
  end
  for _, replaced in ipairs(job.replaced_jobs or {}) do
    replaced.result = job.result
    safe_call(replaced.done, unpack_result(replaced.result))
  end
  safe_call(job.done, unpack_result(job.result))
  return job.result
end

function Queue:drain()
  if self.running then return end
  self.running = true
  -- Guarantee running is cleared even if a job somehow raises past run_job's
  -- pcall, so a single failure can never permanently wedge the scheduler.
  local ok, err = pcall(function()
    while #self.pending > 0 do
      local job = table.remove(self.pending, 1)
      self:finish_job(job)
    end
  end)
  self.running = false
  if not ok then error(err) end
end

-- ============ Async pump (issue #54) ============
--
-- drain() runs every pending job to a terminal state within one call. That is
-- correct for the export store/finalize path, which is itself a synchronous
-- darktable callback that must return each job's result inline. But it means a
-- job never sits observably in running/waiting/retrying between event-loop
-- turns, so a restart, a panel poll, or a persistence hook can never see
-- in-flight work — the reason the lifecycle tracker and durable resume store
-- exist as a data model but cannot run live (see docs/queue-system.md).
--
-- The async pump closes that gap: it drains a BOUNDED number of jobs per tick
-- and yields control back to darktable between ticks, so (a) a long batch never
-- freezes the UI for its whole duration, and (b) intermediate lifecycle states
-- are observable between ticks (a panel polling `__dtrmflickr_jobs` sees the
-- still-`queued` remainder while the just-run jobs are terminal). The
-- success/failure + retry/backoff contract and idempotency guarantees are
-- unchanged — the pump reuses finish_job/run_job exactly like drain().

-- Run up to `max_jobs` pending jobs to a terminal state, then return control.
-- Returns (jobs_run, pending_remaining). Honours the same `running` reentrancy
-- guard as drain(): a reentrant Queue:call from inside a running job runs
-- immediately (it sees running=true and jumps the queue) rather than being
-- double-processed here. A no-op (returns 0) if a drain is already in progress.
function Queue:drain_step(max_jobs)
  if self.running then return 0, #self.pending end
  max_jobs = math.max(1, math.floor(tonumber(max_jobs) or 1))
  local ran = 0
  self.running = true
  -- Mirror drain()'s guarantee: clear `running` even if a job escapes run_job's
  -- pcall, so one failure can never wedge the scheduler with running=true.
  local ok, err = pcall(function()
    while ran < max_jobs and #self.pending > 0 do
      local job = table.remove(self.pending, 1)
      self:finish_job(job)
      ran = ran + 1
    end
  end)
  self.running = false
  if not ok then error(err) end
  return ran, #self.pending
end

-- The pump loop body. Drains `pump_batch` jobs per tick and yields the control
-- thread between ticks (via `pump_yield`) until the queue empties or
-- `should_stop` signals shutdown. Idempotent: a second call while a pump is
-- already running returns immediately, so two pumps can never race the same
-- pending list. Stopping on `should_stop` leaves the remaining jobs pending —
-- that is correct; the durable resume store (issues #55/#57) persists and
-- replays them, so the pump must not force them to terminal on shutdown.
function Queue:pump()
  if self.pump_running then return end
  self.pump_running = true
  local ok, err = pcall(function()
    while #self.pending > 0 do
      if self.should_stop and self.should_stop() then break end
      self:drain_step(self.pump_batch)
      -- Only yield when more work remains, so the final tick does not sleep for
      -- nothing. The yield releases the control thread (dt.control.sleep) so
      -- darktable stays responsive and the intermediate states are observable.
      if #self.pending > 0 and self.pump_yield then self.pump_yield(self.pump_tick_ms) end
    end
  end)
  self.pump_running = false
  if not ok then error(err) end
end

-- Enqueue work to run asynchronously and make sure a pump is draining it. Use
-- this (instead of Queue:call) for work that should defer across darktable
-- callbacks rather than block the caller for the whole batch. The result is
-- delivered through the job's `done` callback (and the lifecycle events), not
-- returned — an async caller cannot block on an inline return value.
--
-- If `spawn` is configured the pump runs off the UI thread; otherwise it runs
-- inline here (still yielding between ticks via `pump_yield` if present, or just
-- draining straight through if not) so a missing spawn degrades to a synchronous
-- drain rather than silently stranding the job in `pending` forever.
function Queue:submit_async(method, fn, opts)
  local job = self:enqueue(method, fn, opts)
  self:ensure_pump()
  return job
end

-- Start the pump if one is not already running. Dispatched via `spawn` when
-- available (dt.control.dispatch), else run inline.
function Queue:ensure_pump()
  if self.pump_running then return end
  if #self.pending == 0 then return end
  if self.spawn then
    self.spawn(function() self:pump() end)
  else
    self:pump()
  end
end

function Queue:pumping()
  return self.pump_running == true
end

function Queue:call(method, fn, opts)
  local job = self:enqueue(method, fn, opts)
  -- `done` is now wired in enqueue (so both enqueue and call honour it); the
  -- surviving job after a coalesce already carries the newest job's `done`.
  if self.running then
    -- Reentrant call from inside a running job: run it now (synchronously,
    -- jumping the queue) and return its real result instead of leaving it
    -- pending. The job is the just-enqueued/surviving pending entry, so pull it
    -- out of pending if present and finish it directly.
    for i, pending in ipairs(self.pending) do
      if pending == job then
        table.remove(self.pending, i)
        break
      end
    end
    return unpack_result(self:finish_job(job))
  end
  self:drain()
  if job.result then return unpack_result(job.result) end
  return nil, "queued Flickr job has not run yet"
end

-- Zero the cumulative counters and drop the recent-results history so the next
-- batch's panel feedback reflects *that batch*, not the whole darktable session.
-- The stats table accumulates for the queue's whole lifetime, so without this a
-- single throttled export leaves the panel showing "throttled Nx - waited X.Xs
-- total" forever, even when later work runs clean — the aggregate the panel
-- describes as "the whole batch's" was actually the whole session's. Call this at
-- a batch boundary (the export `initialize`). Only the counters and `recent` are
-- cleared: pacing timestamps (`last_started`), `pending`, `running`, and the
-- monotonic `sequence` are scheduler state, not per-batch feedback, and are left
-- untouched so a reset mid-activity can never corrupt pacing or job identity.
function Queue:reset_stats()
  for k in pairs(self.stats) do self.stats[k] = 0 end
  self.recent = {}
end

function Queue:pending_count()
  return #self.pending
end

-- Attempt count of the most recently run job (the call that just returned).
-- 1 for a first-try success/failure, N for a job the retry loop ran N times, 0
-- when the last job was stale-cancelled (or none has run yet). Lets a caller
-- attribute the retry cost of an individual call to whatever it was doing — the
-- queue's cumulative `summary().retried` can't be split per call.
function Queue:last_attempts()
  return self.last_run_attempts or 0
end

function Queue:recent_results()
  return copy_list(self.recent)
end

function Queue:summary()
  local copy = {}
  for k, v in pairs(self.stats) do copy[k] = v end
  copy.pending = #self.pending
  copy.running = self.running
  copy.pumping = self.pump_running
  return copy
end

return M
end

package.preload["dtrmflickr.queue_jobs"] = function(...)
-- queue_jobs.lua — explicit job lifecycle state + account-bound persistent records.
--
-- This is the offline-testable foundation for the resumable/queued-uploads work
-- (issue #36). It has two independent, pure concerns and touches no darktable or
-- network API, so it is unit-tested directly (see tests/test_queue_jobs.lua):
--
--   A. A lifecycle *state tracker* that consumes the queue's existing `on_event`
--      stream (queue.lua already emits enqueued/started/waiting/retry/succeeded/
--      failed/stale/coalesced) and collapses it into one explicit per-job state —
--      queued | running | waiting | retrying | succeeded | failed | stale |
--      cancelled — so a panel can show "what is each job doing right now" instead
--      of only the terminal `recent_results`. The queue stays the scheduler; this
--      is a passive observer.
--
--   B. Account-bound *persistent records* + (de)serialization. Each resumable job
--      record carries its owning account nsid, so when jobs persist/defer across
--      UI events or restarts the design-notes account-binding contract holds:
--      a record whose owning nsid is not the currently active account is
--      cancelled/skipped, never run against the wrong token (see the
--      "Account-binding requirement for the async/persistent queue" note in
--      docs/design-notes.md). The serialized string is what a future restart-
--      resume would stash in a darktable preference blob and rebuild from.
--
-- What is intentionally NOT here (gated on an async/coroutine queue): the live
-- in-panel grid, the actual preference read/write at load/save, and the
-- resume-and-rerun execution. darktable storage callbacks are synchronous and
-- the queue drains within a single call, so intermediate states are not
-- observable in the panel today; this module is the data model those features
-- will consume once the queue can defer work.

local M = {}

----------------------------------------------------------------------
-- Shared state vocabulary.
----------------------------------------------------------------------

-- A job is in exactly one of these states. The first four are live/non-terminal
-- (the job may still change); the last four are terminal (the job is done and
-- will not move again on its own).
M.STATES = {
  queued = true, running = true, waiting = true, retrying = true,
  succeeded = true, failed = true, stale = true, cancelled = true,
}

local TERMINAL = {
  succeeded = true, failed = true, stale = true, cancelled = true,
}

function M.is_terminal(state)
  return TERMINAL[tostring(state or "")] == true
end

function M.is_resumable(state)
  -- A persisted job worth resuming is one that has not reached a terminal
  -- outcome. `succeeded` work is done; `failed`/`stale`/`cancelled` are decided
  -- and must not be silently retried by a resume (a failed upload may already
  -- have created a photo — see the non-idempotent-retry note in queue-system.md).
  return M.STATES[tostring(state or "")] == true and not TERMINAL[state]
end

----------------------------------------------------------------------
-- A. Lifecycle state tracker (consumes queue `on_event` payloads).
----------------------------------------------------------------------

local Tracker = {}
Tracker.__index = Tracker

-- opts.limit bounds how many distinct jobs are remembered (oldest dropped),
-- mirroring the queue's bounded `recent`. Default 200.
function M.new_tracker(opts)
  opts = opts or {}
  return setmetatable({
    jobs = {},       -- id -> record
    order = {},      -- insertion order of ids (for a stable snapshot)
    limit = math.max(1, tonumber(opts.limit) or 200),
  }, Tracker)
end

local function tracker_record(self, id)
  local rec = self.jobs[id]
  if rec then return rec end
  rec = { id = id, state = "queued" }
  self.jobs[id] = rec
  self.order[#self.order + 1] = id
  -- Drop the oldest *terminal* job once over the cap so a long session cannot
  -- grow unbounded, but never evict a live job (it would lose a job still in
  -- flight). If every remembered job is still live we simply exceed the cap
  -- rather than corrupt the in-flight view.
  while #self.order > self.limit do
    local evicted
    for i = 1, #self.order do
      local oid = self.order[i]
      local r = self.jobs[oid]
      if not r or M.is_terminal(r.state) then
        table.remove(self.order, i)
        self.jobs[oid] = nil
        evicted = true
        break
      end
    end
    if not evicted then break end
  end
  return rec
end

-- Bind a job to its owning account nsid. The queue's event payload does not
-- carry the nsid (the queue is account-agnostic), so the producer that enqueues
-- the work calls this — directly, or by putting `nsid` on the `on_event`
-- payload it forwards (observe reads `payload.nsid` too). Required for the
-- account-binding contract to mean anything on a persisted record.
function Tracker:bind_account(id, nsid)
  if id == nil then return end
  local rec = tracker_record(self, id)
  if nsid ~= nil and nsid ~= "" then rec.nsid = tostring(nsid) end
end

-- Map one queue lifecycle event onto a job's explicit state. Unknown events are
-- ignored (forward-compatible). Terminal states are sticky: a late stray event
-- for an already-finished job never resurrects it.
function Tracker:observe(payload)
  if type(payload) ~= "table" then return end
  local event = payload.event
  if event == nil then return end

  -- `coalesced` is about the *replaced* job, not payload.id (which is the
  -- surviving newer job). Mark the replaced job cancelled and let the survivor
  -- be tracked normally below.
  if event == "coalesced" and payload.replaced_id ~= nil then
    local replaced = tracker_record(self, payload.replaced_id)
    if not M.is_terminal(replaced.state) then
      replaced.state = "cancelled"
      replaced.reason = "coalesced"
    end
  end

  local id = payload.id
  if id == nil then return end
  local rec = tracker_record(self, id)
  if payload.method ~= nil then rec.method = payload.method end
  if payload.label ~= nil then rec.label = payload.label end
  if payload.nsid ~= nil and payload.nsid ~= "" then rec.nsid = tostring(payload.nsid) end
  if payload.attempt ~= nil then rec.attempts = tonumber(payload.attempt) or rec.attempts end

  -- Once terminal, only the surviving job's own terminal events matter; ignore
  -- the rest so a stale `started`/`waiting` cannot un-finish a job.
  if M.is_terminal(rec.state) then return end

  if event == "enqueued" then
    rec.state = "queued"
  elseif event == "started" then
    rec.state = "running"
  elseif event == "retry" then
    rec.state = "retrying"
    if payload.error ~= nil then rec.error = tostring(payload.error) end
  elseif event == "waiting" then
    -- A `pace` wait is ordinary throttling of a fresh job; any other wait
    -- reason (retry/transient/rate-limit) is backing off before a retry. The
    -- `retry` event (the decision) fires first for the latter, so this just
    -- keeps the state consistent through the sleep.
    if payload.why == "pace" then
      rec.state = "waiting"
    else
      rec.state = "retrying"
    end
  elseif event == "succeeded" then
    rec.state = "succeeded"
    rec.error = nil
  elseif event == "failed" then
    rec.state = "failed"
    if payload.error ~= nil then rec.error = tostring(payload.error) end
  elseif event == "stale" then
    rec.state = "stale"
    if payload.error ~= nil then rec.error = tostring(payload.error) end
  end
end

local function copy_record(rec)
  local out = {}
  for k, v in pairs(rec) do out[k] = v end
  return out
end

-- Ordered list of shallow copies (insertion order), so callers can sort/render
-- without mutating the tracker.
function Tracker:snapshot()
  local out = {}
  for _, id in ipairs(self.order) do
    local rec = self.jobs[id]
    if rec then out[#out + 1] = copy_record(rec) end
  end
  return out
end

-- Only the live (non-terminal) jobs — the "what is happening now" view a panel
-- would poll, and the set a restart would persist as resumable.
function Tracker:active()
  local out = {}
  for _, id in ipairs(self.order) do
    local rec = self.jobs[id]
    if rec and not M.is_terminal(rec.state) then out[#out + 1] = copy_record(rec) end
  end
  return out
end

function Tracker:get(id)
  local rec = self.jobs[id]
  return rec and copy_record(rec) or nil
end

-- Account switch / logout: every non-terminal job whose owning account is not
-- the now-active account is cancelled, implementing design requirement (2) —
-- a deferred job must never run against the wrong token. `active_nsid == nil`
-- or "" (logged out) cancels *all* non-terminal jobs. Returns the count
-- cancelled. A job with no bound nsid is treated as orphaned and cancelled when
-- there is an active account it cannot be confirmed to belong to.
function Tracker:cancel_for_account_change(active_nsid)
  active_nsid = active_nsid ~= nil and tostring(active_nsid) or ""
  local cancelled = 0
  for _, id in ipairs(self.order) do
    local rec = self.jobs[id]
    if rec and not M.is_terminal(rec.state) then
      local owner = rec.nsid or ""
      if active_nsid == "" or owner ~= active_nsid then
        rec.state = "cancelled"
        rec.reason = "account-changed"
        cancelled = cancelled + 1
      end
    end
  end
  return cancelled
end

function Tracker:reset()
  self.jobs = {}
  self.order = {}
end

----------------------------------------------------------------------
-- B. Account-bound persistent records.
----------------------------------------------------------------------

-- Split records into the ones that may run under the active account and the
-- orphans that may not. Pure (no mutation): a record is runnable iff there IS an
-- active account and the record's owning nsid matches it. A logged-out state
-- (active_nsid nil/"") orphans everything. This is the read-only classification;
-- `cancel_orphans` is the mutating sibling that stamps the orphans cancelled.
function M.partition_by_account(records, active_nsid)
  active_nsid = active_nsid ~= nil and tostring(active_nsid) or ""
  local runnable, orphaned = {}, {}
  for _, rec in ipairs(records or {}) do
    local owner = rec and rec.nsid ~= nil and tostring(rec.nsid) or ""
    if active_nsid ~= "" and owner == active_nsid then
      runnable[#runnable + 1] = rec
    else
      orphaned[#orphaned + 1] = rec
    end
  end
  return runnable, orphaned
end

-- Mutating partition: orphaned records get state "cancelled" / reason
-- "account-changed" (so a persisted batch reloaded under a different account is
-- visibly skipped, not silently run). Returns runnable, orphaned.
function M.cancel_orphans(records, active_nsid)
  local runnable, orphaned = M.partition_by_account(records, active_nsid)
  for _, rec in ipairs(orphaned) do
    if rec and not M.is_terminal(rec.state) then
      rec.state = "cancelled"
      rec.reason = "account-changed"
    end
  end
  return runnable, orphaned
end

-- Keep only the records worth persisting for a resume: the non-terminal
-- (`is_resumable`) ones. A terminal job is already decided — re-running a
-- `succeeded` job duplicates work, and re-running a `failed` upload may create a
-- duplicate photo (see the non-idempotent-retry note in queue-system.md) — so it
-- must never be carried into the resume blob. Pure; returns a new list.
function M.to_resumable(records)
  local out = {}
  for _, rec in ipairs(records or {}) do
    if type(rec) == "table" and M.is_resumable(rec.state) then
      out[#out + 1] = rec
    end
  end
  return out
end

-- Resume-safety classifier. Unlike `partition_by_account` (which keys purely on
-- the owning nsid and would happily mark a terminal-but-owned record runnable),
-- `plan_resume` is what an async resume calls: it guarantees a terminal job is
-- never re-run. Returns three lists:
--   runnable — resumable AND owned by the active account (safe to re-run)
--   orphaned — resumable but owned by another account / unbound / logged out
--   finished — already terminal (succeeded/failed/stale/cancelled): skip, never
--              re-run, regardless of which account owns it
-- Pure (no mutation). A logged-out active account (nil/"") sends every resumable
-- record to `orphaned`. This wires the documented `is_resumable` contract into
-- the partition path so the persistence layer is resume-safe end to end.
function M.plan_resume(records, active_nsid)
  active_nsid = active_nsid ~= nil and tostring(active_nsid) or ""
  local runnable, orphaned, finished = {}, {}, {}
  for _, rec in ipairs(records or {}) do
    if type(rec) == "table" then
      if M.is_terminal(rec.state) then
        finished[#finished + 1] = rec
      else
        local owner = rec.nsid ~= nil and tostring(rec.nsid) or ""
        if active_nsid ~= "" and owner == active_nsid then
          runnable[#runnable + 1] = rec
        else
          orphaned[#orphaned + 1] = rec
        end
      end
    end
  end
  return runnable, orphaned, finished
end

----------------------------------------------------------------------
-- Idempotency-aware resume safety.
--
-- `plan_resume` guarantees a *terminal* job is never re-run. But a non-terminal
-- record is not automatically safe to re-run either: a non-idempotent Flickr
-- call that had already *started* executing when the process was interrupted may
-- already have reached Flickr. A lost-ack success is indistinguishable, from a
-- persisted record, from a never-sent failure, so re-running it could create a
-- duplicate photo / album — the exact hazard documented under "Non-idempotent
-- jobs must opt out of retry" in queue-system.md.
----------------------------------------------------------------------

-- Methods that are NOT idempotent — re-running them can create a duplicate
-- because they have no dedupe key. This is the same set the queue runs with
-- `max_attempts = 1` (queue.lua / queue-system.md); keep the two in sync. Every
-- other Flickr method here (post-upload setters, reads, album add/remove)
-- converges on replay and is safe to re-run.
local NON_IDEMPOTENT = {
  ["flickr.upload"] = true,
  ["flickr.photosets.create"] = true,
}

function M.is_idempotent(method)
  return NON_IDEMPOTENT[tostring(method or "")] ~= true
end

-- Whether a persisted record is safe to AUTO re-run on resume without risking a
-- duplicate:
--   * terminal       -> false (already decided; lands in plan_resume's finished)
--   * idempotent      -> true  (replay converges to the same state)
--   * non-idempotent  -> true ONLY if it provably never started — state
--                        `queued` (enqueued, `started` never fired). Any of
--                        running/waiting/retrying means the `started` lifecycle
--                        began, so the upload/create may already have reached
--                        Flickr and re-running could duplicate it. This is
--                        deliberately conservative: a non-idempotent job that
--                        merely paced before its fn ran is also indeterminate
--                        from a single persisted state, and "ask the user" is the
--                        right bias when the alternative is a duplicate photo.
function M.is_safely_resumable(rec)
  if type(rec) ~= "table" then return false end
  local state = rec.state
  if not M.is_resumable(state) then return false end
  if M.is_idempotent(rec.method) then return true end
  return state == "queued"
end

-- Idempotency-aware resume planner. `plan_resume` guarantees a terminal job is
-- never re-run; `plan_resume_safe` additionally guarantees a non-idempotent job
-- that may already have executed is never *silently* re-run. Four lists:
--   runnable  — resumable, owned, AND safe to auto re-run (`is_safely_resumable`)
--   uncertain — resumable, owned, but non-idempotent and already started: it may
--               or may not have completed on Flickr; surface for a user decision,
--               never auto re-run (would risk a duplicate photo/album)
--   orphaned  — resumable but other-account / unbound / logged out
--   finished  — already terminal: skip, never re-run, regardless of owner
-- Pure (no mutation). A logged-out active account (nil/"") sends every resumable
-- record to `orphaned` (uncertain stays empty — an other-account upload is
-- orphaned/cancelled regardless of how far it got).
function M.plan_resume_safe(records, active_nsid)
  active_nsid = active_nsid ~= nil and tostring(active_nsid) or ""
  local runnable, uncertain, orphaned, finished = {}, {}, {}, {}
  for _, rec in ipairs(records or {}) do
    if type(rec) == "table" then
      if M.is_terminal(rec.state) then
        finished[#finished + 1] = rec
      else
        local owner = rec.nsid ~= nil and tostring(rec.nsid) or ""
        if active_nsid ~= "" and owner == active_nsid then
          if M.is_safely_resumable(rec) then
            runnable[#runnable + 1] = rec
          else
            uncertain[#uncertain + 1] = rec
          end
        else
          orphaned[#orphaned + 1] = rec
        end
      end
    end
  end
  return runnable, uncertain, orphaned, finished
end

----------------------------------------------------------------------
-- Serialization (durable string for a preference blob).
--
-- Line-based and self-describing. The first line is a version header; each
-- following line is one record's fields joined by US (0x1F). Values are
-- percent-escaped for the few bytes that would break the framing (%, the field
-- and record separators), so arbitrary error text / filenames round-trip
-- losslessly. Deserialize is tolerant: a missing/bad header or a malformed line
-- yields no record rather than an error, so a corrupt blob degrades to "nothing
-- to resume" instead of breaking load.
----------------------------------------------------------------------

local HEADER = "dtrmflickr-jobs 1"
local FS = "\31"          -- field separator (unit separator)
-- Fixed field order. Append-only for forward compatibility; never reorder. A blob
-- written by an older build simply lacks the trailing columns, which read back as
-- nil — so `sets` (#79) is safe to append: an older blob deserializes with no sets.
local FIELDS = { "nsid", "method", "state", "attempts", "image", "label", "error", "reason", "sets" }
-- A record field that is a LIST rather than a scalar gets a custom codec keyed
-- here; everything else round-trips as a plain (escaped) string cell. `sets` is a
-- list of Flickr photoset ids (numeric strings), joined with a comma — safe
-- because ids never contain a comma; the whole cell is still %-escaped by `esc`.
local SETS_SEP = ","
local function encode_sets(sets)
  if type(sets) ~= "table" or #sets == 0 then return "" end
  local parts = {}
  for _, s in ipairs(sets) do
    local str = tostring(s)
    if str ~= "" then parts[#parts + 1] = str end
  end
  return table.concat(parts, SETS_SEP)
end
local function decode_sets(cell)
  if type(cell) ~= "string" or cell == "" then return nil end
  local out = {}
  for part in (cell .. SETS_SEP):gmatch("(.-)" .. SETS_SEP) do
    if part ~= "" then out[#out + 1] = part end
  end
  if #out == 0 then return nil end
  return out
end

local function esc(v)
  return (tostring(v == nil and "" or v)
    :gsub("%%", "%%25")
    :gsub("\n", "%%0A")
    :gsub("\r", "%%0D")
    :gsub("\31", "%%1F"))
end

local function unesc(v)
  return (tostring(v or ""):gsub("%%(%x%x)", function(h)
    return string.char(tonumber(h, 16))
  end))
end

function M.serialize(records)
  local lines = { HEADER }
  for _, rec in ipairs(records or {}) do
    if type(rec) == "table" then
      local cells = {}
      for i, field in ipairs(FIELDS) do
        if field == "sets" then
          cells[i] = esc(encode_sets(rec.sets))
        else
          cells[i] = esc(rec[field])
        end
      end
      lines[#lines + 1] = table.concat(cells, FS)
    end
  end
  return table.concat(lines, "\n")
end

function M.deserialize(blob)
  local out = {}
  if type(blob) ~= "string" or blob == "" then return out end
  local lines = {}
  for line in (blob .. "\n"):gmatch("(.-)\n") do lines[#lines + 1] = line end
  if lines[1] ~= HEADER then return out end
  for i = 2, #lines do
    local line = lines[i]
    if line ~= "" then
      local cells = {}
      for cell in (line .. FS):gmatch("(.-)" .. FS) do cells[#cells + 1] = cell end
      local rec = {}
      for j, field in ipairs(FIELDS) do rec[field] = unesc(cells[j] or "") end
      -- Normalize: empty strings back to nil (except the two required keys), and
      -- attempts back to a number. A record with no method is junk — skip it.
      if rec.method == "" then
        rec = nil
      else
        rec.attempts = tonumber(rec.attempts)
        for _, field in ipairs(FIELDS) do
          if field ~= "attempts" and rec[field] == "" then rec[field] = nil end
        end
        -- Decode the `sets` list column from its comma-joined cell (nil when empty).
        rec.sets = decode_sets(rec.sets)
        if rec.state == nil or M.STATES[rec.state] == nil then rec.state = "queued" end
      end
      if rec then out[#out + 1] = rec end
    end
  end
  return out
end

----------------------------------------------------------------------
-- Persistent store (load/save the resume blob through an injected backend).
--
-- This is the load/save preference-blob plumbing: it turns the serialize/
-- deserialize pair into a durable round-trip against a key/value backend
-- (darktable preferences in production). The backend is INJECTED rather than
-- `require`d so this module stays pure and offline-testable — the main module
-- wraps `dt.preferences` with `make_pref_backend`; tests pass a table stub.
--
-- A backend is any table exposing:
--   read()      -> the stored blob string (or nil/"" when nothing is stored)
--   write(blob) -> persist the blob string
--
-- Save persists only the resumable subset (`to_resumable`), so a terminal job is
-- never written into the blob; a resume rebuilt from a reloaded blob therefore
-- can never re-run a succeeded/failed job (the non-idempotent-retry hazard — see
-- queue-system.md). Records keep their owning nsid, so account partitioning still
-- happens at load time via `plan_resume_safe`; the blob itself is account-mixed.
--
-- LIVE use stays gated on the async/coroutine queue: the synchronous queue drains
-- to terminal within one call, so there is never a live job to persist mid-flight.
-- This lands the durable round-trip the async resume will call.
----------------------------------------------------------------------

local function assert_backend(backend, method)
  assert(type(backend) == "table" and type(backend[method]) == "function",
    "queue_jobs store backend must expose a " .. method .. "() function")
end

-- Serialize the resumable subset of `records` and persist it through `backend`.
-- Returns the blob written (handy for tests / logging). An empty/no-resumable
-- list writes a headers-only blob that `load_records` reads back as no records.
function M.save_records(backend, records)
  assert_backend(backend, "write")
  local blob = M.serialize(M.to_resumable(records))
  backend.write(blob)
  return blob
end

-- Read and rebuild the persisted record list. Tolerant by way of `deserialize`:
-- a nil/empty/corrupt blob yields an empty list ("nothing to resume").
function M.load_records(backend)
  assert_backend(backend, "read")
  return M.deserialize(backend.read())
end

-- Drop the persisted blob (after a clean resume, or on logout). Distinct from
-- `save_records({}, ...)` only for intent; both write the empty blob.
function M.clear_records(backend)
  assert_backend(backend, "write")
  backend.write("")
end

-- Adapt a darktable-style preferences object to the {read, write} backend
-- interface. `prefs` must expose read(plugin, key, type) / write(plugin, key,
-- type, value) — exactly `dt.preferences`. Takes `prefs` as a parameter (rather
-- than `require`-ing darktable) so this module stays offline-importable; lives
-- here so wiring it in the main module is a one-liner that costs no main-chunk
-- local. A nil read normalizes to "" so `deserialize` sees a string.
function M.make_pref_backend(prefs, plugin, key)
  assert(type(prefs) == "table" and type(prefs.read) == "function"
    and type(prefs.write) == "function",
    "make_pref_backend requires a preferences object with read()/write()")
  plugin = plugin or "dtrmflickr"
  key = key or "queue_resume"
  return {
    read = function() return prefs.read(plugin, key, "string") or "" end,
    write = function(blob) prefs.write(plugin, key, "string", tostring(blob or "")) end,
  }
end

return M
end

