--   reconstruction handler re-derives the still-pending reasons from the image's
--   tags and re-runs ONLY those setters. Re-running an idempotent setter converges
--   to the same Flickr state, so there is no duplicate and no harm if the photo was
--   already fully synced (the handler then finds nothing pending and no-ops).
--
--   The record uses method "dtrmflickr.resend", which `queue_jobs.is_idempotent`
--   classifies idempotent and (state "queued") `is_safely_resumable`, so
--   `plan_resume_safe` routes it to `runnable` and the resume executor (#57) re-runs
--   it with NO duplicate photo/album. The non-idempotent upload stays out of the
--   resume blob entirely: an image that never finished uploading simply isn't
--   recorded here, and the user re-exports it (current behaviour, no duplicate).
--
-- This module is pure / offline-importable: every darktable dependency (image
-- resolution, the Flickr call wrapper, rest/metadata/state helpers) is INJECTED by
-- the main module, never `require`d here, so it stays unit-testable without a
-- darktable runtime and costs no main-chunk locals.
----------------------------------------------------------------------

local M = {}

-- The synthetic method name for a post-upload metadata-remainder resume record.
-- Kept idempotent + safely-resumable by queue_jobs (unknown/own methods default
-- idempotent; state "queued" never started). Must NOT be one of the queue's
-- non-idempotent methods.
M.METHOD = "dtrmflickr.resend"

-- A durable, restart-stable key for a darktable image. Within one library the
-- image's numeric `id` is stable across restarts, so it round-trips through the
-- serialized resume blob and can be resolved back to the image at startup. Returns
-- nil for a nil image or one with no id (which therefore produces no record).
function M.image_key(image)
  if image == nil then return nil end
  local id = image.id
  if id == nil then return nil end
  id = tostring(id)
  if id == "" then return nil end
  return id
end

-- Normalize a value into a clean list of distinct, non-empty photoset-id strings.
-- Accepts nil, a single id, or a list; trims out empties and de-dupes (stable
-- order). Used both to seed a record's intended-album set and to merge a freshly
-- created photoset id into an existing record. Returns nil for an empty result so
-- a record never carries an empty `sets` table (keeps a clean record minimal).
function M.normalize_sets(...)
  local out, seen = {}, {}
  local function add_one(v)
    if v == nil then return end
    local s = tostring(v)
    if s == "" or seen[s] then return end
    seen[s] = true
    out[#out + 1] = s
  end
  for _, arg in ipairs({ ... }) do
    if type(arg) == "table" then
      for _, v in ipairs(arg) do add_one(v) end
    else
      add_one(arg)
    end
  end
  if #out == 0 then return nil end
  return out
end

-- Collect the intended Flickr photoset id(s) from a resolved export-album spec
-- (`extra_data.album`) that are known UP FRONT — i.e. EXISTING albums (kind
-- "existing", including a "create" that matched an existing title). A pure
-- `kind == "create"` target has no photoset id yet (it is created in finalize),
-- so it is deliberately excluded: a never-created set must never be re-created
-- from a resume record (no-duplicate-album contract — finalize keeps
-- photosets.create at max_attempts=1 and resume never re-runs it). Returns nil
-- when there are no known set ids (so build_record gets a minimal record).
function M.existing_set_ids(album)
  if type(album) ~= "table" then return nil end
  local ids = {}
  for _, target in ipairs(album.targets or {}) do
    if type(target) == "table" and target.kind ~= "create"
       and target.photoset_id ~= nil and tostring(target.photoset_id) ~= "" then
      ids[#ids + 1] = target.photoset_id
    end
  end
  return M.normalize_sets(ids)
end

-- Build a resume record describing the post-upload remainder for one uploaded
-- image. Pure. Returns nil when there is no usable image key (so a caller can
-- `if rec then add_pending(rec) end` unconditionally).
--
--   image_key : durable id string (from M.image_key)
--   nsid      : owning account nsid (account-binding contract)
--   label     : optional human label (filename) for the panel/log
--   sets      : optional intended Flickr photoset id(s) this image should belong
--               to (issue #79) — a single id or a list. The reconstruction files
--               the photo into each one not already a member, via idempotent
--               addPhoto. Omitted/empty for a no-album export.
function M.build_record(image_key, nsid, label, sets)
  if image_key == nil or image_key == "" then return nil end
  return {
    method = M.METHOD,
    nsid = (nsid ~= nil and nsid ~= "") and tostring(nsid) or nil,
    image = tostring(image_key),
    -- "queued" = never started executing on the async pump. Combined with the
    -- idempotent method this is what makes `is_safely_resumable` return true and
    -- routes the record to `runnable` (not `uncertain`) at restart.
    state = "queued",
    label = label,
    sets = M.normalize_sets(sets),
  }
end

-- Re-run the still-pending, sync-enabled metadata setters for a single already-
-- uploaded image. This is the idempotent remainder a resume replays; it mirrors
-- the panel's `push_selected_metadata` single-image body but is dependency-injected
-- so it is offline-testable and lives off the main-chunk local budget.
--
-- deps (all injected by the main module's reconstruction handler):
--   call(method, fn)                 -> ok, err   (the shared __dtrmflickr_call)
--   rest                             -> flickr_rest module
--   metadata                         -> metadata module
--   state                            -> state module
--   sync                             -> resolved master_sync_fields() table
--   fingerprints(image, sync)        -> effective_metadata_fingerprints
--   store_fingerprints(image, nsid, fingerprints, fields) -> persist helper
--   keyword_tags(image)              -> rules.image_keyword_tags
--   sets                             -> optional intended photoset id(s) (#79):
--                                       file the photo into each one it is not yet
--                                       a member of, via idempotent addPhoto
--   already_in_set(err)              -> optional predicate: true when an addPhoto
--                                       error means "already in set" (Flickr err 3),
--                                       treated as success. Defaults to false.
--   tr(s)                            -> optional translate hook (defaults identity)
--
-- Returns (status, detail):
--   "synced"   detail = number of fields/album-adds pushed (>=1 action succeeded)
--   "clean"    detail = nil                        (nothing was pending — no-op)
--   "unlinked" detail = nil                        (no Flickr photo id for account)
--   "error"    detail = error string              (a setter/add failed)
-- A truthy first return (any non-"error" status string) lets the queue treat the
-- resumed job as success; "error" returns (nil, detail) to trigger normal retry of
-- the idempotent setters/adds.
function M.resend_image(image, acc, deps)
  deps = deps or {}
  local call = deps.call
  local rest = deps.rest
  local meta = deps.metadata
  local state = deps.state
  local sync = deps.sync or {}
  local tr = deps.tr or function(s) return s end
  if image == nil or acc == nil or acc.nsid == nil then
    return nil, "resume resend: missing image/account"
  end
  local photo_id = state.get_photo_id(image, acc.nsid)
  if photo_id == nil or photo_id == "" then
    -- No linked photo for this account: nothing to resend (and never re-upload).
    return "unlinked"
  end
  -- Album-membership remainder (issue #79): the intended set ids this image
  -- should belong to but may not yet (a quit before/inside finalize's addPhoto
  -- loop). Compute the still-pending adds up front so a record whose ONLY pending
  -- work is an album add is not short-circuited as "clean" by the metadata plan.
  local pending_sets = {}
  if deps.sets ~= nil then
    local member = {}
    for _, sid in ipairs(state.get_sets(image, acc.nsid) or {}) do
      member[tostring(sid)] = true
    end
    local wanted = M.normalize_sets(deps.sets) or {}
    for _, sid in ipairs(wanted) do
      if not member[sid] then pending_sets[#pending_sets + 1] = sid end
    end
  end

  local fingerprints = deps.fingerprints and deps.fingerprints(image, sync) or nil
  local _status, _pub, _pid, reasons = state.evaluate_publish_state(image, acc.nsid, {
    metadata_fingerprints = fingerprints,
  })
  local plan = meta.metadata_resend_plan(sync, reasons)
  if not plan.any and #pending_sets == 0 then
    return "clean"
  end

  local pushed = 0
  local meta_pushed = 0
  local function push(reason, method, fn)
    local ok, err = call(method, fn)
    if ok then
      state.clear_reason(image, acc.nsid, reason)
      if deps.store_fingerprints and fingerprints then
        deps.store_fingerprints(image, acc.nsid, fingerprints, { reason })
      end
      pushed = pushed + 1
      meta_pushed = meta_pushed + 1
      return true
    end
    state.mark_reason(image, acc.nsid, reason)
    return false, err
  end

  if plan.send_meta then
    local title = sync.title and (image.title or "") or nil
    local description = sync.description and (image.description or "") or nil
    local ok, err = push("title_description", "flickr.photos.setMeta", function()
      return rest.photos_set_meta(deps.api_key, deps.api_secret, acc, photo_id, title, description)
    end)
    if not ok then return nil, err end
  end
  if plan.send_tags then
    local tags = (deps.keyword_tags and deps.keyword_tags(image)) or ""
    local ok, err = push("keywords", "flickr.photos.setTags", function()
      return rest.photos_set_tags(deps.api_key, deps.api_secret, acc, photo_id, tags)
    end)
    if not ok then return nil, err end
  end
  if plan.send_date then
    local date_taken = meta.image_date_taken(image)
    local ok, err = push("date_taken", "flickr.photos.setDates", function()
      return rest.photos_set_dates(deps.api_key, deps.api_secret, acc, photo_id, date_taken, 0)
    end)
    if not ok then return nil, err end
  end
  if plan.send_gps then
    local lat, lon = meta.image_location(image)
    local ok, err = push("gps", "flickr.photos.geo.setLocation", function()
      return rest.photos_geo_set_location(deps.api_key, deps.api_secret, acc, photo_id, lat, lon, 16)
    end)
    if not ok then return nil, err end
  end

  -- File the photo into any still-pending intended albums (issue #79). addPhoto
  -- is idempotent: replaying a member add converges, and Flickr error 3 ("already
  -- in set") is treated as success — so a resume that races a partly-filed batch
  -- never duplicates membership. A genuine add failure returns (nil, err) to
  -- retry the whole idempotent job; the metadata reasons cleared above stay
  -- cleared in state.lua, so the retry re-runs only what is still pending.
  local already_in_set = deps.already_in_set or function() return false end
  for _, set_id in ipairs(pending_sets) do
    local ok, err = call("flickr.photosets.addPhoto", function()
      return rest.photosets_add_photo(deps.api_key, deps.api_secret, acc, set_id, photo_id)
    end)
    if ok or already_in_set(err) then
      state.add_set(image, acc.nsid, set_id)
      pushed = pushed + 1
    else
      return nil, err
    end
  end

  if meta_pushed > 0 then
    -- Only stamp the metadata-published marker when a metadata setter actually
    -- ran; an album-only resend (pushed > 0, meta_pushed == 0) leaves it untouched.
    state.set_metadata_published_at(image, acc.nsid)
  end
  if pushed > 0 then
    return "synced", pushed
  end
  return "clean"
end

-- Reconstruct a job descriptor from a persisted resume record (the
-- `__dtrmflickr_resume_handlers[METHOD]` body). Pure with respect to darktable:
-- the live wiring is injected.
--
-- deps:
--   resolve_image(image_key) -> image | nil   (find the darktable image by id)
--   account()                -> acc   | nil   (the active account)
--   resend(image, acc, sets) -> status, detail (M.resend_image bound to live deps);
--                               `sets` is the record's intended-album id list (#79)
--
-- Returns a `{ method, fn, opts }` descriptor for Queue:submit_async, or nil when
-- the image can no longer be resolved / there is no active account (the executor
-- then keeps the record persisted for a later session rather than dropping it).
function M.rebuild(rec, deps)
  if type(rec) ~= "table" or rec.image == nil then return nil end
  deps = deps or {}
  if type(deps.resolve_image) ~= "function" or type(deps.resend) ~= "function" then
    return nil
  end
  local image = deps.resolve_image(rec.image)
  if image == nil then return nil end
  local acc = deps.account and deps.account() or nil
  if acc == nil or acc.nsid == nil then return nil end
  -- Account-binding contract: only resume a record whose owning nsid matches the
  -- active account. plan_resume_safe already enforced this (orphans never reach a
  -- runnable rebuild), but re-check defensively so a mis-wired caller can never
  -- resend one account's image under another account's token.
  if rec.nsid ~= nil and tostring(rec.nsid) ~= tostring(acc.nsid) then return nil end
  return {
    method = M.METHOD,
    fn = function() return deps.resend(image, acc, rec.sets) end,
    opts = {},
  }
end

return M
end

package.preload["dtrmflickr.queue_panel"] = function(...)
-- queue_panel.lua — pure formatting for the live job-lifecycle panel (issue #56).
--
-- The lighttable Flickr panel can now render "what is each queued job doing right
-- now" by polling the `queue_jobs` lifecycle tracker (which collapses the queue's
-- async `on_event` stream into one explicit per-job state). This module is the
-- pure, offline-testable presentation layer between that tracker snapshot and the
-- darktable label widgets the main module owns:
--
--   * `job_line(rec)`         — one record -> one human row
--                               (state · name · attempt · error).
--   * `build(snapshot, opts)` — a tracker snapshot -> a bounded, stably-ordered
--                               list of rows plus a one-line counts summary. Live
--                               (non-terminal) jobs are always kept; terminal jobs
--                               backfill the remaining budget, most-recent first;
--                               rows are emitted in the tracker's insertion order
--                               so a job never jumps around between polls.
--   * `uncertain_summary` / `uncertain_lines` — surface the resume planner's
--                               `uncertain` records (a non-idempotent job that may
--                               already have reached Flickr — see
--                               queue_jobs.plan_resume_safe) so the panel can flag
--                               them for an explicit user decision instead of
--                               silently re-running and risking a duplicate.
--
-- It touches no darktable or network API (a `translate` hook localizes the few
-- fixed strings; record data is user content / ids and is never translated), so
-- the whole layer is unit-tested in tests/test_queue_panel.lua. Living outside the
-- main module keeps it off the Lua main-chunk local-variable budget (CLAUDE.md);
-- it is wired into tools/build-single-file.ps1.

local M = {}

-- Human word per lifecycle state. Kept short for a narrow panel column. The set
-- mirrors queue_jobs.STATES; `succeeded` reads as the friendlier "done".
M.STATE_WORD = {
  queued = "queued", running = "running", waiting = "waiting",
  retrying = "retrying", succeeded = "done", failed = "failed",
  stale = "stale", cancelled = "cancelled",
}

local TERMINAL = {
  succeeded = true, failed = true, stale = true, cancelled = true,
}

-- Order states appear in the summary line: live states first (most interesting),
-- then terminal outcomes.
local SUMMARY_ORDER = {
  "running", "retrying", "waiting", "queued",
  "succeeded", "failed", "stale", "cancelled",
}

local function identity(s) return s end

-- A job's display name: its explicit label, else the Flickr method, else a
-- generic word. Never translated (label/method are user content / ids).
function M.name_of(rec)
  if type(rec) ~= "table" then return "?" end
  local label = rec.label
  if label ~= nil and tostring(label) ~= "" then return tostring(label) end
  local method = rec.method
  if method ~= nil and tostring(method) ~= "" then return tostring(method) end
  return "request"
end

-- One record -> one row: "<state> · <name>" with an optional " (attempt N)" when
-- a job has been tried more than once and an optional ": <error>" when an error
-- is recorded. Pure; `translate` localizes only the fixed "attempt" word.
function M.job_line(rec, translate)
  translate = translate or identity
  local state = rec and tostring(rec.state or "") or ""
  local word = M.STATE_WORD[state] or state
  if word == "" then word = "?" end
  local line = word .. " \194\183 " .. M.name_of(rec)  -- \194\183 = U+00B7 middle dot
  local attempts = rec and tonumber(rec.attempts) or nil
  if attempts and attempts > 1 then
    line = line .. string.format(translate(" (attempt %d)"), attempts)
  end
  local err = rec and rec.error
  if err ~= nil and tostring(err) ~= "" then
    line = line .. ": " .. tostring(err)
  end
  return line
end

-- One-line counts summary, e.g. "jobs: 2 running, 1 retrying, 3 done, 1 failed".
-- Only non-zero states are listed, in SUMMARY_ORDER. When the grid is showing
-- fewer rows than the tracker holds, append " (showing S/T)" so a user knows the
-- view is capped. Returns "" for an empty queue. Pure.
function M.summary_line(counts, total, shown, translate)
  translate = translate or identity
  counts = counts or {}
  total = tonumber(total) or 0
  if total <= 0 then return "" end
  local parts = {}
  for _, state in ipairs(SUMMARY_ORDER) do
    local n = tonumber(counts[state]) or 0
    if n > 0 then
      parts[#parts + 1] = string.format("%d %s", n, M.STATE_WORD[state] or state)
    end
  end
  local line = translate("jobs: ") .. table.concat(parts, ", ")
  shown = tonumber(shown) or total
  if shown < total then
    line = line .. string.format(translate(" (showing %d/%d)"), shown, total)
  end
  return line
end

-- A tracker snapshot (insertion-ordered list of record copies) -> a bounded view.
-- opts.limit (default 12) caps how many rows render. Selection priority: keep the
-- live (non-terminal) jobs first — most-recent first when even those overflow the
-- cap — then backfill the remaining budget with the most-recent terminal jobs.
-- Whatever is chosen is emitted in the original insertion order, so the rows are
-- stable across polls (a job keeps its slot; it does not jump when its state
-- changes). Returns { lines, shown, total, counts, summary }. Pure.
function M.build(snapshot, opts)
  opts = opts or {}
  local translate = opts.translate or identity
  local limit = math.max(1, math.floor(tonumber(opts.limit) or 12))
  snapshot = snapshot or {}

  local counts = {}
  local live_idx, term_idx = {}, {}
  for i, rec in ipairs(snapshot) do
    local state = tostring((rec and rec.state) or "")
    counts[state] = (counts[state] or 0) + 1
    if TERMINAL[state] then
      term_idx[#term_idx + 1] = i
    else
      live_idx[#live_idx + 1] = i
    end
  end

  -- Pick indices to show: live first (most-recent first if capped), then the
  -- most-recent terminal jobs to fill the rest.
  local chosen = {}
  local shown = 0
  for j = #live_idx, 1, -1 do
    if shown >= limit then break end
    chosen[live_idx[j]] = true
    shown = shown + 1
  end
  for j = #term_idx, 1, -1 do
    if shown >= limit then break end
    chosen[term_idx[j]] = true
    shown = shown + 1
  end

  -- Emit in insertion order so slots are stable across refreshes.
  local lines = {}
  for i, rec in ipairs(snapshot) do
    if chosen[i] then lines[#lines + 1] = M.job_line(rec, translate) end
  end

  return {
    lines = lines,
    shown = #lines,
    total = #snapshot,
    counts = counts,
    summary = M.summary_line(counts, #snapshot, #lines, translate),
  }
end

-- One-line headline for the resume planner's `uncertain` set: non-idempotent jobs
-- that were interrupted after they may have reached Flickr, so re-running risks a
-- duplicate. Empty list -> "". Pure.
function M.uncertain_summary(records, translate)
  translate = translate or identity
  records = records or {}
  local n = #records
  if n <= 0 then return "" end
  return string.format(
    translate("interrupted uploads needing your decision: %d (may already be on Flickr)"),
    n)
end

-- One row per uncertain record: "<name> (<state>)". Never translated (record data
-- is user content / ids). Returns a (possibly empty) list. Pure.
function M.uncertain_lines(records)
  local out = {}
  for _, rec in ipairs(records or {}) do
    if type(rec) == "table" then
      local state = tostring(rec.state or "")
      local suffix = state ~= "" and (" (" .. state .. ")") or ""
      out[#out + 1] = M.name_of(rec) .. suffix
    end
  end
  return out
end

return M
end

