  local updated = tonumber(counts.updated) or 0
  if updated > 0 then
    return string.format(tr("Flickr: finished — %d uploaded, %d updated, %d skipped, %d failed, %d post-upload error(s), %d album error(s), %d total"),
      counts.uploaded or 0, updated, counts.skipped or 0, counts.failed or 0,
      counts.post_errors or 0, counts.album_errors or 0, counts.total or 0)
  end
  return string.format(tr("Flickr: finished — %d uploaded, %d skipped, %d failed, %d post-upload error(s), %d album error(s), %d total"),
    counts.uploaded or 0, counts.skipped or 0, counts.failed or 0,
    counts.post_errors or 0, counts.album_errors or 0, counts.total or 0)
end

----------------------------------------------------------------------
-- Per-image result table (issue #6).
--
-- The compact named lines above are tuned for the panel's transient toast:
-- they collapse to per-bucket name lists. For a large batch the user also
-- wants the full picture — one row per image with its status and the relevant
-- id/reason/error — which belongs in the darktable log, not a toast. These
-- helpers build that table from the same `extra_data` buckets `store`/`finalize`
-- already populate, so they stay pure and offline-testable.
--
-- A live, incrementally-updating in-panel grid is not buildable today: darktable
-- storage callbacks are synchronous and the queue drains within a single call,
-- so intermediate per-row states are never observable. This is the realistic
-- end-of-batch form; the live grid stays gated on the async/persistent queue.

-- Turn one skipped result entry into a human reason string. `store` records
-- skipped rows with heterogeneous fields depending on which rule fired
-- (keyword skip-filter, rating threshold, color label). Pure and nil-safe.
local function skip_reason(entry)
  if type(entry) ~= "table" then return "skipped" end
  if entry.reason == "rating" then
    return string.format("rating %s below threshold %s",
      tostring(entry.rating), tostring(entry.threshold))
  end
  if entry.reason == "color_label" then
    return string.format("color label '%s' matched skip rule", tostring(entry.label))
  end
  if entry.filter then
    return string.format("keyword '%s' matched skip rule '%s'",
      tostring(entry.tag or ""), tostring(entry.filter))
  end
  if entry.reason and entry.reason ~= "" then return tostring(entry.reason) end
  return "skipped"
end
M.skip_reason = skip_reason

-- Build a structured, ordered per-image result list from the finalize buckets.
-- Returns rows in summary order (uploaded, then skipped, then failed). Each row
-- is one of:
--   { kind = "uploaded", filename, photo_id, failed_actions = { <action>, ... } }
--   { kind = "skipped",  filename, reason = <string> }
--   { kind = "failed",   filename, error = <string> }
-- Post-upload metadata errors are not their own rows: a post-error always
-- belongs to an image that *did* upload, so it is folded into that uploaded
-- row's `failed_actions` (matched by photo_id, falling back to the same image
-- object). `failed_actions` is always a list (empty when the upload was clean),
-- so a row with #failed_actions > 0 is a "partial" success.
--
-- `owner` (optional) is the active account's NSID/path_alias. When supplied,
-- each uploaded row gets a `url` field with its public Flickr photo page URL
-- (issue #37). Omit it (as the offline tests do) and rows carry no `url`.
function M.result_rows(extra_data, owner)
  extra_data = extra_data or {}
  local rows = {}

  -- Index post-upload errors by the photo they belong to so each uploaded row
  -- can collect its own failed actions. Prefer photo_id (a stable string id);
  -- fall back to the image object identity when an id is somehow absent.
  local post_by_id, post_by_image = {}, {}
  for _, pe in ipairs(extra_data.post_errors or {}) do
    if type(pe) == "table" then
      local action = pe.action or "metadata"
      if pe.photo_id ~= nil and pe.photo_id ~= "" then
        local key = tostring(pe.photo_id)
        post_by_id[key] = post_by_id[key] or {}
        post_by_id[key][#post_by_id[key] + 1] = action
      elseif pe.image ~= nil then
        post_by_image[pe.image] = post_by_image[pe.image] or {}
        post_by_image[pe.image][#post_by_image[pe.image] + 1] = action
      end
    end
  end

  for _, up in ipairs(extra_data.uploaded or {}) do
    local actions
    if up.photo_id ~= nil and post_by_id[tostring(up.photo_id)] then
      actions = post_by_id[tostring(up.photo_id)]
    elseif up.image ~= nil and post_by_image[up.image] then
      actions = post_by_image[up.image]
    end
    rows[#rows + 1] = {
      kind = "uploaded",
      filename = display_name(up),
      photo_id = up.photo_id,
      replaced = (type(up) == "table" and up.replaced) and true or false,
      failed_actions = actions or {},
      attempts = tonumber(up.attempts),
      url = owner and urls.photo_url(owner, up.photo_id) or nil,
    }
  end
  for _, sk in ipairs(extra_data.skipped or {}) do
    rows[#rows + 1] = { kind = "skipped", filename = display_name(sk), reason = skip_reason(sk) }
  end
  for _, fa in ipairs(extra_data.failed or {}) do
    rows[#rows + 1] = {
      kind = "failed",
      filename = display_name(fa),
      error = (fa and fa.error and tostring(fa.error)) or "unknown error",
      attempts = tonumber(fa.attempts),
    }
  end
  return rows
end

-- Display status word for a result row: "partial" for an uploaded row that had
-- a post-upload metadata error, "updated" for a clean replace-in-place row
-- (issue #60), otherwise the row's kind verbatim. "partial" wins over "updated"
-- so a replaced photo whose metadata setter failed is still flagged as partial.
local function row_status(row)
  if row.kind == "uploaded" then
    if row.failed_actions and #row.failed_actions > 0 then return "partial" end
    if row.replaced then return "updated" end
  end
  return row.kind
end
M.row_status = row_status

-- A " (N attempts)" suffix for a row whose work retried (N > 1). Upload itself
-- is single-attempt, so this only appears when an idempotent post-upload setter
-- (or a failed-row's call) rode out a transient/rate-limit error. Empty string
-- for a clean first-try row (or a skipped row, which never ran a call), so the
-- detail column stays terse in the common case.
local function attempts_suffix(row)
  local n = tonumber(row.attempts)
  if n and n > 1 then return string.format(" (%d attempts)", n) end
  return ""
end
M.attempts_suffix = attempts_suffix

-- The right-hand detail column for a result row. When an uploaded row carries a
-- `url` (owner was known — issue #37), the public Flickr photo page URL is
-- appended so the result table doubles as a copyable link list.
local function row_detail(row)
  if row.kind == "uploaded" then
    local verb = row.replaced and "updated" or "uploaded"
    local photo = row.photo_id and ((row.replaced and "updated photo " or "photo ") .. tostring(row.photo_id)) or verb
    local url_suffix = (row.url and row.url ~= "") and ("  " .. row.url) or ""
    if row.failed_actions and #row.failed_actions > 0 then
      return string.format("%s (%s update failed)%s%s", photo,
        table.concat(row.failed_actions, ", "), attempts_suffix(row), url_suffix)
    end
    return photo .. attempts_suffix(row) .. url_suffix
  elseif row.kind == "skipped" then
    return row.reason or "skipped"
  else
    return (row.error or "unknown error") .. attempts_suffix(row)
  end
end
M.row_detail = row_detail

-- Render the per-image result rows into aligned text lines for the log. The
-- status and filename columns are left-padded to their widest value so the
-- table reads as a grid. Returns an empty list when there are no rows, so the
-- caller emits nothing for an all-clean export with no images. `opts.translate`
-- localizes only the header line (the row data is user content / ids).
--
-- `opts.max_rows` caps how many image rows are rendered before collapsing the
-- rest into a single "(+N more — see log)" footer; the header still counts every
-- row. Omit it (as the log call does) and the full table is emitted. The widths
-- are measured over the *shown* rows only, so a capped panel table stays narrow.
function M.result_table_lines(extra_data, opts)
  opts = opts or {}
  local tr = opts.translate
  if type(tr) ~= "function" then tr = function(s) return s end end
  local rows = M.result_rows(extra_data, opts.owner)
  local total = #rows
  if total == 0 then return {} end

  local max = tonumber(opts.max_rows)
  local shown = total
  if max and max >= 1 and total > max then shown = max end

  local status_w, name_w = 0, 0
  local cells = {}
  for i = 1, shown do
    local row = rows[i]
    local s, n = row_status(row), row.filename or "?"
    cells[i] = { status = s, name = n, detail = row_detail(row) }
    if #s > status_w then status_w = #s end
    if #n > name_w then name_w = #n end
  end

  local lines = {}
  lines[#lines + 1] = string.format(tr("Flickr: per-image results (%d):"), total)
  local fmt = string.format("  %%-%ds  %%-%ds  %%s", status_w, name_w)
  for _, c in ipairs(cells) do
    lines[#lines + 1] = string.format(fmt, c.status, c.name, c.detail)
  end
  if shown < total then
    lines[#lines + 1] = string.format(tr("  (+%d more — see log for the full table)"), total - shown)
  end
  return lines
end

-- Compose the panel-facing result block (issue #40): the aggregate summary line
-- followed by the capped per-image table, joined into one multi-line string for
-- a darktable label widget. `finalize` already computes the bucket counts, so it
-- passes them in `counts` (the same shape M.finalize_summary takes); the table
-- is built from the raw `extra_data` buckets. Returns "" when nothing was
-- processed (no summary worth showing), so the panel can blank its result label.
--
-- `opts.translate` localizes, `opts.owner` adds per-row Flickr URLs, and
-- `opts.max_rows` (default 20) caps the in-panel table — the full table still
-- goes to the log via M.result_table_lines with no cap.
function M.result_panel_text(counts, extra_data, opts)
  opts = opts or {}
  counts = counts or {}
  local total = tonumber(counts.total) or 0
  if total == 0 then return "" end
  local max = tonumber(opts.max_rows) or 20
  local parts = { M.finalize_summary(counts, opts) }
  for _, line in ipairs(M.result_table_lines(extra_data, {
    translate = opts.translate, owner = opts.owner, max_rows = max,
  })) do
    parts[#parts + 1] = line
  end
  return table.concat(parts, "\n")
end

-- The uploaded photos that have a public Flickr URL, as a structured list of
-- { name = <recognizable filename>, url = <photo page URL> } (issue #40 open/copy
-- buttons; issue #37 toast). Needs the active account's `owner` (NSID/path_alias);
-- without it (or with no uploads) returns an empty list. Prefers the original
-- image basename (e.g. "IMG_1234.cr2") over the export temp path. Pure/testable.
function M.uploaded_links(extra_data, owner)
  local links = {}
  if not owner or owner == "" then return links end
  for _, up in ipairs((extra_data and extra_data.uploaded) or {}) do
    local url = urls.photo_url(owner, up.photo_id)
    if url then
      local img = type(up) == "table" and up.image
      local name = (type(img) == "table" and img.filename and img.filename ~= "")
        and img.filename or name_of(up)
      links[#links + 1] = { name = name, url = url }
    end
  end
  return links
end

-- Compact "resulting Flickr URL" lines for the panel toast (issue #37). The
-- per-image result table above is the full record and goes to the log; this is
-- the user-facing "here's where it landed" line per uploaded photo. Needs the
-- active account's `owner` (NSID/path_alias) to build the URL — without it (or
-- with no uploads) it returns an empty list and the caller prints nothing.
--
-- `opts.max` caps how many URL lines are emitted before collapsing the rest
-- into a single "(+N more — see log)" line, so a large batch does not flood the
-- transient toast; the full set is always in the result table the caller logs.
function M.uploaded_url_lines(extra_data, opts)
  opts = opts or {}
  local tr = opts.translate
  if type(tr) ~= "function" then tr = function(s) return s end end
  local owner = opts.owner
  local lines = {}
  if not owner or owner == "" then return lines end

  -- Only uploads that actually have a usable URL count toward the cap.
  local linkable = M.uploaded_links(extra_data, owner)

  local max = tonumber(opts.max) or 10
  if max < 1 then max = 1 end
  local n = #linkable
  local shown = math.min(n, max)
  for i = 1, shown do
    lines[#lines + 1] = string.format(tr("Flickr: %s -> %s"), linkable[i].name, linkable[i].url)
  end
  if n > shown then
    lines[#lines + 1] = string.format(tr("Flickr: (+%d more — see log for all URLs)"), n - shown)
  end
  return lines
end

return M
end

package.preload["dtrmflickr.tag_reconcile"] = function(...)
-- tag_reconcile.lua — pure diff / action-planning logic for the lighttable
-- Flickr tag reconciler (issue #3).
--
-- This module is deliberately free of any `darktable` dependency so it can be
-- unit-tested offline. The caller is responsible for collecting the two name
-- lists:
--   * local_names  — publishable darktable keyword leaf names (already filtered
--                    through rules/metadata so plugin/state/never-sync tags and
--                    private/category tags are excluded). See
--                    metadata.image_keyword_tags / rules.image_keyword_tags.
--   * remote_names — Flickr tag `raw` strings (parse_remote_tags in the main
--                    module).
--
-- Matching is case-insensitive on the trimmed text, mirroring how the upload
-- path de-dupes keywords (publish_tag_name lowercases its `seen` key) and how
-- Flickr itself collapses tags. The display forms are preserved as typed.

local M = {}

-- Normalize a tag for COMPARISON only (never for display or for sending to
-- Flickr). Lowercased + trimmed; embedded double quotes removed so a local
-- keyword and its stored-on-Flickr form (which can't carry a `"`) compare equal.
local function match_key(name)
  return tostring(name or ""):gsub('"', ""):match("^%s*(.-)%s*$"):lower()
end
M.match_key = match_key

-- Normalize a tag for SENDING to Flickr's space-delimited `tags` parameter.
-- Per CLAUDE.md's live-tested rule: strip embedded double quotes, preserve
-- backslashes literally, and quote the whole tag only when it contains
-- whitespace. Returns nil for an empty/quote-only tag.
local function encode_tag(name)
  name = tostring(name or ""):gsub('"', ""):match("^%s*(.-)%s*$")
  if name == "" then return nil end
  if name:find("%s") then return '"' .. name .. '"' end
  return name
end
M.encode_tag = encode_tag

-- Join a list of tag names into a single Flickr `tags` string. Empty/quote-only
-- entries are dropped; duplicates (case-insensitive) are collapsed, first form
-- wins. Returns "" for an empty result (setTags treats "" as "clear all tags").
function M.encode_tags(names)
  local seen = {}
  local out = {}
  for _, name in ipairs(names or {}) do
    local key = match_key(name)
    local encoded = encode_tag(name)
    if encoded and key ~= "" and not seen[key] then
      seen[key] = true
      out[#out + 1] = encoded
    end
  end
  return table.concat(out, " ")
end

local function sorted_unique(names)
  local seen = {}
  local out = {}
  for _, name in ipairs(names or {}) do
    local key = match_key(name)
    local trimmed = tostring(name or ""):match("^%s*(.-)%s*$")
    if key ~= "" and not seen[key] then
      seen[key] = true
      out[#out + 1] = trimmed
    end
  end
  table.sort(out, function(a, b)
    local la, lb = a:lower(), b:lower()
    if la == lb then return a < b end
    return la < lb
  end)
  return out
end

-- Diff local keywords against remote Flickr tags.
-- Returns a table:
--   local_only  — sorted display names present locally but not on Flickr
--   remote_only — sorted display names present on Flickr but not locally
--   matching    — sorted { local_name, remote_name } pairs present in both
-- All comparisons are case-insensitive; display forms are preserved. When a tag
-- matches, the local display form is used in `matching[i].name` (so "add" round
-- trips), with the remote form kept alongside for reference.
function M.diff(local_names, remote_names)
  local local_by_key = {}
  for _, name in ipairs(sorted_unique(local_names)) do
    local_by_key[match_key(name)] = name
  end
  local remote_by_key = {}
  for _, name in ipairs(sorted_unique(remote_names)) do
    remote_by_key[match_key(name)] = name
  end

  local result = { local_only = {}, remote_only = {}, matching = {} }
  for _, name in ipairs(sorted_unique(local_names)) do
    local key = match_key(name)
    if remote_by_key[key] then
      result.matching[#result.matching + 1] = { name = name, remote_name = remote_by_key[key] }
    else
      result.local_only[#result.local_only + 1] = name
    end
  end
  for _, name in ipairs(sorted_unique(remote_names)) do
    if not local_by_key[match_key(name)] then
      result.remote_only[#result.remote_only + 1] = name
    end
  end
  return result
end

-- ---- Action planners ---------------------------------------------------------
-- Flickr's flickr.photos.setTags is a FULL REPLACE of the tag set, so every
-- mutating action computes the COMPLETE intended tag set as a name list. The
-- caller encodes it with M.encode_tags before calling setTags. Returning name
-- lists (not the encoded string) keeps a single encode/dedup path and lets the
-- caller inspect the result (e.g. to decide whether local keywords are fully
-- published). The operations are idempotent: replaying the same plan converges
-- to the same tags.

-- "Add local-only keywords to Flickr": union of current remote tags + the
-- local-only keywords (case-insensitive dedup, remote forms win). Existing
-- remote tags are preserved.
function M.plan_add_local_only(remote_names, local_only)
  local merged = {}
  for _, n in ipairs(remote_names or {}) do merged[#merged + 1] = n end
  for _, n in ipairs(local_only or {}) do merged[#merged + 1] = n end
  local seen, out = {}, {}
  for _, n in ipairs(merged) do
    local key = match_key(n)
    if key ~= "" and not seen[key] then seen[key] = true; out[#out + 1] = n end
  end
  return out
end

-- "Remove selected Flickr tags": remote tags minus the chosen names.
function M.plan_remove(remote_names, to_remove)
  local remove_keys = {}
  for _, n in ipairs(to_remove or {}) do remove_keys[match_key(n)] = true end
  local kept = {}
  for _, n in ipairs(remote_names or {}) do
    if not remove_keys[match_key(n)] then kept[#kept + 1] = n end
  end
  return kept
end

-- "Replace Flickr tags from local keywords": the full local set, nothing else.
function M.plan_replace(local_names)
  return sorted_unique(local_names)
end

-- "Pull remote-only tags into darktable": the list of remote tag names that
-- should be added as darktable keywords (the caller adds them via dt.tags).
function M.plan_pull_remote_only(remote_only)
  return sorted_unique(remote_only)
end

return M
end

package.preload["dtrmflickr.people"] = function(...)
-- people.lua — pure helpers for Flickr people tagging (issues #24, #18).
--
-- The darktable-side wiring (resolving identifiers to NSIDs, calling
-- flickr.photos.people.add) lives in dtrmflickr.lua; the signed REST plumbing and
-- response parsers live in flickr_rest.lua. This module holds only the
-- side-effect-free decision logic so it can be unit-tested offline:
--   * parse_identifiers — turn the free-text panel field into distinct tokens
--   * add_plan          — idempotent diff of who still needs adding to the photo

local M = {}

-- Split a free-text "people" field into a list of distinct identifier tokens.
-- Tokens are separated by commas or new lines only — NOT spaces, because Flickr
-- usernames may legitimately contain spaces (e.g. "Jane Doe"). Each token is
-- trimmed; empty tokens are dropped; duplicates collapse case-insensitively with
-- the first spelling winning. A token containing "@" is classified as an email
-- (resolved via flickr.people.findByEmail), otherwise a username
-- (flickr.people.findByUsername). Returns a list of { value = <trimmed string>,
-- kind = "email" | "username" }.
function M.parse_identifiers(text)
  local out, seen = {}, {}
  for token in tostring(text or ""):gmatch("[^,\r\n]+") do
    local value = token:match("^%s*(.-)%s*$")
    if value ~= "" then
      local key = value:lower()
      if not seen[key] then
        seen[key] = true
        out[#out + 1] = {
          value = value,
          kind = value:find("@", 1, true) and "email" or "username",
        }
      end
    end
  end
  return out
end

-- Decide which resolved members still need adding to a photo, idempotently.
-- `resolved` is a list of { value = <original identifier>, nsid = <NSID|nil> }
-- (the result of looking each identifier up via findByUsername/findByEmail).
-- `existing_nsids` is the list of NSIDs already on the photo (from
-- flickr.photos.people.getList). For each entry an action is assigned:
--   "unresolved" — no NSID (lookup failed); nothing to add
--   "present"    — NSID already on the photo; skip (idempotent re-run)
--   "duplicate"  — a different identifier in this request already resolved to the
--                  same NSID; collapse to a single add
--   "add"        — genuinely new; queue an flickr.photos.people.add call
-- Returns { to_add = { nsid, ... },           -- NSIDs to add, de-duplicated
--           already_present = { value, ... },  -- identifiers skipped as present
--           entries = { { value, nsid, action }, ... } }.  -- full per-input trace
function M.add_plan(resolved, existing_nsids)
  local present = {}
  for _, id in ipairs(existing_nsids or {}) do
    local nsid = tostring(id or "")
    if nsid ~= "" then present[nsid] = true end
  end

  local queued = {}
  local to_add, already_present, entries = {}, {}, {}
  for _, e in ipairs(resolved or {}) do
    local nsid = tostring(e and e.nsid or "")
    local entry = { value = e and e.value or "", nsid = nsid }
    if nsid == "" then
      entry.action = "unresolved"
    elseif present[nsid] then
      entry.action = "present"
      already_present[#already_present + 1] = entry.value
    elseif queued[nsid] then
      entry.action = "duplicate"
    else
      queued[nsid] = true
      entry.action = "add"
      to_add[#to_add + 1] = nsid
    end
    entries[#entries + 1] = entry
  end

  return { to_add = to_add, already_present = already_present, entries = entries }
end

return M
end

package.preload["dtrmflickr.albums"] = function(...)
-- albums.lua — pure album (photoset) input helpers.
--
-- The album field on the export panel (and the lighttable panel) lets a user
-- name SEVERAL albums at once, separated by commas, so one upload can land in
-- multiple photosets (issue #27). The actual resolution against the fetched
-- album cache and the Flickr REST calls live in the main module / flickr_rest,
-- but the parsing + target-building is pure string work — kept here so both the
-- export path and the panel share one implementation and it can be unit-tested
-- without darktable UI state.

local M = {}

local function trim(s)
  return (tostring(s or ""):gsub("^%s+", ""):gsub("%s+$", ""))
end

-- ---------------------------------------------------------------------------
-- Album-cache helpers (issue #45)
--
-- These used to live in the main module as closures over the `album_cache`
-- table. They are pure: where they need the cache they take it as an explicit
-- first argument, so they can be unit-tested and shared by the export and panel
-- paths without darktable UI state. The main module still owns the actual
-- `album_cache` table (its mutation is tied to widget refreshes) and passes it
-- in.
-- ---------------------------------------------------------------------------

-- Sort key for natural-ish album ordering: a leading integer sorts numerically
-- (so "20031107 ..." groups before plain-text titles and orders by number),
-- everything else falls back to a case-insensitive title compare.
local function natural_title_key(item)
  local title = trim(item and item.title or "")
  if title == "" then title = tostring(item and item.id or "") end
  local prefix, rest = title:match("^(%d+)%s*(.*)$")
  if prefix then
    return 0, tonumber(prefix) or 0, rest:lower(), title:lower()
  end
  return 1, 0, title:lower(), title:lower()
end
M.natural_title_key = natural_title_key

-- Sort a list of album items in place (numeric-prefix-aware, then title).
function M.sort(items)
  table.sort(items, function(a, b)
    local ag, an, ar, at = natural_title_key(a)
    local bg, bn, br, bt = natural_title_key(b)
    if ag ~= bg then return ag < bg end
    if an ~= bn then return an < bn end
    if ar ~= br then return ar < br end
    if at ~= bt then return at < bt end
    return tostring(a.id or "") < tostring(b.id or "")
  end)
end

-- Human-readable combobox/status label for one album item: "Title (#id) - N photo(s)".
function M.label(item)
  local title = trim(item and item.title or "")
  local id = tostring(item and item.id or "")
  local count = item and item.photos and tostring(item.photos) or nil
  if title == "" then title = id end
  local label = string.format("%s (#%s)", title, id)
  if count and count ~= "" then
    return string.format("%s - %s photo(s)", label, count)
  end
  return label
end

-- True if `query` (case-insensitive substring) appears in the album's id,
-- title, or rendered label. An empty query matches everything.
function M.matches_query(item, query)
  query = trim(query):lower()
  if query == "" then return true end
  local haystack = table.concat({
    tostring(item.id or ""),
    tostring(item.title or ""),
    M.label(item),
  }, " "):lower()
  return haystack:find(query, 1, true) ~= nil
end

-- Relevance score for `item` against an already-lowercased `query` (lower bins
-- sort first). Used by filter_matches so the most relevant albums surface within
-- a display cap on large libraries:
--   0  exact match on id / title / rendered label
--   1  title starts with the query (prefix)
--   2  a word inside the title starts with the query
--   3  some other substring hit (id, mid-word in title, or label)
-- Returns nil when the item does not match at all.
local function match_score(item, query)
  if query == "" then return 3 end
  local id = tostring(item.id or ""):lower()
  local title = tostring(item.title or ""):lower()
  local label = M.label(item):lower()
  if query == id or query == title or query == label then return 0 end
  if title:sub(1, #query) == query then return 1 end
  -- word-boundary prefix inside the title (after a space or punctuation)
  if (" " .. title):find("[%s%p]" .. query:gsub("(%W)", "%%%1"), 1, false) then return 2 end
  if id:find(query, 1, true) or title:find(query, 1, true) or label:find(query, 1, true) then
    return 3
  end
  return nil
end
M.match_score = match_score

-- Filter `cache` to the items matching `query`, ranked by relevance (see
-- match_score: exact > title-prefix > word-prefix > other substring), with the
-- cache's existing natural-title order as a stable tiebreak. An empty/whitespace
-- query returns the whole cache in its current order.
--
-- Returns (matches, total) where `total` is the full match count (before the
-- limit) and `matches` is capped to `limit` (no cap when limit is nil/<=0). The
-- ranking is what makes large libraries usable: the album a user is typing
-- toward stays visible within the cap instead of being hidden behind dozens of
-- earlier-in-the-alphabet substring hits.
function M.filter_matches(cache, query, limit)
  query = trim(query):lower()
  cache = cache or {}
  if query == "" then
    local all = {}
    for _, item in ipairs(cache) do all[#all + 1] = item end
    local total = #all
    if limit and limit > 0 and total > limit then
      local capped = {}
      for i = 1, limit do capped[i] = all[i] end
      return capped, total
    end
    return all, total
  end

  local scored = {}
  for index, item in ipairs(cache) do
    local score = match_score(item, query)
    if score then
      scored[#scored + 1] = { item = item, score = score, index = index }
    end
  end
  table.sort(scored, function(a, b)
    if a.score ~= b.score then return a.score < b.score end
    return a.index < b.index
  end)

  local matches, total = {}, #scored
  local n = (limit and limit > 0) and math.min(limit, total) or total
  for i = 1, n do matches[i] = scored[i].item end
  return matches, total
end

-- Resolve a free-text album reference against `cache`. Returns (item, kind):
--   "exact"     id/title/label matched exactly
--   "unique"    a single fuzzy match
-- or (nil, kind) where kind is "ambiguous" / "none" / "empty".
function M.find_match(cache, value)
  value = trim(value)
  if value == "" then return nil, "empty" end
  local lower = value:lower()
  local matches = {}
  for _, item in ipairs(cache or {}) do
    local id = tostring(item.id or "")
    local title = tostring(item.title or "")
    local label = M.label(item)
    if value == id or lower == title:lower() or lower == label:lower() then
      return item, "exact"
    end
    if M.matches_query(item, value) then matches[#matches + 1] = item end
  end
  if #matches == 1 then return matches[1], "unique" end
  if #matches > 1 then return nil, "ambiguous" end
  return nil, "none"
end

-- Like find_match but exact-only (no fuzzy fallback). Returns (item, "exact")
-- or (nil, "none"/"empty"). Used to detect a pre-existing album before create.
function M.find_exact(cache, value)
  value = trim(value)
  if value == "" then return nil, "empty" end
  local lower = value:lower()
  for _, item in ipairs(cache or {}) do
    local id = tostring(item.id or "")
    local title = tostring(item.title or "")
    local label = M.label(item)
    if value == id or lower == title:lower() or lower == label:lower() then
      return item, "exact"
    end
  end
  return nil, "none"
end

-- Order a list of set ids so ids present in `cache` come first in cache order
-- (a stable, human-meaningful order), with any remaining/unknown ids appended
-- in their original order. Deduplicates.
function M.ordered_set_ids(cache, set_ids)
  local wanted = {}
  for _, set_id in ipairs(set_ids or {}) do
    wanted[tostring(set_id)] = true
  end

  local ordered, used = {}, {}
  for _, item in ipairs(cache or {}) do
    local id = tostring(item and item.id or "")
    if wanted[id] and not used[id] then
      ordered[#ordered + 1] = id
      used[id] = true
    end
  end
  for _, set_id in ipairs(set_ids or {}) do
    set_id = tostring(set_id)
    if not used[set_id] then ordered[#ordered + 1] = set_id end
  end
  return ordered
end

-- Split a user-typed album field into individual album references. Parts are
-- comma-separated (mirrors the panel's multi-add), trimmed, with empties
-- dropped. Order is preserved; exact-duplicate raw parts (case-insensitive,
-- after trimming) are collapsed so "Trips, trips" only resolves once.
function M.split_album_input(value)
  local parts, seen = {}, {}
  if type(value) ~= "string" then return parts end
  for part in value:gmatch("[^,]+") do
    local t = trim(part)
    if t ~= "" then
      local key = t:lower()
      if not seen[key] then
        seen[key] = true
        parts[#parts + 1] = t
      end
    end
  end
  return parts
end

-- Resolve a comma-separated list of EXISTING-album references into photoset
-- targets. `resolver(part)` is supplied by the caller (it closes over the
-- album cache) and must behave like find_album_match: return (item, kind) where
-- item has .id / .title, or (nil, kind) where kind is "ambiguous"/"none"/etc.
--
-- Returns:
--   targets — list of { kind = "existing", photoset_id, title, match? },
--             deduped by photoset id (so the same album listed twice, or matched
--             by both name and id, is added once)
--   errors  — list of { query, reason } for parts that matched nothing or were
--             ambiguous
function M.resolve_existing(value, resolver)
  local targets, errors, seen_ids = {}, {}, {}
  for _, part in ipairs(M.split_album_input(value)) do
    local item, kind = resolver(part)
    if item and item.id and item.id ~= "" then
      local id = tostring(item.id)
      if not seen_ids[id] then
        seen_ids[id] = true
        targets[#targets + 1] = { kind = "existing", photoset_id = id, title = item.title or id, match = kind }
      end
    elseif part:match("^%d+$") then
      -- A bare numeric reference is treated as a manual photoset id even when it
      -- is not in the fetched cache (same fallback the single-album path used).
      if not seen_ids[part] then
        seen_ids[part] = true
        targets[#targets + 1] = { kind = "existing", photoset_id = part, title = part, match = "manual-id" }
      end
    else
      errors[#errors + 1] = {
        query = part,
        reason = (kind == "ambiguous")
          and "too many matches; type more or choose from matching albums"
          or "no matching album; refresh albums or check the name",
      }
    end
  end
  return targets, errors
end

-- Membership preview for a typed target-album field (issue #28).
--
-- As the user types/selects an album to ADD the current photo to, the panel
-- wants to say whether that photo is already in the named album(s) — before the
-- add attempt, instead of only discovering it from Flickr's error 3 ("already in
-- set"). This is the pure core: it resolves the typed value against the cache
-- (via the same `resolver(part)` shape add() uses) and compares each resolved
-- target id to `member_ids` (the photo's current set ids, e.g. state.get_sets).
--
-- `member_ids` may be a list or a set-like table; ids are compared as strings.
-- Returns a result table:
--   entries  — per-target { query, id?, title?, status }, in input order, where
--              status is "member" / "not_member" / "ambiguous" / "none"
--   members      — count of status == "member"
--   non_members  — count of status == "not_member"
--   unresolved   — count of "ambiguous" + "none"
--   total        — #entries
-- An empty/whitespace value returns an empty result (total == 0).
function M.target_membership_status(value, resolver, member_ids)
  local result = { entries = {}, members = 0, non_members = 0, unresolved = 0, total = 0 }

  -- Normalize member_ids into a string-keyed set, accepting either a list
  -- ({"100","200"}) or a set ({ ["100"] = true }).
  local member_set = {}
  if type(member_ids) == "table" then
    local is_list = member_ids[1] ~= nil
    if is_list then
      for _, id in ipairs(member_ids) do
        local s = tostring(id or "")
        if s ~= "" then member_set[s] = true end
      end
    else
      for id, present in pairs(member_ids) do
        if present then
          local s = tostring(id or "")
          if s ~= "" then member_set[s] = true end
        end
      end
    end
  end

  for _, part in ipairs(M.split_album_input(value)) do
    local m, k
    if resolver then m, k = resolver(part) end
    local entry
    if m and m.id and tostring(m.id) ~= "" then
      local id = tostring(m.id)
      local is_member = member_set[id] == true
      entry = {
        query = part,
        id = id,
        title = m.title or id,
        status = is_member and "member" or "not_member",
      }
      if is_member then result.members = result.members + 1
      else result.non_members = result.non_members + 1 end
    else
      local status = (k == "ambiguous") and "ambiguous" or "none"
      entry = { query = part, status = status }
      result.unresolved = result.unresolved + 1
    end
    result.entries[#result.entries + 1] = entry
  end

  result.total = #result.entries
  return result
end

-- Short human label for a target_membership_status result, for the panel's
-- live add-to-album indicator. `translate` is an optional gettext-style fn (it
-- receives plain English and may localize); when absent the English is used.
-- Returns "" for an empty result so the panel can blank the indicator.
function M.format_membership_status(result, translate)
  local t = translate or function(s) return s end
  if not result or (result.total or 0) == 0 then return "" end

  -- Single typed target: a precise, photo-centric sentence.
  if result.total == 1 then
    local e = result.entries[1]
    if e.status == "member" then
      return string.format(t("already in '%s'"), e.title or e.query)
    elseif e.status == "not_member" then
      return string.format(t("not yet in '%s'"), e.title or e.query)
    elseif e.status == "ambiguous" then
      return string.format(t("'%s': too many matching albums"), e.query)
    else
      return string.format(t("'%s': no matching album"), e.query)
    end
  end

  -- Multiple typed targets: a compact tally.
  local parts = {}
  if result.members > 0 then
    parts[#parts + 1] = string.format(t("%d already a member"), result.members)
  end
  if result.non_members > 0 then
    parts[#parts + 1] = string.format(t("%d to add"), result.non_members)
  end
  if result.unresolved > 0 then
    parts[#parts + 1] = string.format(t("%d unresolved"), result.unresolved)
  end
  return table.concat(parts, ", ")
end

-- Plan a "create album from the current selection" action (issue #30).
--
-- `entries` is the selection in display order, one per selected image:
--   { image = <opaque token>, photo_id = <string|nil> }
-- where photo_id is the image's stored Flickr id for the active account (nil/""
-- when the image is not published there). This is the pure core of the panel's
-- create-from-selection button: it decides which photos go into the new album
-- and in what order, without any darktable/REST state.
--
-- Returns a plan table:
--   members     — ordered, de-duplicated list of { image, photo_id } to put in
--                 the album (first occurrence of each photo_id wins). members[1]
--                 is the primary photo used by flickr.photosets.create; the rest
--                 are added with flickr.photosets.addPhoto.
--   unlinked    — count of selected images with no Flickr id (skipped)
--   duplicates  — count of entries dropped because their photo_id already
--                 appeared earlier in the selection
--   total       — #entries (the raw selection size)
-- The caller treats an empty `members` (every image unlinked) as "nothing to do".
function M.plan_selection_create(entries)
  local plan = { members = {}, unlinked = 0, duplicates = 0, total = 0 }
  local seen = {}
  for _, entry in ipairs(entries or {}) do
    plan.total = plan.total + 1
    local photo_id = trim(entry and entry.photo_id or "")
    if photo_id == "" then
      plan.unlinked = plan.unlinked + 1
    elseif seen[photo_id] then
      plan.duplicates = plan.duplicates + 1
    else
      seen[photo_id] = true
      plan.members[#plan.members + 1] = { image = entry.image, photo_id = photo_id }
    end
  end
  return plan
end

-- Build the ordered, comma-delimited photo-id list for
-- flickr.photosets.reorderPhotos (issue #31). `ids` is a list of photo ids in the
-- desired order; entries are stringified, trimmed, empties dropped, and duplicates
-- collapsed (first occurrence wins). Returns the comma-joined string ("" when no
-- usable id remains). Flickr keeps any photos NOT named here in their original
-- relative order, so a single-id result moves just that photo to the front.
function M.reorder_csv(ids)
  local out, seen = {}, {}
  for _, id in ipairs(ids or {}) do
    local s = trim(id)
    if s ~= "" and not seen[s] then
      seen[s] = true
      out[#out + 1] = s
    end
  end
  return table.concat(out, ",")
end

-- Resolve a comma-separated list of NEW-album titles into targets. Each title
-- is checked against the cache via `exact_resolver(title)` (find_album_exact):
-- if a set with that exact title/id already exists we reuse it (kind="existing",
-- duplicate_create=true) rather than creating a duplicate; otherwise it becomes
-- a kind="create" target. Deduped by title and by resolved id.
--
-- Always returns an empty errors list (every title is either reused or created);
-- the signature matches resolve_existing for a uniform caller.
function M.resolve_create(value, exact_resolver)
  local targets, errors, seen_titles, seen_ids = {}, {}, {}, {}
  for _, title in ipairs(M.split_album_input(value)) do
    local key = title:lower()
    if not seen_titles[key] then
      seen_titles[key] = true
      local match = exact_resolver and exact_resolver(title) or nil
      if match and match.id and match.id ~= "" then
        local id = tostring(match.id)
        if not seen_ids[id] then
          seen_ids[id] = true
          targets[#targets + 1] = {
            kind = "existing", photoset_id = id, title = match.title or title, duplicate_create = true,
          }
        end
      else
        targets[#targets + 1] = { kind = "create", title = title }
      end
    end
  end
  return targets, errors
end

return M
end

package.preload["dtrmflickr.groups"] = function(...)
-- groups.lua — pure group/pool input + submission-outcome helpers (issue #32).
--
-- Flickr "groups" expose shared community pools (flickr.groups.pools.*), distinct
-- from a user's own albums/photosets. The panel lets a user name SEVERAL groups
-- at once (comma-separated) so one action can submit a published photo to multiple
-- pools. Like albums.lua, this module is the pure core: it resolves the typed
-- group field against the fetched group cache and plans/classifies the submission,
-- with no darktable UI or REST state — so both the (future) export path and the
-- lighttable panel share one implementation and it is unit-testable.
--
-- Groups differ from albums in two ways this module accounts for:
--   * group ids are NSIDs ("34427465446@N01"), not plain integers, so the
--     "bare numeric is a manual id" album fallback is replaced with an NSID-shape
--     fallback;
--   * a pool add can partially succeed in ways an album add cannot — the pool may
--     be moderated (photo lands in a pending queue), or the add may be rejected
--     for a per-group / per-user limit, content rules, or a disabled pool. The
--     issue specifically asks to "handle per-group upload limits and report
--     submissions the group rejected", so classify_add_result + summarize_submission
--     turn the raw Flickr error codes into actionable outcomes.

local M = {}

local function trim(s)
  return (tostring(s or ""):gsub("^%s+", ""):gsub("%s+$", ""))
end

-- A group id is a Flickr NSID: digits, then "@N", then digits ("12345@N00").
local function looks_like_nsid(s)
  return tostring(s or ""):match("^%d+@N%d+$") ~= nil
end
M.looks_like_nsid = looks_like_nsid

-- Human-readable combobox/status label for one group: "Name (#nsid) - N photo(s)".
function M.label(item)
  local name = trim(item and item.name or "")
  local nsid = tostring(item and item.nsid or "")
  local count = item and item.photos and tostring(item.photos) or nil
  if name == "" then name = nsid end
  local label = string.format("%s (#%s)", name, nsid)
  if count and count ~= "" then
    return string.format("%s - %s photo(s)", label, count)
  end
  return label
end

-- True if `query` (case-insensitive substring) appears in the group's nsid,
-- name, or rendered label. An empty query matches everything.
function M.matches_query(item, query)
  query = trim(query):lower()
  if query == "" then return true end
  local haystack = table.concat({
    tostring(item.nsid or ""),
    tostring(item.name or ""),
    M.label(item),
  }, " "):lower()
  return haystack:find(query, 1, true) ~= nil
end

-- Relevance score for `item` against an already-lowercased `query` (lower bins
-- sort first). Mirrors albums.match_score:
--   0  exact match on nsid / name / rendered label
--   1  name starts with the query (prefix)
--   2  a word inside the name starts with the query
--   3  some other substring hit (nsid, mid-word in name, or label)
-- Returns nil when the item does not match at all.
local function match_score(item, query)
  if query == "" then return 3 end
  local nsid = tostring(item.nsid or ""):lower()
  local name = tostring(item.name or ""):lower()
  local label = M.label(item):lower()
  if query == nsid or query == name or query == label then return 0 end
  if name:sub(1, #query) == query then return 1 end
  if (" " .. name):find("[%s%p]" .. query:gsub("(%W)", "%%%1"), 1, false) then return 2 end
  if nsid:find(query, 1, true) or name:find(query, 1, true) or label:find(query, 1, true) then
    return 3
  end
  return nil
end
M.match_score = match_score

-- Filter `cache` to the items matching `query`, ranked by relevance, with the
-- cache's existing order as a stable tiebreak. Returns (matches, total) where
-- total is the full match count and matches is capped to `limit` (no cap when
-- limit is nil/<=0). Mirrors albums.filter_matches so large group lists stay
-- usable.
function M.filter_matches(cache, query, limit)
  query = trim(query):lower()
  cache = cache or {}
  if query == "" then
    local all = {}
    for _, item in ipairs(cache) do all[#all + 1] = item end
    local total = #all
    if limit and limit > 0 and total > limit then
      local capped = {}
      for i = 1, limit do capped[i] = all[i] end
      return capped, total
    end
    return all, total
  end

  local scored = {}
  for index, item in ipairs(cache) do
    local score = match_score(item, query)
    if score then
      scored[#scored + 1] = { item = item, score = score, index = index }
    end
  end
  table.sort(scored, function(a, b)
    if a.score ~= b.score then return a.score < b.score end
    return a.index < b.index
  end)

  local matches, total = {}, #scored
  local n = (limit and limit > 0) and math.min(limit, total) or total
  for i = 1, n do matches[i] = scored[i].item end
  return matches, total
end

-- Resolve a free-text group reference against `cache`. Returns (item, kind):
--   "exact"   nsid/name/label matched exactly
--   "unique"  a single fuzzy match
-- or (nil, kind) where kind is "ambiguous" / "none" / "empty".
function M.find_match(cache, value)
  value = trim(value)
  if value == "" then return nil, "empty" end
  local lower = value:lower()
  local matches = {}
  for _, item in ipairs(cache or {}) do
    local nsid = tostring(item.nsid or "")
    local name = tostring(item.name or "")
    local label = M.label(item)
    if value == nsid or lower == name:lower() or lower == label:lower() then
      return item, "exact"
    end
    if M.matches_query(item, value) then matches[#matches + 1] = item end
  end
  if #matches == 1 then return matches[1], "unique" end
  if #matches > 1 then return nil, "ambiguous" end
  return nil, "none"
end

-- Split a user-typed group field into individual references. Comma-separated,
-- trimmed, empties dropped, order preserved, exact-duplicate raw parts
-- (case-insensitive) collapsed. Mirrors albums.split_album_input.
function M.split_input(value)
  local parts, seen = {}, {}
  if type(value) ~= "string" then return parts end
  for part in value:gmatch("[^,]+") do
    local t = trim(part)
    if t ~= "" then
      local key = t:lower()
      if not seen[key] then
        seen[key] = true
        parts[#parts + 1] = t
      end
    end
  end
  return parts
end

-- Resolve a comma-separated list of group references into pool targets.
-- `resolver(part)` is supplied by the caller (it closes over the group cache)
-- and behaves like find_match: returns (item, kind) where item has .nsid/.name,
-- or (nil, kind) where kind is "ambiguous"/"none"/etc.
--
-- Returns:
--   targets — list of { kind = "existing", group_id, name, match? }, deduped by
--             group id (the same group by name and by NSID is added once)
--   errors  — list of { query, reason } for parts that matched nothing or were
--             ambiguous
function M.resolve_existing(value, resolver)
  local targets, errors, seen_ids = {}, {}, {}
  for _, part in ipairs(M.split_input(value)) do
    local item, kind = resolver(part)
    if item and item.nsid and item.nsid ~= "" then
      local id = tostring(item.nsid)
      if not seen_ids[id] then
        seen_ids[id] = true
        targets[#targets + 1] = { kind = "existing", group_id = id, name = item.name or id, match = kind }
      end
    elseif looks_like_nsid(part) then
      -- A bare NSID is treated as a manual group id even when it is not in the
      -- fetched cache (mirrors the album numeric-id fallback). The add will fail
      -- with Flickr error 2 if the user is not a member of that group.
      if not seen_ids[part] then
        seen_ids[part] = true
        targets[#targets + 1] = { kind = "existing", group_id = part, name = part, match = "manual-id" }
      end
    else
      errors[#errors + 1] = {
        query = part,
        reason = (kind == "ambiguous")
          and "too many matches; type more or choose from matching groups"
          or "no matching group; refresh groups or check the name",
      }
    end
  end
  return targets, errors
end

-- Extract the leading "(NN)" Flickr error code from an error string, as a number.
-- Errors surface as "Flickr REST failed (NN): msg" (see flickr_rest.parse_error).
local function error_code(err)
  return tonumber(tostring(err or ""):match("%((%d+)%)"))
end
M.error_code = error_code

-- Outcome categories for a single pool add. `success` means the photo is now in
-- the pool (or accepted into a moderation queue); `terminal` means retrying the
-- same add would not help (a limit/rule rejection or an auth/group error) — used
-- so the queue does not pointlessly re-attempt. `category` is a coarse bucket for
-- summaries.
--   added             ok                         success, no-op-safe
--   already_in_pool   code 3                     success (already a member)
--   pending           code 6 (moderated queue)   success-ish, awaiting approval
--   pending_already   code 7                      success-ish, already pending
--   rejected_max_pools code 4 (photo in max pools)        rejected, terminal
--   rejected_user_limit code 5 (user pool-photo limit)    rejected, terminal
--   rejected_pool_full code 10 (pool at upper limit)      rejected, terminal
--   rejected_content  code 8 (content not allowed)        rejected, terminal
--   rejected_disabled code 11 (posting disabled)          rejected, terminal
--   error_group       code 1/2 (photo/group not found)    error, terminal
--   error             anything else (transport, transient) not terminal
local ADD_OUTCOMES = {
  [3]  = { category = "already_in_pool",   success = true,  terminal = true },
  [6]  = { category = "pending",           success = true,  terminal = true },
  [7]  = { category = "pending_already",   success = true,  terminal = true },
  [4]  = { category = "rejected_max_pools", success = false, terminal = true },
  [5]  = { category = "rejected_user_limit", success = false, terminal = true },
  [10] = { category = "rejected_pool_full", success = false, terminal = true },
  [8]  = { category = "rejected_content",  success = false, terminal = true },
  [11] = { category = "rejected_disabled", success = false, terminal = true },
  [1]  = { category = "error_group",       success = false, terminal = true },
  [2]  = { category = "error_group",       success = false, terminal = true },
}

-- Classify the result of a single flickr.groups.pools.add call. `ok` is the
-- truthy first return of the REST call (or the wrapped __dtrmflickr_call); `err`
-- is its error string on failure. Returns an outcome table:
--   { category, success, terminal, code }
function M.classify_add_result(ok, err)
  if ok then
    return { category = "added", success = true, terminal = true, code = nil }
  end
  local code = error_code(err)
  local mapped = code and ADD_OUTCOMES[code]
  if mapped then
    return { category = mapped.category, success = mapped.success, terminal = mapped.terminal, code = code }
  end
  -- Unmapped failure: a transport error or a transient Flickr code (105/106).
  -- Not terminal — the shared queue may retry.
  return { category = "error", success = false, terminal = false, code = code }
end

