  if not block then return {} end
  local tags = {}
  for raw in block:gmatch('<tag[^>]-raw="(.-)"[^>]*>') do
    tags[#tags + 1] = xml_unescape(raw)
  end
  for raw in block:gmatch("<tag[^>]-raw='(.-)'[^>]*>") do
    tags[#tags + 1] = xml_unescape(raw)
  end
