  local lines = { STATUS_HEADLINE[status] or "Compared title/description with Flickr." }
  for _, f in ipairs(fields or {}) do
    lines[#lines + 1] = M.describe_field(f.label, f.local_value, f.remote)
  end
  return table.concat(lines, "\n")
end

return M
end

