  local info_mod = deps.account_info or account_info
  local rest_mod = deps.rest or rest

  local status_label = dt.new_widget("label") { label = "" }
  local verifier_label = dt.new_widget("label") { label = _("verifier code") }

  local verifier_entry = dt.new_widget("entry") {
    text = "",
    placeholder = _("9-digit code from Flickr"),
    tooltip = _("paste the code Flickr shows after you authorize"),
  }

  local pending = nil   -- { token, secret } held between 'log in' and 'complete login'
  local last_error = nil
  local complete_button
  local login_button
  local logout_button
  local info_button
  -- Multi-line account-identity block (issue #12): username/realname, photo
  -- count, profile + buddyicon (avatar) URLs, and the monthly-upload quota. Empty
  -- until the user clicks "refresh account info"; cleared on logout.
  local info_label = dt.new_widget("label") { label = "" }

  local function short_error(err)
    local s = tostring(err or ""):gsub("%s+", " ")
    if #s > 160 then s = s:sub(1, 157) .. "..." end
    return s
  end

  local function refresh_status()
    local acc = load_token()
    local logged_in = acc ~= nil
    local waiting_for_verifier = pending ~= nil and not logged_in
    -- A saved token that Flickr has since rejected (expired/revoked, code 98 or a
    -- 401 on a signed call). We keep the token so the account name still shows, but
    -- surface the re-login prompt loudly instead of pretending we are still logged
    -- in. Cleared on a fresh login (save_token) and on logout (clear_token).
    local revoked = logged_in and __dtrmflickr_auth_revoked == true

    status_label.label = revoked
        and string.format(_("status: login for %s expired or was revoked — log out and log in again"),
          acc.username or acc.nsid)
      or logged_in
      and (last_error
        and string.format(_("status: logged in as %s (not saved)"), acc.username or acc.nsid)
        or string.format(_("status: logged in as %s"), acc.username or acc.nsid))
      or last_error
        and string.format(_("status: login failed: %s"), last_error)
      or waiting_for_verifier
        and _("status: authorize in browser, paste the code, then 'complete login'")
        or  _("status: not logged in")

    verifier_label.visible = waiting_for_verifier
    verifier_entry.visible = waiting_for_verifier
    if complete_button then complete_button.visible = waiting_for_verifier end
    -- Offer the re-login button whenever there is no usable session: either no
    -- token at all, or a saved-but-revoked one the user must replace.
    if login_button then login_button.visible = (not logged_in) or revoked end
    if logout_button then logout_button.visible = logged_in end
    -- Account-identity refresh is only meaningful with a usable session.
    if info_button then info_button.visible = logged_in and not revoked end
    if info_label then info_label.visible = logged_in end
    if not logged_in then info_label.label = "" end
  end

  -- Called from the signed-call wrapper when a Flickr call fails. If the failure
  -- is an expired/revoked token (NOT an ambiguous permission error — see
  -- flickr_rest.AUTH_ERROR_CODES), mark the session as needing re-login, refresh
  -- the account status, and print a one-time prompt so the user notices even when
  -- the Lua-options pane is closed. Idempotent: re-flagging an already-revoked
  -- session does not re-spam the prompt. A successful login clears the flag.
  local function note_auth_failure(err)
    if not rest.is_token_expired(err) then return end
    -- Only meaningful while a token is actually saved; a call that fails with 98
    -- after the user already logged out needs no prompt.
    if not load_token() then return end
    local already = __dtrmflickr_auth_revoked == true
    __dtrmflickr_auth_revoked = true
    refresh_status()
    if not already then
      dt.print(_("Flickr rejected your saved login — it has expired or been revoked. "
        .. "Open Lua options > 'Flickr: account login' and log in again."))
      dt.print_log("[dtrmflickr] auth token expired/revoked: " .. tostring(err))
    end
  end

  -- "Request delete permission" toggle lives HERE, in the login area, rather than
  -- as a standalone bool preference — on purpose. darktable only commits a bool
  -- *preference* to config when the preferences dialog is closed: its value is
  -- written by the dialog "response" handler, not on toggle (see darktable
  -- src/lua/preferences.c response_callback_bool, wired in update_widget_bool). The
  -- login button is embedded in that same dialog, so a freshly-ticked preference
  -- checkbox is invisible to a login click in the same session, and the plugin
  -- would silently fall back to write-only scope (issue: delete login asked for
  -- write perms). A live check_button's `.value` is readable immediately, so
  -- reading it at click time is correct without closing/reopening preferences. The
  -- choice is mirrored into a hidden pref so it persists across restarts (written
  -- immediately on toggle, unlike the dialog checkbox; read back to seed `value`).
  local delete_perm_check = dt.new_widget("check_button") {
    label = _("request delete permission on next login"),
    tooltip = _("when on, the next Flickr login asks Flickr for permission to delete photos (required for 'delete from Flickr'). Leave off for normal use; tick this, then click 'log in to Flickr' — no need to close preferences first"),
    value = dt.preferences.read(PLUGIN, "request_delete_perm", "bool") == true,
  }
  -- check_button fires clicked_callback (changed_callback is invalid for the type
  -- and aborts script load).
  delete_perm_check.clicked_callback = function(widget)
    dt.preferences.write(PLUGIN, "request_delete_perm", "bool", widget.value == true)
    dt.print_log(string.format("[dtrmflickr] request_delete_perm toggled -> %s", tostring(widget.value == true)))
  end

  login_button = dt.new_widget("button") {
    label = _("log in to Flickr…"),
    clicked_callback = function()
      last_error = nil
      local key, secret = get_credentials()
      if not key then
        dt.print(_("Enter your Flickr API key and secret first."))
        return
      end
      dt.print(_("Requesting Flickr authorization…"))
      local tok, sec_or_err = auth.get_request_token(key, secret)
      if not tok then
        dt.print(_("Flickr request-token failed: ") .. tostring(sec_or_err))
        dt.print_log("[dtrmflickr] request_token error: " .. tostring(sec_or_err))
        return
      end
      pending = { token = tok, secret = sec_or_err }
      -- Default to write scope; only request delete scope when the user explicitly
      -- opted in (issue #19). Delete is never requested silently. Read the LIVE
      -- check_button value, not the preference: a preference toggled in the same
      -- still-open dialog has not been committed yet (see delete_perm_check above).
      local want_delete = delete_perm_check.value == true
      local url = auth.authorize_url(tok, auth.login_perms(want_delete))
      open_url(url)
      refresh_status()
      if want_delete then
        dt.print(_("Requesting DELETE permission — Flickr will ask to allow deleting your photos."))
      end
      dt.print(_("Opened Flickr in your browser. Paste the verifier code and click 'complete login'."))
      dt.print_log("[dtrmflickr] authorize URL (open manually if browser didn't): " .. url)
    end,
  }

  complete_button = dt.new_widget("button") {
    label = _("complete login"),
    clicked_callback = function()
      if not pending then dt.print(_("Click 'log in to Flickr' first.")); return end
      last_error = nil
      local code = (verifier_entry.text or ""):gsub("%D", "")
      if code == "" then dt.print(_("Enter the verifier code from Flickr.")); return end
      local key, secret = get_credentials()
      if not key then dt.print(_("Enter your Flickr API key and secret first.")); return end
      local acc, err = auth.get_access_token(key, secret, pending.token, pending.secret, code)
      if not acc then
        last_error = short_error(err)
        refresh_status()
        dt.print(_("Flickr access-token failed: ") .. last_error)
        dt.print_log("[dtrmflickr] access_token error: " .. tostring(err))
        return
      end
      local saved, save_err = save_token(acc)
      if not saved then
        last_error = save_err
        pending = nil
        verifier_entry.text = ""
        refresh_status()
        dt.print(_("Flickr authorized for this session, but login was not saved: ") .. tostring(save_err))
        dt.print_log("[dtrmflickr] password_save error: " .. tostring(save_err))
        return
      end
      pending = nil
      last_error = nil
      verifier_entry.text = ""
      refresh_status()
      dt.print(string.format(_("Logged in to Flickr as %s"), acc.username or acc.nsid))
      dt.print_log("[dtrmflickr] logged in, nsid=" .. tostring(acc.nsid))
    end,
  }

  -- Issue #12: fetch and render the logged-in account's identity + quota on
  -- demand. Kept behind a button (not auto-fetched at startup) so opening the
  -- preferences pane never makes two network calls unprompted; the panel shows
  -- the cheap saved username immediately and this enriches it when asked.
  info_button = dt.new_widget("button") {
    label = _("refresh account info"),
    tooltip = _("fetch your Flickr username, profile/avatar URL and monthly upload quota"),
    clicked_callback = function()
      local acc = load_token()
      if not acc then dt.print(_("Log in to Flickr first.")); return end
      local key, secret = get_credentials()
      if not key then dt.print(_("Enter your Flickr API key and secret first.")); return end
      local info, ierr = info_mod.fetch_identity(rest_mod, key, secret, acc)
      if not info then
        if __dtrmflickr_note_auth_failure then __dtrmflickr_note_auth_failure(ierr) end
        info_label.label = _("could not load account info: ") .. short_error(ierr)
        dt.print_log("[dtrmflickr] account info (getInfo) failed: " .. tostring(ierr))
        return
      end
      -- getUploadStatus is best-effort: a write-only / read-lacking token can fail
      -- it (code 99) without the identity being unavailable, so render identity
      -- regardless and only append the quota line when it resolves.
      local status, serr = info_mod.fetch_upload_status(rest_mod, key, secret, acc)
      if not status then
        if __dtrmflickr_note_auth_failure then __dtrmflickr_note_auth_failure(serr) end
        dt.print_log("[dtrmflickr] account upload status failed: " .. tostring(serr))
      end
      info_label.label = table.concat(info_mod.summary_lines(info, status), "\n")
      info_label.visible = true
    end,
  }

  logout_button = dt.new_widget("button") {
    label = _("log out"),
    clicked_callback = function()
      clear_token()
      pending = nil
      last_error = nil
      refresh_status()
      dt.print(_("Logged out of Flickr."))
    end,
  }

  local account_widget = dt.new_widget("box") {
    orientation = "vertical",
    status_label,
    delete_perm_check,
    login_button,
    verifier_label,
    verifier_entry,
    complete_button,
    logout_button,
    info_button,
    info_label,
  }

  return {
    widget = account_widget,
    refresh_status = refresh_status,
    note_auth_failure = note_auth_failure,
  }
end

return M
end

package.preload["dtrmflickr.dtrmflickr"] = function(...)
--[[ dtrmflickr — Flickr export/storage for darktable

  Copyright (C) 2026

  darktable is free software: you can redistribute it and/or modify it under the
  terms of the GNU General Public License as published by the Free Software
  Foundation, either version 3 of the License, or (at your option) any later
  version.

  darktable is distributed in the hope that it will be useful, but WITHOUT ANY
  WARRANTY; without even the implied warranty of MERCHANTABILITY or FITNESS FOR A
  PARTICULAR PURPOSE.  See the GNU General Public License for more details.

  ----------------------------------------------------------------------------
  Build status:
    STEP 1 — storage skeleton (register_storage + widget + callbacks).  DONE.
    STEP 2 — OAuth 1.0a login + token persistence.                      DONE.
    STEP 3 — single-image upload.                                       DONE.
    STEP 4 — state tags for returned Flickr photo IDs.                  DONE.
    STEP 5 — albums/photosets + license updates.                        DONE.
    STEP 6+ — metadata mapping, publish/sync, resilience.               TODO.

  UI layout:
    * Lua Options — Flickr app credentials, account login, and saved defaults.
    * Export-panel storage widget — per-export choices.
    * Lighttable panel — selected published photo management.

  Upload/state are live-verified; albums/license need live verification.
]]

local dt   = require "darktable"
local http = require "dtrmflickr.http"
local upload = require "dtrmflickr.flickr_upload"
local rest = require "dtrmflickr.flickr_rest"
local state = require "dtrmflickr.state"
local metadata = require "dtrmflickr.metadata"
local claim = require "dtrmflickr.claim"
local settings = require "dtrmflickr.settings"
local rules = require "dtrmflickr.rules"
local report = require "dtrmflickr.report"
local tag_reconcile = require "dtrmflickr.tag_reconcile"
local people = require "dtrmflickr.people"
local albums = require "dtrmflickr.albums"
local groups = require "dtrmflickr.groups"  -- group/pool submission helpers (#32)
local widgets = require "dtrmflickr.widgets"
local remote_pull = require "dtrmflickr.remote_pull"  -- pull remote edits back (#20)
local panel_helpers = require "dtrmflickr.panel_helpers"  -- pure panel parse/index/label helpers (#46)
local account_ui = require "dtrmflickr.account_ui"  -- account-login widget + session state (#47)
local queue_panel = require "dtrmflickr.queue_panel"  -- pure live job-lifecycle grid formatter (#56)
local batch_apply = require "dtrmflickr.batch_apply"  -- pure multi-select settings-apply planner/formatter (#49)

local PLUGIN     <const> = "dtrmflickr"            -- reserved namespace (prefs, password, tags)
local STORAGE    <const> = "dtrmflickr"            -- register_storage plugin_name
local PANEL      <const> = "dtrmflickr_panel"      -- lighttable management panel
local HUMAN      <const> = "Flickr"                -- storage display name

local function _(msgid) return dt.gettext.gettext(msgid) end

----------------------------------------------------------------------
-- Transport capability (step-0 spike): curl-primary, LuaSec optional.
----------------------------------------------------------------------
local function detect_transport()
  if http.quiet_rest_available and http.quiet_rest_available() then
    local detail = nil
    if http.native_status then
      local _ok
      _ok, detail = http.native_status()
    end
    return "native", _("quiet in-process REST transport detected") .. (detail and (": " .. tostring(detail)) or "")
  end
  if http.native_status then
    local _ok, detail = http.native_status()
    dt.print_log("[dtrmflickr] native HTTP unavailable: " .. tostring(detail))
  end
  return "curl", _("will use curl or the Windows HTTP helper for HTTPS")
end
local TRANSPORT, TRANSPORT_MSG = detect_transport()

----------------------------------------------------------------------
-- Preferences / token persistence.
--   consumer key+secret -> registered prefs (app identity, edited in Lua Options)
--   access token+secret -> darktable.password keyed (PLUGIN, nsid)  [secret]
--   active account nsid + display name -> unregistered prefs        [internal]
----------------------------------------------------------------------
local TOKEN_SEP <const> = "\t"   -- neither char appears in Flickr tokens
local session_account = nil
local EMPTY_FILTER_PREF <const> = "<none>"
local FLICKR_TAG_LIMIT <const> = 75
local clear_album_cache
local effective_metadata_fingerprints
local store_metadata_fingerprints
local panel_sets
-- Passive lifecycle observer: collapses the queue's event stream into one
-- explicit per-job state (queued/running/waiting/retrying/done/failed) for a
-- future live panel and for account-bound resume (issue #36). A global (not a
-- main-chunk local) so it costs nothing against the local-variable limit. The
-- queue stays the scheduler; this only watches.
__dtrmflickr_jobs = require("dtrmflickr.queue_jobs").new_tracker()

__dtrmflickr_queue = require("dtrmflickr.queue").new {
  on_event = function(payload)
    __dtrmflickr_jobs:observe(payload)
    -- LIVE durable-resume wiring (issue #55). Persist the resumable set on async
    -- pump lifecycle transitions; clear it on a clean drain. Gated on
    -- `is_pumping` inside the store so the synchronous Queue:call path (which
    -- drains to terminal within one call and has nothing to recover) never
    -- touches the preference. A global like __dtrmflickr_jobs so it costs no
    -- main-chunk local.
    if __dtrmflickr_resume then __dtrmflickr_resume.on_event() end
    -- Repaint the live job-lifecycle grid on every async tick (issue #56) so the
    -- panel shows each job moving through queued/running/waiting/retrying/done as
    -- the async queue drains. Cheap (a bounded snapshot render) and guarded for
    -- module-load ordering — the panel's refresher is assigned later in the chunk.
    if panel_sets and panel_sets.refresh_queue_jobs then panel_sets.refresh_queue_jobs() end
  end,
  sleep_ms = function(ms)
    -- dt.control.sleep takes an int delay in MILLISECONDS (see
    -- docs/lua-api-manual/darktable/darktable.control.md). The queue already
    -- hands us milliseconds, so pass them straight through — do NOT divide by
    -- 1000 (that turned a 5000 ms rate-limit backoff into a 5 ms no-op and
    -- defeated pacing/retry/throttle waits entirely).
    if dt.control and dt.control.sleep then dt.control.sleep(math.floor(tonumber(ms) or 0)) end
  end,
  -- Async pump wiring (issue #54). These let the queue defer work across
  -- darktable callbacks: `spawn` runs the pump loop off the UI thread,
  -- `pump_yield` releases the control thread between ticks, and `should_stop`
  -- aborts the loop when darktable is shutting down (leaving any remaining jobs
  -- pending for the durable resume store to replay — issues #55/#57). No
  -- production caller submits async work yet (the export path stays synchronous
  -- via Queue:call); this completes the darktable integration surface the
  -- resumable-upload children build on.
  spawn = function(fn)
    if dt.control and dt.control.dispatch then dt.control.dispatch(fn) else fn() end
  end,
  pump_yield = function(ms)
    if dt.control and dt.control.sleep then dt.control.sleep(math.floor(tonumber(ms) or 0)) end
  end,
  should_stop = function()
    return dt.control and dt.control.ending == true
  end,
  on_wait = function(ms, why, method, attempt)
    if why == "rate-limit" then
      dt.print(string.format(_("Flickr: waiting %.1fs due to API limit before retrying %s"),
        (tonumber(ms) or 0) / 1000, tostring(method or "request")))
    elseif why == "transient" then
      dt.print_log(string.format("[dtrmflickr] retrying %s after %.1fs transient wait (attempt %d)",
        tostring(method or "request"), (tonumber(ms) or 0) / 1000, tonumber(attempt) or 1))
    end
  end,
  default_max_attempts = 3,
  retry_base_ms = 1000,
  rate_limit_base_ms = 5000,
  retry_max_ms = 30000,
  method_pace_ms = {
    ["flickr.photos.getInfo"] = 250,
    ["flickr.photos.getPerms"] = 250,
    ["flickr.photos.search"] = 250,
    ["flickr.photosets.getList"] = 250,
  },
}

-- LIVE durable resume store (issue #55). Wraps dt.preferences as the {read,write}
-- backend and persists the tracker's resumable set across the async pump's
-- lifecycle. The blob lives in an UNREGISTERED internal preference (key
-- "queue_resume", "string"), exactly like active_nsid/active_username above:
-- registering it would surface a raw serialized blob as a user-editable string in
-- the Lua Options dialog, which is wrong for internal state. A global so it costs
-- no main-chunk local. Persistence is gated on the queue actually pumping so the
-- synchronous export path never churns the preference.
__dtrmflickr_resume = require("dtrmflickr.queue_resume").new {
  queue_jobs = require("dtrmflickr.queue_jobs"),
  tracker = __dtrmflickr_jobs,
  backend = require("dtrmflickr.queue_jobs").make_pref_backend(dt.preferences, PLUGIN, "queue_resume"),
  is_pumping = function() return __dtrmflickr_queue:pumping() end,
  log = function(msg) dt.print_log(msg) end,
}

function __dtrmflickr_call(method, fn, opts)
  local results = table.pack(__dtrmflickr_queue:call(method, fn, opts))
  -- Detect an expired/revoked OAuth token (the 401-equivalent) on any signed
  -- Flickr call and flip the session into a "needs re-login" state, instead of
  -- letting the operation fail silently mid-batch with a generic error (issue
  -- #1). Helper convention: a non-nil first return is success; a failure is
  -- (nil, err), so the error message lives in slot 2 when slot 1 is nil. The
  -- queue already refuses to retry these (codes 98/99/401 are not transient).
  -- __dtrmflickr_note_auth_failure is a global assigned once the account UI is
  -- built; guard for module-load ordering even though calls only run afterwards.
  if results[1] == nil and results.n >= 2 and __dtrmflickr_note_auth_failure then
    __dtrmflickr_note_auth_failure(results[2])
  end
  if panel_sets and panel_sets.refresh_queue_status then panel_sets.refresh_queue_status() end
  return table.unpack(results, 1, results.n)
end

local function keep_label_pref(widget)
  -- Label-only Lua preference rows are explanatory text; there is no user value to save.
  return widget
end

local function json_escape(s)
  return tostring(s or ""):gsub('[%z\1-\31\\"]', function(c)
    if c == "\\" then return "\\\\" end
    if c == '"' then return '\\"' end
    return string.format("\\u%04x", c:byte())
  end)
end

local function json_object(fields)
  return string.format('{"server":"%s","username":"%s","password":"%s"}',
    json_escape(fields.server), json_escape(fields.username), json_escape(fields.password))
end

local function json_unescape(s)
  s = tostring(s or ""):gsub("\\u(%x%x%x%x)", function(h)
    local n = tonumber(h, 16)
    if n and n < 128 then return string.char(n) end
    return ""
  end)
  return s
    :gsub("\\t", "\t")
    :gsub("\\r", "\r")
    :gsub("\\n", "\n")
    :gsub('\\"', '"')
    :gsub("\\\\", "\\")
end

local function json_string_field(body, name)
  -- Good enough for the JSON generated by darktable.password backends:
  -- flat object, string fields, escaped control characters.
  local raw = tostring(body or ""):match('"' .. name .. '"%s*:%s*"(.-)"')
  return raw and json_unescape(raw) or nil
end

local function pack_token(token, secret)
  local payload = token .. TOKEN_SEP .. secret
  -- darktable's Windows credentials backend currently stores roughly half of
  -- the password byte string. Keep the real payload in the first half and add
  -- ignorable padding after a second separator.
  return payload .. TOKEN_SEP .. string.rep("x", #payload + 8)
end

local function unpack_token(packed)
  return tostring(packed or ""):match("^(.-)" .. TOKEN_SEP .. "([^" .. TOKEN_SEP .. "]+)")
end

local function register_keyword_rule_preferences_reverse(prefix, label, values)
  for i = #values, 1, -1 do
    local item = values[i]
    dt.preferences.register(PLUGIN, prefix .. "_" .. item.key, "string",
      string.format(_("Flickr: keyword -> %s %s"), label, item.pref),
      string.format(_("apply %s %s to Flickr when any listed keyword matches"), label, item.pref),
      EMPTY_FILTER_PREF)
  end
end

local keyword_rules_help_widget = dt.new_widget("label") {
  label = _("enter one keyword, or comma-separated keywords\nskip-upload keywords leave matching images local\nconflicts are shown during export\nprivacy/safety use the safest match\ncontent/license use the first match"),
}

local settings_help_widget = dt.new_widget("label") {
  label = _("Lua options are credentials and automation rules\nExport > Flickr controls and saves upload defaults\nThe lighttable Flickr panel edits selected published photo(s)"),
}

local function save_token(acc)
  local active_nsid = dt.preferences.read(PLUGIN, "active_nsid", "string")
  if (session_account and session_account.nsid ~= acc.nsid)
    or (active_nsid and active_nsid ~= "" and active_nsid ~= acc.nsid) then
    clear_album_cache()
  end
  local packed = pack_token(acc.token, acc.secret)
  local ok = dt.password.save(PLUGIN, acc.nsid, json_object {
    server = acc.nsid,
    username = acc.nsid,
    password = packed,
  })
  session_account = acc
  -- A fresh access token clears any prior expired/revoked flag (issue #1).
  __dtrmflickr_auth_revoked = false
  -- Account-binding contract (issue #36 / design-notes): switching accounts
  -- invalidates any non-terminal jobs owned by the previous account so a
  -- deferred/persisted job can never run against the new account's token.
  if __dtrmflickr_jobs then __dtrmflickr_jobs:cancel_for_account_change(acc.nsid) end
  dt.preferences.write(PLUGIN, "active_nsid", "string", acc.nsid)
  dt.preferences.write(PLUGIN, "active_username", "string", acc.username or acc.nsid)
  if not ok then return nil, _("darktable password storage refused the OAuth token; login is session-only") end
  return true
end

local function load_token()
  local nsid = dt.preferences.read(PLUGIN, "active_nsid", "string")
  if not nsid or nsid == "" then return nil end
  if session_account and session_account.nsid == nsid then return session_account end
  local packed = dt.password.get(PLUGIN, nsid)
  if not packed or packed == "" then return nil end
  packed = json_string_field(packed, "password")
  if not packed or packed == "" then return nil end
  local token, secret = unpack_token(packed)
  if not token then return nil end
  return {
    nsid = nsid, token = token, secret = secret,
    username = dt.preferences.read(PLUGIN, "active_username", "string"),
  }
end

local function clear_token()
  local nsid = dt.preferences.read(PLUGIN, "active_nsid", "string")
  if nsid and nsid ~= "" then
    dt.password.save(PLUGIN, nsid, json_object { server = nsid, username = nsid, password = "" })
  end  -- no delete API; blank it
  session_account = nil
  -- Clearing the token clears any stale "login revoked" flag: there is no longer
  -- a saved login the warning could apply to.
  __dtrmflickr_auth_revoked = false
  clear_album_cache()
  -- Logout invalidates every non-terminal job (no active token to run them).
  if __dtrmflickr_jobs then __dtrmflickr_jobs:cancel_for_account_change(nil) end
  dt.preferences.write(PLUGIN, "active_nsid", "string", "")
  dt.preferences.write(PLUGIN, "active_username", "string", "")
end

----------------------------------------------------------------------
-- Open a URL in the default browser (authorize step). Use a SINGLE quoted
-- argument — dt.control.execute on Windows mishandles multiple quoted items.
----------------------------------------------------------------------
local function open_url(url)
  local osn = dt.configuration.running_os
  local cmd
  if osn == "windows" then     cmd = 'explorer "' .. url .. '"'
  elseif osn == "macos" then   cmd = 'open "' .. url .. '"'
  else                         cmd = 'xdg-open "' .. url .. '"' end
  dt.control.execute(cmd)
end

----------------------------------------------------------------------
-- Account state and widgets.
----------------------------------------------------------------------
local function get_credentials()
  local key = dt.preferences.read(PLUGIN, "api_key", "string")
  local secret = dt.preferences.read(PLUGIN, "api_secret", "string")
  if not key or key == "" or not secret or secret == "" then return nil end
  return key, secret
end

local DEFAULT_SETTING_PREF_TYPE <const> = "string"

local function read_stored_default_pref(name, default_value)
  local value = dt.preferences.read(PLUGIN, name, DEFAULT_SETTING_PREF_TYPE)
    or dt.preferences.read(PLUGIN, name, "enum")
    or dt.preferences.read(PLUGIN, name, "lua")
  if value == nil or value == "" then
    dt.preferences.write(PLUGIN, name, DEFAULT_SETTING_PREF_TYPE, default_value)
    return default_value
  end
  dt.preferences.write(PLUGIN, name, DEFAULT_SETTING_PREF_TYPE, value)
  return value
end

local function read_default_pref(name, default_value)
  local spec = settings.default_setting_specs_by_name[name]
  if not spec then return read_stored_default_pref(name, default_value) end

  local index = settings.index_from_pref(spec.values, read_stored_default_pref(name, default_value), 1)
  local selected = spec.values[index]
  dt.preferences.write(PLUGIN, name, DEFAULT_SETTING_PREF_TYPE, selected.pref)
  return selected.pref
end

local sync_widgets = {}

local function read_sync_pref(name)
  local value = dt.preferences.read(PLUGIN, "sync_" .. name, "bool")
  if value == nil then return settings.sync_field_defaults[name] == true end
  return value == true
end

local function write_sync_pref(name, value)
  dt.preferences.write(PLUGIN, "sync_" .. name, "bool", value == true)
end

local function current_sync_fields()
  local fields = {}
  for name in pairs(settings.sync_field_defaults) do
    local widget = sync_widgets[name]
    fields[name] = widget and widget.value == true or read_sync_pref(name)
    write_sync_pref(name, fields[name])
  end
  return fields
end

local function master_sync_fields()
  local fields = {}
  for name in pairs(settings.sync_field_defaults) do
    fields[name] = read_sync_pref(name)
  end
  return fields
end

