  label = _("album action"),
  tooltip = _("choose whether to skip albums, add to an existing album, or create a new album"),
  selected = 1,
  _("no album"), _("existing album"), _("create new album"),
}
local album_cache = {}
local album_cache_nsid = nil
local filtering_albums = false
local function trim(value)
  return tostring(value or ""):match("^%s*(.-)%s*$")
end

-- Pure album-cache helpers now live in albums.lua (issue #45): albums.sort,
-- albums.label, albums.matches_query, albums.find_match, albums.find_exact,
-- albums.ordered_set_ids. The main module keeps the album_cache table and passes
-- it in. The closures below adapt the cache-taking API to the old single-arg
-- call shape used by panel/export code (and the __test hooks).

local function album_input_value()
  local typed = trim(album_entry.text or "")
  if typed ~= "" then return typed end
  return trim(album_widget.value or "")
end

local ALBUM_MATCH_LIMIT = 25

-- Empty a combobox's entries. The safe-clear logic lives in widgets.lua (it has
-- to dodge darktable's append/invalid-index __newindex traps); see the comment
-- there. Kept as a thin local alias so the many call sites stay terse.
local clear_widget_items = widgets.clear_combobox

local function update_album_match_widget(widget, query)
  clear_widget_items(widget)
  query = trim(query)
  if query == "" then
    widget.selected = 0
    widget.value = nil
    return #album_cache, 0
  end
  -- Rank matches by relevance (exact > title-prefix > word-prefix > other
  -- substring) and cap to ALBUM_MATCH_LIMIT, so on large libraries the album the
  -- user is typing toward stays within the shown set instead of being hidden
  -- behind dozens of earlier-in-the-alphabet substring hits (issue #29).
  local matches, count = albums.filter_matches(album_cache, query, ALBUM_MATCH_LIMIT)
  local shown = 0
  for _, item in ipairs(matches) do
    shown = shown + 1
    widget[shown] = albums.label(item)
  end
  widget.selected = 0
  widget.value = nil
  return count, shown
end

local function update_album_choices(query)
  filtering_albums = true
  local count, shown = update_album_match_widget(album_widget, query)
  filtering_albums = false
  return count, shown
end


local function refresh_album_matches()
  local query = album_input_value()
  if query == "" and album_entry.text == "" then query = "" end
  if filtering_albums then return end
  if #album_cache == 0 then
    if query ~= "" then album_status_label.label = _("refresh albums to search") end
    return
  end
  local count, shown = update_album_choices(query)
  if query == "" then
    album_status_label.label = string.format(_("%d album(s) loaded; type to search"), #album_cache)
  elseif count == 1 then
    album_status_label.label = _("1 matching album")
  elseif count > shown then
    album_status_label.label = string.format(_("%d matching album(s); showing first %d"), count, shown)
  else
    album_status_label.label = string.format(_("%d matching album(s)"), count)
  end
end

album_widget.changed_callback = function(widget)
  if filtering_albums then return end
  local selected = trim(widget.value or "")
  if selected ~= "" then album_entry.text = selected end
end

local function album_cache_matches(account)
  local nsid = type(account) == "table" and account.nsid or account
  nsid = tostring(nsid or "")
  return nsid == "" or album_cache_nsid == nil or album_cache_nsid == nsid
end

clear_album_cache = function()
  album_cache = {}
  album_cache_nsid = nil
  update_album_choices(album_input_value())
end

local function set_album_cache(items, account)
  album_cache = items or {}
  album_cache_nsid = account ~= nil and (type(account) == "table" and account.nsid or account) or nil
  update_album_choices(album_input_value())
end

local function merge_album_cache(items, account)
  items = items or {}
  if not album_cache_matches(account) then clear_album_cache() end
  if #album_cache == 0 then
    set_album_cache(items, account)
    return
  end
  if account ~= nil then
    album_cache_nsid = type(account) == "table" and account.nsid or account
  end

  local positions = {}
  for i, item in ipairs(album_cache) do
    local id = tostring(item and item.id or "")
    if id ~= "" then positions[id] = i end
  end
  for _, item in ipairs(items) do
    local id = tostring(item and item.id or "")
    if id ~= "" then
      local existing_index = positions[id]
      if existing_index then
        album_cache[existing_index] = item
      else
        album_cache[#album_cache + 1] = item
        positions[id] = #album_cache
      end
    end
  end
  update_album_choices(album_input_value())
end

local function refresh_album_list()
  local account = load_token()
  local api_key, api_secret = get_credentials()
  if not account then
    album_status_label.label = _("log in to refresh albums")
    dt.print(_("Flickr: log in before refreshing albums."))
    return nil, "not logged in to Flickr"
  end
  if not api_key or not api_secret then
    album_status_label.label = _("missing API credentials")
    dt.print(_("Flickr: missing API key/secret."))
    return nil, "missing Flickr API key/secret"
  end

  local sets, err = __dtrmflickr_call("flickr.photosets.getList", function()
    return rest.photosets_get_list(api_key, api_secret, account)
  end)
  if not sets then
    album_status_label.label = _("album refresh failed")
    dt.print(string.format(_("Flickr: album refresh failed: %s"), tostring(err)))
    dt.print_log(string.format("[dtrmflickr] album refresh failed: %s", tostring(err)))
    return nil, err
  end
  set_album_cache(sets, account)
  album_status_label.label = string.format(_("%d album(s) loaded"), #sets)
  dt.print(string.format(_("Flickr: loaded %d album(s)"), #sets))
  return sets
end

local function refresh_album_cache_for_export(api_key, api_secret, account, opts)
  if not account or not api_key or not api_secret then return nil, "missing account or API credentials" end
  opts = opts or {}
  if opts.use_cache and #album_cache > 0 and album_cache_matches(account) then
    album_status_label.label = string.format(_("%d album(s) loaded"), #album_cache)
    return album_cache
  end
  if not album_cache_matches(account) then clear_album_cache() end
  local sets, err = __dtrmflickr_call("flickr.photosets.getList", function()
    return rest.photosets_get_list(api_key, api_secret, account)
  end)
  if not sets then return nil, err end
  set_album_cache(sets, account)
  album_status_label.label = string.format(_("%d album(s) loaded"), #sets)
  return sets
end

