  return lib and lib.visible ~= false and lib.expanded ~= false and lib.on_screen ~= false
end

local function join_values(values)
  if not values or #values == 0 then return "" end
  return table.concat(values, ", ")
end

-- Pure formatter for the panel's two queue-status lines. Kept separate from the
-- widget update so it can be unit-tested without darktable widgets. It surfaces
-- the throttle/wait information the queue already tracks but the panel used to
-- discard: the cumulative `rate_limited` count (so the user sees when Flickr is
-- throttling the batch, not just the ok/failed totals), the cumulative
-- `waited_ms` across all waits (so a slow batch reads as "Flickr is pacing us"
-- rather than "stuck"), and the last job's `waited_ms` (so a job that visibly
-- paused on backoff is distinguishable from one that ran straight through).
-- Returns (label, detail).
local function format_queue_status(summary, recent)
  if not summary then return "", "" end
  local label = string.format(
    _("queue: %d ok, %d failed, %d retried, %d pending"),
    summary.succeeded or 0, summary.failed or 0, summary.retried or 0, summary.pending or 0)
  if (tonumber(summary.rate_limited) or 0) > 0 then
    label = label .. string.format(_(" - throttled %dx"), summary.rate_limited)
  end
  -- Surface the cumulative time the queue has spent sleeping on pacing/backoff
  -- (the queue tracks `waited_ms` across all waits but the panel used to discard
  -- it). On a large throttled batch this tells the user how much wall-clock the
  -- backoff has actually cost, distinguishing "slow because Flickr is pacing us"
  -- from "stuck". Only shown once there has been a measurable wait.
  if (tonumber(summary.waited_ms) or 0) >= 100 then
    label = label .. string.format(_(" - waited %.1fs total"), summary.waited_ms / 1000)
  end
  local detail = ""
  local last = recent and recent[#recent] or nil
  if last then
    local name = last.label or last.method or _("request")
    local attempts = tonumber(last.attempts) or 0
    detail = string.format(_("last queue: %s %s"), tostring(name), tostring(last.status or ""))
    if attempts > 1 then
      detail = detail .. string.format(_(" after %d attempts"), attempts)
    end
    local waited = tonumber(last.waited_ms) or 0
    if waited > 0 then
      detail = detail .. string.format(_(" (waited %.1fs)"), waited / 1000)
    end
    if last.error then detail = detail .. ": " .. tostring(last.error) end
  end
  return label, detail
end

function panel_sets.refresh_queue_status()
  local summary = __dtrmflickr_queue and __dtrmflickr_queue:summary() or nil
  local recent = (summary and __dtrmflickr_queue.recent_results)
    and __dtrmflickr_queue:recent_results() or nil
  local label, detail = format_queue_status(summary, recent)
  panel_sets.queue_label.label = label
  if panel_sets.queue_detail_label then panel_sets.queue_detail_label.label = detail end
  panel_sets.refresh_queue_jobs()
end

-- Repaint the live job-lifecycle grid (issue #56) from the queue_jobs tracker
-- snapshot. Called both after a synchronous queue call and on every async
-- lifecycle event (see the queue's on_event), so a job's state, attempt count and
-- error update live as the async queue ticks. Bounded + stably ordered by
-- queue_panel.build; unused pool rows are blanked. Also surfaces the resume
-- planner's `uncertain` records (a non-idempotent job interrupted after it may
-- have reached Flickr) so the user can decide on them (#36/#57 own the action).
function panel_sets.refresh_queue_jobs()
  local rows = panel_sets.queue_jobs_rows
  if not rows then return end
  local snapshot = __dtrmflickr_jobs and __dtrmflickr_jobs:snapshot() or {}
  local view = queue_panel.build(snapshot,
    { limit = panel_sets.queue_jobs_limit, translate = _ })
  panel_sets.queue_jobs_header.label = view.summary or ""
  for i = 1, #rows do
    rows[i].label = view.lines[i] or ""
  end
  -- Uncertain resume records the start-up classifier parked for a user decision.
  local plan = __dtrmflickr_resume and __dtrmflickr_resume.plan or nil
  local uncertain = plan and plan.uncertain or nil
  panel_sets.queue_uncertain_label.label = queue_panel.uncertain_summary(uncertain, _)
end

function panel_sets.clear_choices()
  clear_widget_items(panel_sets.match_widget)
end

function panel_sets.clear_current_choices()
  panel_sets.current_ids = {}
  clear_widget_items(panel_sets.current_widget)  -- not a cached for-loop; see clear_widget_items
  panel_sets.current_widget[1] = _("Select one of this photo's albums")
  panel_sets.current_widget.selected = 1
end

function panel_sets.update_current_choices(image, account_nsid)
  panel_sets.clear_current_choices()
  if image and account_nsid then
    for _, set_id in ipairs(albums.ordered_set_ids(album_cache, state.get_sets(image, account_nsid))) do
      panel_sets.current_ids[#panel_sets.current_ids + 1] = set_id
      panel_sets.current_widget[#panel_sets.current_widget + 1] = panel_sets.title_for_id(set_id)
    end
  end
  -- Memberships (or the loaded photo) just changed — keep the "already in target
  -- album?" indicator (issue #28) in sync. update_membership_indicator blanks
  -- itself when no photo is loaded, so this also clears a stale indicator on
  -- deselect.
  if panel_sets.update_membership_indicator then panel_sets.update_membership_indicator() end
end

function panel_sets.selected_current_id()
  local index = panel_sets.current_widget.selected or 0
  if index <= 1 then return nil end
  return panel_sets.current_ids[index - 1]
end

function panel_sets.input_value()
  local typed = trim(panel_sets.entry.text or "")
  if typed ~= "" then return typed end
  return trim(panel_sets.match_widget.value or "")
end

function panel_sets.update_choices(query)
  panel_sets.filtering = true
  local count, shown = update_album_match_widget(panel_sets.match_widget, query)
  panel_sets.filtering = false
  return count, shown
end

-- Refresh the "already in this target album?" indicator (issue #28) from the
-- current add-to-album input and the loaded photo's recorded memberships. Blanks
-- the line when nothing is typed, no photo is loaded, or no albums are cached
-- (resolve() can't match without a cache, so an indicator would be misleading).
function panel_sets.update_membership_indicator()
  if not panel_sets.membership_label then return end
  local image = panel_current.image
  local acc = panel_current.account
  local value = panel_sets.input_value()
  if value == "" or not image or not acc or #album_cache == 0 then
    panel_sets.membership_label.label = ""
    return
  end
  local member_ids = state.get_sets(image, acc.nsid)
  local result = albums.target_membership_status(value, panel_sets.resolve, member_ids)
  panel_sets.membership_label.label = albums.format_membership_status(result, _)
end

function panel_sets.title_for_id(set_id)
  set_id = tostring(set_id or "")
  for _, item in ipairs(album_cache) do
    if tostring(item.id or "") == set_id then return albums.label(item) end
  end
  return set_id
end

function panel_sets.format_memberships(sets)
  if not sets or #sets == 0 then return _("in albums: none") end
  local labels = {}
  for _, set_id in ipairs(albums.ordered_set_ids(album_cache, sets)) do labels[#labels + 1] = panel_sets.title_for_id(set_id) end
  return _("in albums:") .. "\n" .. table.concat(labels, "\n")
end

function panel_sets.search()
  local query = panel_sets.input_value()
  if #album_cache == 0 then
    if query ~= "" then panel_sets.status_label.label = _("refresh albums to search") end
    return
  end
  local count, shown = panel_sets.update_choices(query)
  if query == "" then
    panel_sets.status_label.label = string.format(_("%d album(s) loaded; type to search"), #album_cache)
  elseif count == 1 then
    panel_sets.status_label.label = _("1 matching album")
  elseif count > shown then
    panel_sets.status_label.label = string.format(_("%d matching album(s); showing first %d"), count, shown)
  else
    panel_sets.status_label.label = string.format(_("%d matching album(s)"), count)
  end
  panel_sets.update_membership_indicator()
end

panel_sets.match_widget.changed_callback = function(widget)
  if panel_sets.filtering then return end
  local selected = trim(widget.value or "")
  if selected ~= "" then panel_sets.entry.text = selected end
  panel_sets.update_membership_indicator()
end

