local parse_photo_id_or_url = claim.parse_photo_id

local function set_panel_photo_id_link()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection ~= 1 then
    dt.print(_("Flickr: select exactly one image before setting the link."))
    return
  end
  local image = selection[1]
  local photo_id = parse_photo_id_or_url(panel_photo_id_entry.text)
  if not photo_id then
    dt.print(_("Flickr: enter a Flickr photo ID or URL first."))
    return
  end

  local acc = load_token()
  local tag_account_nsid = state.get_any_photo_id(image)
  local account_nsid = acc and acc.nsid or tag_account_nsid
  if not account_nsid or account_nsid == "" then
    dt.print(_("Flickr: log in first, or select a photo that already has a Flickr link."))
    return
  end

  local old_photo_id = state.get_photo_id(image, account_nsid)
  state.set_photo_id(image, account_nsid, photo_id)
  panel_photo_id_entry.text = ""
  panel_remote_label.label = old_photo_id
    and string.format(_("Flickr: link changed from %s to %s"), old_photo_id, photo_id)
    or string.format(_("Flickr: link set to %s"), photo_id)
  dt.print(panel_remote_label.label)
  refresh_panel(true, http.quiet_rest_available())
end

local function clear_panel_photo_id_link()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection ~= 1 then
    dt.print(_("Flickr: select exactly one image before clearing the link."))
    return
  end
  local image = selection[1]
  local acc = load_token()
  local tag_account_nsid = state.get_any_photo_id(image)
  local account_nsid = tag_account_nsid or (acc and acc.nsid)
  if not account_nsid or account_nsid == "" then
    dt.print(_("Flickr: selected image has no stored Flickr link to clear."))
    return
  end
  local old_photo_id = state.get_photo_id(image, account_nsid)
  if not old_photo_id then
    dt.print(_("Flickr: selected image has no stored Flickr link to clear."))
    return
  end
  state.clear_photo_id(image, account_nsid)
  state.clear_sets(image, account_nsid)
  panel_remote_label.label = string.format(_("Flickr: local link cleared for photo %s"), old_photo_id)
  dt.print(panel_remote_label.label)
  refresh_panel(true, false)
end

function panel_sets.api_context(action)
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(string.format(_("Flickr: select exactly one published image before %s."), action))
    return nil
  end
  local image, acc, photo_id = panel_current.image, panel_current.account, panel_current.photo_id
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return nil
  end
  if not acc then
    dt.print(_("Flickr: log in before editing albums."))
    return nil
  end
  if not album_cache_matches(acc) then clear_album_cache() end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return nil
  end
  return image, acc, photo_id, api_key, api_secret
end

function panel_sets.refresh_list()
  local acc = load_token()
  local api_key, api_secret = get_credentials()
  if not acc then
    panel_sets.status_label.label = _("log in to refresh albums")
    dt.print(_("Flickr: log in before refreshing albums."))
    return nil, "not logged in to Flickr"
  end
  if not api_key or not api_secret then
    panel_sets.status_label.label = _("missing API credentials")
    dt.print(_("Flickr: missing API key/secret."))
    return nil, "missing Flickr API key/secret"
  end
  local sets, err = refresh_album_cache_for_export(api_key, api_secret, acc)
  if not sets then
    panel_sets.status_label.label = _("album refresh failed")
    dt.print(string.format(_("Flickr: album refresh failed: %s"), tostring(err)))
    return nil, err
  end
  panel_sets.update_choices(panel_sets.input_value())
  if panel_current.image and panel_current.account then
    panel_sets_label.label = panel_sets.format_memberships(state.get_sets(panel_current.image, panel_current.account.nsid))
    panel_sets.update_current_choices(panel_current.image, panel_current.account.nsid)
  end
  panel_sets.status_label.label = string.format(_("%d album(s) loaded"), #sets)
  dt.print(string.format(_("Flickr: loaded %d album(s)"), #sets))
  return sets
end

function panel_sets.refresh_memberships()
  local image, acc, photo_id, api_key, api_secret = panel_sets.api_context(_("refreshing albums"))
  if not image then return nil end

  local memberships, err, sets = __dtrmflickr_call("flickr.photosets.getList", function()
    return rest.photosets_get_memberships(api_key, api_secret, acc, photo_id)
  end)
  if not memberships then
    panel_sets.status_label.label = _("album membership refresh failed")
    dt.print(string.format(_("Flickr: album membership refresh failed: %s"), tostring(err)))
    return nil, err
  end

  if sets then merge_album_cache(sets, acc) end
  state.clear_sets(image, acc.nsid)
  for _, item in ipairs(memberships) do
    if item.id and item.id ~= "" then state.add_set(image, acc.nsid, item.id) end
  end
  panel_sets_label.label = panel_sets.format_memberships(state.get_sets(image, acc.nsid))
  panel_sets.update_current_choices(image, acc.nsid)
  panel_sets.update_choices(panel_sets.input_value())
  panel_sets.status_label.label = string.format(_("synced %d album membership(s)"), #memberships)
  dt.print(panel_sets.status_label.label)
  return memberships
end

function panel_sets.resolve(value)
  local match, kind = albums.find_match(album_cache, value)
  if match then return match, kind end
  value = trim(value)
  if value:match("^%d+$") then return { id = value, title = value }, "manual-id" end
  return nil, kind
end

local function flickr_error_code(err)
  return tostring(err or ""):match("%((%d+)%)")
end

local function photoset_add_is_already_present(err)
  return flickr_error_code(err) == "3"
    and tostring(err or ""):lower():find("already in set", 1, true) ~= nil
end

local function photoset_remove_is_already_absent(err)
  return flickr_error_code(err) == "3"
    and tostring(err or ""):lower():find("not in set", 1, true) ~= nil
end

function panel_sets.add()
  local image, acc, photo_id, api_key, api_secret = panel_sets.api_context(_("adding an album"))
  if not image then return end
  if #album_cache == 0 then panel_sets.refresh_list() end
  panel_sets.search()
  local value = panel_sets.input_value()
  if value == "" then
    dt.print(_("Flickr: type an album name or ID first."))
    return
  end

  local added, errors, unresolved = 0, {}, {}
  for part in value:gmatch("[^,]+") do
    local item, kind = panel_sets.resolve(part)
    if item and item.id and item.id ~= "" then
      local ok, err = __dtrmflickr_call("flickr.photosets.addPhoto", function()
        return rest.photosets_add_photo(api_key, api_secret, acc, item.id, photo_id)
      end)
      if ok or photoset_add_is_already_present(err) then
        state.add_set(image, acc.nsid, item.id)
        added = added + 1
      else
        errors[#errors + 1] = string.format("%s: %s", tostring(item.title or item.id), tostring(err))
      end
    else
      unresolved[#unresolved + 1] = string.format("%s: %s", trim(part),
        kind == "ambiguous" and "too many matches; type more or choose from matching albums"
        or "no matching album; refresh albums or check the name")
    end
  end

  if #unresolved > 0 then
    panel_sets.status_label.label = _("choose a matching album")
    dt.print(_("Flickr: choose a matching album: ") .. table.concat(unresolved, "; "))
  elseif #errors > 0 then
    panel_sets.status_label.label = _("album add failed")
    dt.print(_("Flickr: album add failed: ") .. table.concat(errors, "; "))
  else
    panel_sets.entry.text = ""
    panel_sets.clear_choices()
    panel_sets_label.label = panel_sets.format_memberships(state.get_sets(image, acc.nsid))
    panel_sets.update_current_choices(image, acc.nsid)
    panel_sets.status_label.label = string.format(_("added to %d album(s)"), added)
    dt.print(panel_sets.status_label.label)
  end
end

-- Batch add-to-album for a multi-selection (issue #49). panel_sets.add() files
-- the one focused photo into the typed album(s); this files EVERY selected
-- published photo into them. The "add existing album" button dispatches here when
-- selection_count > 1, leaving the single-image add() untouched. Unlike the
-- settings batch this needs no two-click confirm: addPhoto is purely additive and
-- idempotent (Flickr error 3 "already in set" is treated as success), so it can
-- never destroy data the way overwriting privacy/safety can. The album target(s)
-- are resolved once (identical for every photo); photos with no linked Flickr id
-- are skipped. Reports a per-photo tally; mirrors create_from_selection's style.
function panel_sets.add_to_selection()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection <= 1 then
    panel_sets.add()
    return
  end
  local acc = panel_current.account or load_token()
  if not acc then
    dt.print(_("Flickr: log in before editing albums."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end
  if not album_cache_matches(acc) then clear_album_cache() end
  if #album_cache == 0 then panel_sets.refresh_list() end
  panel_sets.search()
  local value = panel_sets.input_value()
  if value == "" then
    dt.print(_("Flickr: type an album name or ID first."))
    return
  end

  -- Resolve the requested album(s) once; the resolution is the same for every
  -- selected photo. Bail before touching Flickr if any part is ambiguous/unknown.
  local targets, unresolved = {}, {}
  for part in value:gmatch("[^,]+") do
    local item, kind = panel_sets.resolve(part)
    if item and item.id and item.id ~= "" then
      targets[#targets + 1] = item
    else
      unresolved[#unresolved + 1] = string.format("%s: %s", trim(part),
        kind == "ambiguous" and "too many matches; type more or choose from matching albums"
        or "no matching album; refresh albums or check the name")
    end
  end
  if #unresolved > 0 then
    panel_sets.status_label.label = _("choose a matching album")
    dt.print(_("Flickr: choose a matching album: ") .. table.concat(unresolved, "; "))
    return
  end
  if #targets == 0 then
    dt.print(_("Flickr: type an album name or ID first."))
    return
  end

  local added_photos, unlinked, errors = 0, 0, {}
  for _, image in ipairs(selection) do
    local photo_id = state.get_photo_id(image, acc.nsid)
    if not photo_id then
      unlinked = unlinked + 1
    else
      local photo_added = false
      for _, item in ipairs(targets) do
        local ok, err = __dtrmflickr_call("flickr.photosets.addPhoto", function()
          return rest.photosets_add_photo(api_key, api_secret, acc, item.id, photo_id)
        end)
        if ok or photoset_add_is_already_present(err) then
          state.add_set(image, acc.nsid, item.id)
          photo_added = true
        else
          errors[#errors + 1] = string.format("%s/%s: %s",
            tostring(photo_id), tostring(item.title or item.id), tostring(err))
        end
      end
      if photo_added then added_photos = added_photos + 1 end
    end
  end

  refresh_panel(true, false)
  panel_sets.status_label.label = string.format(
    _("Flickr: album add — %d photo(s) filed into %d album(s), %d not linked (of %d selected)"),
    added_photos, #targets, unlinked, #selection)
  dt.print(panel_sets.status_label.label)
  if #errors > 0 then
    dt.print(_("Flickr: album add errors: ") .. table.concat(errors, "; "))
  end
end

function panel_sets.create()
  local image, acc, photo_id, api_key, api_secret = panel_sets.api_context(_("creating an album"))
  if not image then return end
  if #album_cache == 0 then panel_sets.refresh_list() end
  local title = trim(panel_sets.new_entry.text or "")
  if title == "" then
    dt.print(_("Flickr: type a new album title first."))
    return
  end

  local existing = albums.find_exact(album_cache, title)
  if existing then
    panel_sets.status_label.label = _("album already exists")
    dt.print(string.format(_("Flickr: album '%s' already exists; use add existing album."), title))
    return
  end

  -- Do NOT auto-retry album creation. flickr.photosets.create is not idempotent
  -- and has no dedupe key, so a transient timeout *after* Flickr created the set
  -- (ack lost) is indistinguishable from "never created" — a retry would make a
  -- second duplicate album with the same title. One attempt: a transient create
  -- failure is reported and the user retries. (Same policy as flickr.upload.)
  local photoset_id, err = __dtrmflickr_call("flickr.photosets.create", function()
    return rest.photosets_create(api_key, api_secret, acc, title, photo_id)
  end, { max_attempts = 1 })
  if photoset_id then
    state.add_set(image, acc.nsid, photoset_id)
    table.insert(album_cache, 1, { id = photoset_id, title = title, photos = "1" })
    panel_sets.new_entry.text = ""
    panel_sets_label.label = panel_sets.format_memberships(state.get_sets(image, acc.nsid))
    panel_sets.update_current_choices(image, acc.nsid)
    panel_sets.status_label.label = string.format(_("created album '%s'"), title)
    dt.print(panel_sets.status_label.label)
  else
    panel_sets.status_label.label = _("album create failed")
    dt.print(string.format(_("Flickr: album create failed: %s"), tostring(err)))
  end
end

-- Create a new album from the CURRENT lighttable selection (issue #30).
--
-- Unlike panel_sets.create (which acts on the single focused published photo),
-- this gathers every selected image that is already published to the active
-- account, creates the photoset with the first as primary, then adds the rest
-- with flickr.photosets.addPhoto. Unpublished images in the selection are
-- skipped and reported; duplicate Flickr ids collapse to one. As with the
-- single create, photosets.create is NOT retried (non-idempotent, no dedupe
-- key), but the per-photo addPhoto calls keep the default retry policy.
function panel_sets.create_from_selection()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection == 0 then
    dt.print(_("Flickr: select one or more published images before creating an album."))
    return
  end
  local acc = load_token()
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before creating an album."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end
  local title = trim(panel_sets.new_entry.text or "")
  if title == "" then
    dt.print(_("Flickr: type a new album title first."))
    return
  end
  if not album_cache_matches(acc) then clear_album_cache() end
  if #album_cache == 0 then panel_sets.refresh_list() end
  if albums.find_exact(album_cache, title) then
    panel_sets.status_label.label = _("album already exists")
    dt.print(string.format(_("Flickr: album '%s' already exists; use add existing album."), title))
    return
  end

  -- Build the ordered, de-duplicated member list from the selection.
  local entries = {}
  for _, image in ipairs(selection) do
    entries[#entries + 1] = { image = image, photo_id = state.get_photo_id(image, acc.nsid) }
  end
  local plan = albums.plan_selection_create(entries)
  if #plan.members == 0 then
    panel_sets.status_label.label = _("no published photos in selection")
    dt.print(string.format(
      _("Flickr: none of the %d selected image(s) are published to this account; nothing to put in the album."),
      plan.total))
    return
  end

  -- Create the set with the first member as the primary/cover photo.
  local primary = plan.members[1]
  local photoset_id, err = __dtrmflickr_call("flickr.photosets.create", function()
    return rest.photosets_create(api_key, api_secret, acc, title, primary.photo_id)
  end, { max_attempts = 1 })
  if not photoset_id then
    panel_sets.status_label.label = _("album create failed")
    dt.print(string.format(_("Flickr: album create failed: %s"), tostring(err)))
    return
  end
  state.add_set(primary.image, acc.nsid, photoset_id)

  -- Add the remaining members.
  local added, add_errors = 1, {}
  for i = 2, #plan.members do
    local m = plan.members[i]
    local ok, aerr = __dtrmflickr_call("flickr.photosets.addPhoto", function()
      return rest.photosets_add_photo(api_key, api_secret, acc, photoset_id, m.photo_id)
    end)
    if ok or photoset_add_is_already_present(aerr) then
      state.add_set(m.image, acc.nsid, photoset_id)
      added = added + 1
    else
      add_errors[#add_errors + 1] = string.format("%s: %s", tostring(m.photo_id), tostring(aerr))
    end
  end

  table.insert(album_cache, 1, { id = photoset_id, title = title, photos = tostring(added) })
  panel_sets.new_entry.text = ""
  if panel_current.image and panel_current.account then
    panel_sets_label.label = panel_sets.format_memberships(state.get_sets(panel_current.image, panel_current.account.nsid))
    panel_sets.update_current_choices(panel_current.image, panel_current.account.nsid)
  end

  -- Report: created + added, plus any skipped/failed.
  local notes = {}
  if plan.unlinked > 0 then
    notes[#notes + 1] = string.format(_("%d not published, skipped"), plan.unlinked)
  end
  if plan.duplicates > 0 then
    notes[#notes + 1] = string.format(_("%d duplicate(s) collapsed"), plan.duplicates)
  end
  if #add_errors > 0 then
    notes[#notes + 1] = string.format(_("%d add failed"), #add_errors)
  end
  local suffix = (#notes > 0) and (" (" .. table.concat(notes, ", ") .. ")") or ""
  panel_sets.status_label.label = string.format(_("created '%s' with %d photo(s)"), title, added) .. suffix
  dt.print(panel_sets.status_label.label)
  if #add_errors > 0 then
    dt.print(_("Flickr: some photos could not be added: ") .. table.concat(add_errors, "; "))
  end
end

function panel_sets.remove_selected()
  local image, acc, photo_id, api_key, api_secret = panel_sets.api_context(_("removing an album"))
  if not image then return end
  local set_id = panel_sets.selected_current_id()
  if not set_id or set_id == "" then
    panel_sets.status_label.label = _("albums: none recorded")
    dt.print(_("Flickr: choose a current album to remove."))
    return
  end

  local ok, err = __dtrmflickr_call("flickr.photosets.removePhoto", function()
    return rest.photosets_remove_photo(api_key, api_secret, acc, set_id, photo_id)
  end)
  local already_absent = photoset_remove_is_already_absent(err)
  if ok or already_absent then state.remove_set(image, acc.nsid, set_id) end
  panel_sets_label.label = panel_sets.format_memberships(state.get_sets(image, acc.nsid))
  panel_sets.update_current_choices(image, acc.nsid)
  if not ok and not already_absent then
    panel_sets.status_label.label = _("album remove failed")
    dt.print(string.format(_("Flickr: album remove failed: %s"), tostring(err)))
  else
    panel_sets.status_label.label = string.format(_("removed from album %s"), tostring(set_id))
    dt.print(panel_sets.status_label.label)
  end
end

-- Set the selected published photo as the cover (primary photo) of the album
-- chosen in the "album for cover/order/remove" combobox (issue #31). The photo
-- must already be a member of that album; the combobox only lists the photo's
-- recorded albums, so a chosen album is normally a valid target.
function panel_sets.set_cover()
  local image, acc, photo_id, api_key, api_secret = panel_sets.api_context(_("setting an album cover"))
  if not image then return end
  local set_id = panel_sets.selected_current_id()
  if not set_id or set_id == "" then
    panel_sets.status_label.label = _("choose one of this photo's albums first")
    dt.print(_("Flickr: choose one of this photo's albums to set as cover."))
    return
  end

  local ok, err = __dtrmflickr_call("flickr.photosets.setPrimaryPhoto", function()
    return rest.photosets_set_primary_photo(api_key, api_secret, acc, set_id, photo_id)
  end)
  if ok then
    panel_sets.status_label.label = string.format(_("set as cover of album %s"), tostring(set_id))
    dt.print(panel_sets.status_label.label)
  else
    panel_sets.status_label.label = _("set cover failed")
    dt.print(string.format(_("Flickr: set album cover failed: %s"), tostring(err)))
  end
end

-- Move the selected published photo to the front of the album chosen in the
-- "album for cover/order/remove" combobox (issue #31). Uses reorderPhotos with a
-- single-id ordered list: Flickr keeps the album's other photos in their existing
-- relative order, so this only promotes the chosen photo to first.
function panel_sets.move_to_front()
  local image, acc, photo_id, api_key, api_secret = panel_sets.api_context(_("reordering an album"))
  if not image then return end
  local set_id = panel_sets.selected_current_id()
  if not set_id or set_id == "" then
    panel_sets.status_label.label = _("choose one of this photo's albums first")
    dt.print(_("Flickr: choose one of this photo's albums to reorder."))
    return
  end

  local photo_ids = albums.reorder_csv({ photo_id })
  local ok, err = __dtrmflickr_call("flickr.photosets.reorderPhotos", function()
    return rest.photosets_reorder_photos(api_key, api_secret, acc, set_id, photo_ids)
  end)
  if ok then
    panel_sets.status_label.label = string.format(_("moved to front of album %s"), tostring(set_id))
    dt.print(panel_sets.status_label.label)
  else
    panel_sets.status_label.label = _("reorder failed")
    dt.print(string.format(_("Flickr: album reorder failed: %s"), tostring(err)))
  end
end

local function load_remote_content_type(api_key, api_secret, acc, photo_id, dateuploaded)
  local args = {
    user_id = acc and acc.nsid or nil,
    -- `views` is free here (same call) and feeds the panel-only stats line (#73).
    extras = "content_type,views",
    per_page = 50,
    page = 1,
  }
  if dateuploaded and dateuploaded ~= "" then
    args.min_upload_date = dateuploaded
    args.max_upload_date = dateuploaded
  end

  local body, err
  if acc then
    body, err = __dtrmflickr_call("flickr.photos.search", function()
      return rest.call(api_key, api_secret, acc, "flickr.photos.search", args)
    end, { coalesce_key = "panel-refresh-content:" .. tostring(photo_id) })
  else
    body, err = __dtrmflickr_call("flickr.photos.search", function()
      return rest.public_call(api_key, "flickr.photos.search", args)
    end, { coalesce_key = "panel-refresh-content:" .. tostring(photo_id) })
  end
  local search_value = panel_helpers.parse_search_content_type(body, photo_id)
  return panel_helpers.panel_content_type_index_from_search_value(search_value), search_value, err,
    remote_pull.search_views(body, photo_id)
end

local function load_remote_settings(api_key, api_secret, acc, photo_id)
  panel_reset_remote(_("Flickr: loading remote settings..."))
  local body, err
  if acc then
    body, err = __dtrmflickr_call("flickr.photos.getInfo", function()
      return rest.call(api_key, api_secret, acc, "flickr.photos.getInfo", { photo_id = photo_id })
    end, { coalesce_key = "panel-refresh:" .. tostring(photo_id) })
  else
    body, err = __dtrmflickr_call("flickr.photos.getInfo", function()
      return rest.public_call(api_key, "flickr.photos.getInfo", { photo_id = photo_id })
    end, { coalesce_key = "panel-refresh:" .. tostring(photo_id) })
  end
  if not body then
    -- Tell "the photo was deleted/removed on Flickr" (error 1, Photo not found)
    -- apart from a transient/auth failure, so the user knows the local link is now
    -- stale and can clear it (issue #20). Permission errors get their own hint.
    local kind = remote_pull.classify_error(err)
    if kind == "deleted" then
      panel_reset_remote(_("Flickr: this photo no longer exists on Flickr (deleted/removed). Use 'clear Flickr link' to drop the stale local link."))
    elseif kind == "permission" then
      panel_reset_remote(_("Flickr: no permission to read this photo on Flickr."))
    else
      panel_reset_remote(string.format(_("Flickr: remote settings unavailable: %s"), tostring(err)))
    end
    return
  end

  local visibility = body:match("<visibility%s+([^>]-)/>") or body:match("<visibility%s+([^>]-)>")
  panel_loading = true
  panel_privacy_widget.selected = panel_helpers.panel_privacy_index_from_flags(
    visibility and panel_helpers.remote_attr(visibility, "ispublic"),
    visibility and panel_helpers.remote_attr(visibility, "isfriend"),
    visibility and panel_helpers.remote_attr(visibility, "isfamily")) or 0
  panel_safety_widget.selected = panel_helpers.panel_safety_index_from_remote(panel_helpers.remote_attr(body, "safety_level")) or 0
  panel_license_widget.selected = panel_helpers.panel_license_index_from_id(panel_helpers.remote_attr(body, "license")) or 0
  local remote_dateuploaded = panel_helpers.remote_attr(body, "dateuploaded")
  -- Persist Flickr's authoritative upload date/time (issue #21). This is the
  -- truth source: it refines the local stamp a fresh upload seeded, and — more
  -- importantly — backfills the real date for photos that were claimed/linked
  -- long after they were first uploaded. Best-effort: a missing/garbage value
  -- (flickr_upload_stamp returns nil) leaves any existing record untouched.
  if acc and panel_current.image then
    local upload_stamp = metadata.flickr_upload_stamp(remote_dateuploaded)
    if upload_stamp then
      state.set_uploaded_at(panel_current.image, acc.nsid, upload_stamp)
    end
  end
  local content_type_index, _ctv, _cte, remote_views = load_remote_content_type(api_key, api_secret, acc, photo_id, remote_dateuploaded)
  panel_content_type_widget.selected = content_type_index or 0
  -- Faves count (issue #9): unlike views/comments there is no free source, so spend
  -- one explicit flickr.photos.getFavorites per panel load. Display-only and
  -- best-effort — a failure just omits the faves part. per_page=1 keeps the page
  -- tiny; we only read the wrapper's total= attribute. Works public or authed.
  local remote_faves
  do
    local fav_body = __dtrmflickr_call("flickr.photos.getFavorites", function()
      if acc then
        return rest.call(api_key, api_secret, acc, "flickr.photos.getFavorites", { photo_id = photo_id, per_page = 1 })
      end
      return rest.public_call(api_key, "flickr.photos.getFavorites", { photo_id = photo_id, per_page = 1 })
    end, { coalesce_key = "panel-refresh-faves:" .. tostring(photo_id) })
    if fav_body then remote_faves = remote_pull.favorites_count(fav_body) end
  end
  -- Panel-only Flickr stats: views (from the search above) + comment count (from the
  -- getInfo body) — both free — plus faves (#9) and the upload date (#9, from the
  -- getInfo dateuploaded). Display-only; never persisted.
  panel_stats_label.label = remote_pull.format_stats(
    remote_views, remote_pull.comment_count(body), remote_faves, remote_dateuploaded) or ""
  local perms_unavailable = false
  if acc then
    local perms_body, perms_err = __dtrmflickr_call("flickr.photos.getPerms", function()
      return rest.photos_get_perms(api_key, api_secret, acc, photo_id)
    end, { coalesce_key = "panel-refresh-perms:" .. tostring(photo_id) })
    if perms_body then
      panel_comment_perm_widget.selected = panel_helpers.panel_permission_index_from_id(panel_helpers.remote_attr(perms_body, "permcomment")) or 0
      panel_addmeta_perm_widget.selected = panel_helpers.panel_permission_index_from_id(panel_helpers.remote_attr(perms_body, "permaddmeta")) or 0
    else
      -- Capture and log the reason so a real perms failure is diagnosable,
      -- matching the getInfo/search read sites; the controls still disable.
      dt.print_log("[dtrmflickr] getPerms unavailable for photo " ..
        tostring(photo_id) .. ": " .. tostring(perms_err))
      panel_comment_perm_widget.selected = 0
      panel_addmeta_perm_widget.selected = 0
      perms_unavailable = true
    end
  else
    panel_comment_perm_widget.selected = 0
    panel_addmeta_perm_widget.selected = 0
  end
  local remote_tags = panel_helpers.parse_remote_tags(body)
  panel_tags_label.label = #remote_tags > 0
    and string.format(_("Flickr tags: %s"), table.concat(remote_tags, ", "))
    or _("Flickr tags: none")
  if panel_reconcile.refresh then panel_reconcile.refresh(panel_current.image, remote_tags) end
  panel_loading = false
  panel_dirty = { privacy = false, safety = false, content_type = false, license = false, comment_perm = false, addmeta_perm = false }
  panel_privacy_widget.sensitive = acc ~= nil
  panel_safety_widget.sensitive = acc ~= nil
  panel_content_type_widget.sensitive = acc ~= nil
  panel_license_widget.sensitive = acc ~= nil
  panel_comment_perm_widget.sensitive = acc ~= nil and not perms_unavailable
  panel_addmeta_perm_widget.sensitive = acc ~= nil and not perms_unavailable
  panel_current.remote_loaded = true
  -- Remember exactly which (image, photo_id, account) we just pulled so a
  -- repeated/duplicate selection of the SAME published photo doesn't re-issue
  -- the getInfo/getPerms/getContentType trio (3 queue jobs per click). Any
  -- panel_reset_remote (selection actually moving, logout, edit) clears this.
  panel_sets.last_remote_load = { image = panel_current.image, photo_id = photo_id, nsid = acc and acc.nsid or nil }
  panel_remote_label.label = perms_unavailable
    and _("Flickr: remote settings loaded; permissions unavailable")
    or content_type_index
    and _("Flickr: remote settings loaded")
    or _("Flickr: remote settings loaded; content type unavailable")
end

local function save_panel_settings()
  local acc, photo_id = panel_current.account, panel_current.photo_id
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image before saving panel settings."))
    return
  end
  if not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before saving Flickr settings."))
    return
  end
  if not panel_current.remote_loaded then
    dt.print(_("Flickr: remote settings are not loaded yet."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end

  local errors = {}
  local skipped = {}
  local saved_fields = {}
  local sync = master_sync_fields()
  local is_public, is_friend, is_family = panel_privacy_flags()
  local wants_privacy = panel_dirty.privacy
  local wants_comment_perm = panel_dirty.comment_perm
  local wants_addmeta_perm = panel_dirty.addmeta_perm
  local update_privacy = wants_privacy and sync.privacy
  local update_comment_perm = wants_comment_perm and sync.permissions
  local update_addmeta_perm = wants_addmeta_perm and sync.permissions
  if update_privacy or update_comment_perm or update_addmeta_perm then
    local ok, err = __dtrmflickr_call("flickr.photos.setPerms", function()
      return rest.photos_set_perms(api_key, api_secret, acc, photo_id, is_public, is_friend, is_family,
        update_comment_perm and panel_comment_perm_value() or nil,
        update_addmeta_perm and panel_addmeta_perm_value() or nil)
    end)
    if not ok then
      if update_privacy then state.mark_reason(panel_current.image, acc.nsid, "visibility") end
      if update_comment_perm or update_addmeta_perm then state.mark_reason(panel_current.image, acc.nsid, "permissions") end
      errors[#errors + 1] = "privacy: " .. tostring(err)
    else
      if update_privacy then state.clear_reason(panel_current.image, acc.nsid, "visibility") end
      if update_comment_perm or update_addmeta_perm then state.clear_reason(panel_current.image, acc.nsid, "permissions") end
      if update_privacy then saved_fields[#saved_fields + 1] = "visibility" end
      if update_comment_perm or update_addmeta_perm then saved_fields[#saved_fields + 1] = "permissions" end
    end
  end
  if wants_privacy and not sync.privacy then skipped[#skipped + 1] = "privacy" end
  if (wants_comment_perm or wants_addmeta_perm) and not sync.permissions then
    skipped[#skipped + 1] = "permissions"
  end
  local safety = panel_safety_value()
  -- setSafetyLevel pushes the safety level, gated by its sync master toggle.
  local push_safety = panel_dirty.safety and sync.safety
  if push_safety then
    local ok, err = __dtrmflickr_call("flickr.photos.setSafetyLevel", function()
      return rest.photos_set_safety_level(api_key, api_secret, acc, photo_id, safety)
    end)
    if not ok then
      state.mark_reason(panel_current.image, acc.nsid, "safety")
      errors[#errors + 1] = "safety: " .. tostring(err)
    else
      state.clear_reason(panel_current.image, acc.nsid, "safety")
      saved_fields[#saved_fields + 1] = "safety"
    end
  elseif panel_dirty.safety then
    skipped[#skipped + 1] = "safety"
  end
  local content_type = panel_content_type_value()
  if panel_dirty.content_type and sync.content_type then
    if content_type then
      local ok, err = __dtrmflickr_call("flickr.photos.setContentType", function()
        return rest.photos_set_content_type(api_key, api_secret, acc, photo_id, content_type)
      end)
      if not ok then
        state.mark_reason(panel_current.image, acc.nsid, "content_type")
        errors[#errors + 1] = "content type: " .. tostring(err)
      else
        state.clear_reason(panel_current.image, acc.nsid, "content_type")
        saved_fields[#saved_fields + 1] = "content_type"
      end
    else
      errors[#errors + 1] = "content type: choose a value first"
    end
  elseif panel_dirty.content_type then
    skipped[#skipped + 1] = "content type"
  end
  local license = panel_license_value()
  if panel_dirty.license and sync.license then
    local ok, err = __dtrmflickr_call("flickr.photos.licenses.setLicense", function()
      return rest.photos_licenses_set_license(api_key, api_secret, acc, photo_id, license)
    end)
    if not ok then
      state.mark_reason(panel_current.image, acc.nsid, "license")
      errors[#errors + 1] = "license: " .. tostring(err)
    else
      state.clear_reason(panel_current.image, acc.nsid, "license")
      saved_fields[#saved_fields + 1] = "license"
    end
  elseif panel_dirty.license then
    skipped[#skipped + 1] = "license"
  end

  if #errors > 0 then
    panel_remote_label.label = _("Flickr: save failed")
    dt.print(_("Flickr: save failed: ") .. table.concat(errors, "; "))
  elseif #skipped > 0 then
    if #saved_fields > 0 then
      state.set_metadata_published_at(panel_current.image, acc.nsid)
      store_metadata_fingerprints(panel_current.image, acc.nsid,
        effective_metadata_fingerprints(panel_current.image, sync), saved_fields)
      panel_sets.refresh_publish_state_label(panel_current.image, acc, photo_id)
    end
    panel_remote_label.label = _("Flickr: settings skipped by Lua sync options")
    dt.print(_("Flickr: settings skipped by Lua sync options: ") .. table.concat(skipped, ", "))
  else
    state.set_metadata_published_at(panel_current.image, acc.nsid)
    store_metadata_fingerprints(panel_current.image, acc.nsid,
      effective_metadata_fingerprints(panel_current.image, sync), saved_fields)
    panel_sets.refresh_publish_state_label(panel_current.image, acc, photo_id)
    panel_remote_label.label = _("Flickr: settings saved")
    dt.print(_("Flickr: settings saved."))
    load_remote_settings(api_key, api_secret, acc, photo_id)
  end
end

-- Batch apply the panel's settings comboboxes (privacy / safety / content-type /
-- license / comment+add-meta permissions) to every selected
-- published photo (issue #49). save_panel_settings handles selection_count == 1;
-- this handles > 1 and is what the "save" button dispatches to in that case, so
-- the verified single-image path stays byte-for-byte untouched.
--
-- Only the fields the user actually changed (panel_dirty) are applied, and only
-- those still enabled by the Lua sync toggles (batch_apply.partition_fields);
-- the chosen widget values are the same for every photo. Per-photo apply mirrors
-- save_panel_settings exactly: setPerms folds privacy+permissions, setSafetyLevel
-- pushes the safety level, the same publish-state reasons are cleared on
-- success / marked on failure, and the same settings fingerprints are stored so
-- the photos read as current afterwards. Photos with no linked Flickr id are
-- skipped (never touched). Reports a per-photo tally like push_selected_metadata.
--
-- Confirmation is two-click (darktable Lua has no blocking modal dialog): the
-- first save on a multi-selection shows exactly which fields will be overwritten
-- on N photos and arms panel_sets.batch_save_armed; the second save performs it.
-- Any selection change disarms it (refresh_panel).
function panel_sets.apply_settings_to_selection()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection <= 1 then
    -- Not actually a multi-selection — fall back to the single-image path.
    panel_sets.batch_save_armed = nil
    save_panel_settings()
    return
  end
  local acc = panel_current.account
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before saving Flickr settings."))
    return
  end
  if not panel_current.remote_loaded then
    dt.print(_("Flickr: remote settings are not loaded yet (select/refresh the focused photo first)."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end

  local sync = master_sync_fields()
  local apply_entries, skipped_entries = batch_apply.partition_fields(panel_dirty, sync)
  if #apply_entries == 0 then
    panel_sets.batch_save_armed = nil
    if #skipped_entries > 0 then
      dt.print(_("Flickr: every changed setting is disabled by the Lua sync options; nothing to apply."))
    else
      dt.print(_("Flickr: change a setting before saving to the selection."))
    end
    return
  end

  -- First click arms + previews; second click (still armed, same selection) runs.
  if not panel_sets.batch_save_armed then
    panel_sets.batch_save_armed = true
    local msg = batch_apply.confirm_text(apply_entries, #selection, _)
    panel_remote_label.label = msg
    dt.print(msg)
    return
  end
  panel_sets.batch_save_armed = nil

  -- Snapshot the user-chosen values once; they are identical for every photo.
  local want = {}
  for _, e in ipairs(apply_entries) do want[e.dirty_key] = true end
  local is_public, is_friend, is_family = panel_privacy_flags()
  local comment_val = panel_comment_perm_value()
  local addmeta_val = panel_addmeta_perm_value()
  local safety_val = panel_safety_value()
  local content_val = panel_content_type_value()
  local license_val = panel_license_value()
  local want_perm = want.comment_perm or want.addmeta_perm

  local applied, with_errors, unlinked = 0, 0, 0
  local fail_notes = {}

  for _, image in ipairs(selection) do
    local photo_id = state.get_photo_id(image, acc.nsid)
    if not photo_id then
      unlinked = unlinked + 1
    else
      local photo_ok, photo_failed = false, false
      local saved_fields = {}

      -- privacy + permissions fold into one setPerms call (mirrors single path).
      if want.privacy or want_perm then
        local ok, err = __dtrmflickr_call("flickr.photos.setPerms", function()
          return rest.photos_set_perms(api_key, api_secret, acc, photo_id, is_public, is_friend, is_family,
            want.comment_perm and comment_val or nil,
            want.addmeta_perm and addmeta_val or nil)
        end)
        if ok then
          photo_ok = true
          if want.privacy then state.clear_reason(image, acc.nsid, "visibility"); saved_fields[#saved_fields + 1] = "visibility" end
          if want_perm then state.clear_reason(image, acc.nsid, "permissions"); saved_fields[#saved_fields + 1] = "permissions" end
        else
          photo_failed = true
          if want.privacy then state.mark_reason(image, acc.nsid, "visibility") end
          if want_perm then state.mark_reason(image, acc.nsid, "permissions") end
          fail_notes[#fail_notes + 1] = string.format("%s/privacy: %s", tostring(photo_id), tostring(err))
        end
      end

      -- safety level via setSafetyLevel.
      if want.safety then
        local ok, err = __dtrmflickr_call("flickr.photos.setSafetyLevel", function()
          return rest.photos_set_safety_level(api_key, api_secret, acc, photo_id, safety_val)
        end)
        if ok then
          photo_ok = true
          if want.safety then state.clear_reason(image, acc.nsid, "safety"); saved_fields[#saved_fields + 1] = "safety" end
        else
          photo_failed = true
          if want.safety then state.mark_reason(image, acc.nsid, "safety") end
          fail_notes[#fail_notes + 1] = string.format("%s/safety: %s", tostring(photo_id), tostring(err))
        end
      end

      if want.content_type then
        if content_val then
          local ok, err = __dtrmflickr_call("flickr.photos.setContentType", function()
            return rest.photos_set_content_type(api_key, api_secret, acc, photo_id, content_val)
          end)
          if ok then
            photo_ok = true
            state.clear_reason(image, acc.nsid, "content_type"); saved_fields[#saved_fields + 1] = "content_type"
          else
            photo_failed = true
            state.mark_reason(image, acc.nsid, "content_type")
            fail_notes[#fail_notes + 1] = string.format("%s/content type: %s", tostring(photo_id), tostring(err))
          end
        else
          photo_failed = true
          fail_notes[#fail_notes + 1] = string.format("%s/content type: choose a value first", tostring(photo_id))
        end
      end

      if want.license then
        local ok, err = __dtrmflickr_call("flickr.photos.licenses.setLicense", function()
          return rest.photos_licenses_set_license(api_key, api_secret, acc, photo_id, license_val)
        end)
        if ok then
          photo_ok = true
          state.clear_reason(image, acc.nsid, "license"); saved_fields[#saved_fields + 1] = "license"
        else
          photo_failed = true
          state.mark_reason(image, acc.nsid, "license")
          fail_notes[#fail_notes + 1] = string.format("%s/license: %s", tostring(photo_id), tostring(err))
        end
      end

      if photo_ok then
        -- Record the just-pushed settings as current so publish-state stops
        -- flagging them (same bookkeeping as the single-image save).
        state.set_metadata_published_at(image, acc.nsid)
        store_metadata_fingerprints(image, acc.nsid,
          effective_metadata_fingerprints(image, sync), saved_fields)
      end
      if photo_failed then with_errors = with_errors + 1
      elseif photo_ok then applied = applied + 1 end
    end
  end

  refresh_panel(true, false)
  local summary = batch_apply.result_summary(
    { applied = applied, with_errors = with_errors, unlinked = unlinked, count = #selection }, _)
  panel_remote_label.label = summary
  dt.print(summary)
  if #skipped_entries > 0 then
    dt.print(string.format(_("Flickr: skipped by Lua sync options: %s"),
      batch_apply.friendly_list(skipped_entries)))
  end
  if #fail_notes > 0 then
    dt.print(_("Flickr: batch settings errors: ") .. table.concat(fail_notes, "; "))
  end
end

local function sync_panel_meta()
  local acc, photo_id, image = panel_current.account, panel_current.photo_id, panel_current.image
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image before syncing metadata."))
    return
  end
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before syncing Flickr metadata."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end

  local sync = master_sync_fields()
  local title = sync.title and (image and image.title or "") or nil
  local description = sync.description and (image and image.description or "") or nil
  if not sync.title and not sync.description then
    dt.print(_("Flickr: title/description sync disabled in Lua Options."))
    return
  end
  if title == nil and description == nil then
    dt.print(_("Flickr: selected image has no title or description to sync."))
    return
  end

  local ok, err = __dtrmflickr_call("flickr.photos.setMeta", function()
    return rest.photos_set_meta(api_key, api_secret, acc, photo_id, title, description)
  end)
  if ok then
    state.set_metadata_published_at(image, acc.nsid)
    state.clear_reason(image, acc.nsid, "title_description")
    store_metadata_fingerprints(image, acc.nsid,
      effective_metadata_fingerprints(image, master_sync_fields()), { "title_description" })
    panel_sets.refresh_publish_state_label(image, acc, photo_id)
    panel_remote_label.label = _("Flickr: title/description synced")
    dt.print(_("Flickr: title/description synced."))
    load_remote_settings(api_key, api_secret, acc, photo_id)
  else
    state.mark_reason(image, acc.nsid, "title_description")
    panel_remote_label.label = _("Flickr: metadata sync failed")
    dt.print(_("Flickr: metadata sync failed: ") .. tostring(err))
  end
end

local function sync_panel_tags()
  local acc, photo_id, image = panel_current.account, panel_current.photo_id, panel_current.image
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image before syncing keywords."))
    return
  end
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before syncing Flickr keywords."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end
  if not master_sync_fields().tags then
    dt.print(_("Flickr: keyword sync disabled in Lua Options."))
    return
  end

  local tags, truncated_tags = rules.image_keyword_tags(image)
  tags = tags or ""
  if truncated_tags and truncated_tags > 0 then
    dt.print(string.format(_("Flickr: selected image has more than %d publishable keywords; skipped %d extra tag(s)"),
      FLICKR_TAG_LIMIT, truncated_tags))
  end

  -- setTags is a full *replace* of the tag set, which is idempotent for a fixed
  -- input: replaying it on a lost-ack retry converges to the same tags. So,
  -- unlike upload/photosets.create, it keeps the default retry/backoff.
  local ok, err = __dtrmflickr_call("flickr.photos.setTags", function()
    return rest.photos_set_tags(api_key, api_secret, acc, photo_id, tags)
  end)
  if ok then
    state.set_metadata_published_at(image, acc.nsid)
    state.clear_reason(image, acc.nsid, "keywords")
    store_metadata_fingerprints(image, acc.nsid,
      effective_metadata_fingerprints(image, master_sync_fields()), { "keywords" })
    panel_sets.refresh_publish_state_label(image, acc, photo_id)
    panel_remote_label.label = _("Flickr: keywords synced")
    dt.print(_("Flickr: keywords synced."))
    load_remote_settings(api_key, api_secret, acc, photo_id)
  else
    state.mark_reason(image, acc.nsid, "keywords")
    panel_remote_label.label = _("Flickr: keyword sync failed")
    dt.print(_("Flickr: keyword sync failed: ") .. tostring(err))
  end
end

-- Pull remote title/description from Flickr back into the selected darktable image
-- (issue #20). The opposite direction of sync_panel_meta: it reads the linked
-- photo's current title/description via flickr.photos.getInfo and writes any that
-- differ onto the local image, honouring the same per-field sync toggles so a
-- field the user manages locally (toggle off) is never overwritten. A field of
-- this is a panel_sets.* method (not a top-level local) to stay clear of the main
-- chunk's local-variable ceiling. Remote-tag pull stays owned by the tag
-- reconciler; this touches title/description only. Live-gated (needs in-app verify).
function panel_sets.pull_remote_meta()
  local acc, photo_id, image = panel_current.account, panel_current.photo_id, panel_current.image
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image before pulling remote edits."))
    return
  end
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before pulling remote edits."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end
  local sync = master_sync_fields()
  if not sync.title and not sync.description then
    dt.print(_("Flickr: title/description sync disabled in Lua Options."))
    return
  end

  local body, err = __dtrmflickr_call("flickr.photos.getInfo", function()
    return rest.call(api_key, api_secret, acc, "flickr.photos.getInfo", { photo_id = photo_id })
  end, { coalesce_key = "panel-pull:" .. tostring(photo_id) })
  if not body then
    local kind = remote_pull.classify_error(err)
    if kind == "deleted" then
      panel_remote_label.label = _("Flickr: photo no longer exists on Flickr (deleted/removed)")
      dt.print(_("Flickr: this photo no longer exists on Flickr; nothing to pull. Consider clearing the local link."))
    else
      panel_remote_label.label = _("Flickr: pull failed")
      dt.print(string.format(_("Flickr: could not read remote edits: %s"), tostring(err)))
    end
    return
  end

  local remote = remote_pull.parse_info(body)
  if not remote then
    panel_remote_label.label = _("Flickr: pull failed")
    dt.print(_("Flickr: could not parse the remote photo info."))
    return
  end

  local plan = remote_pull.title_description_pull(
    remote, { title = image.title, description = image.description }, sync)
  if not plan.any then
    panel_remote_label.label = _("Flickr: title/description already match Flickr")
    dt.print(_("Flickr: title/description already match Flickr; nothing pulled."))
    return
  end

  local changed = {}
  if plan.title then image.title = plan.title.new; changed[#changed + 1] = "title" end
  if plan.description then image.description = plan.description.new; changed[#changed + 1] = "description" end
  -- Local copies now match the remote that was just pushed/edited; refresh the
  -- per-image publish-state label so title/description no longer reads as drifted.
  if panel_sets.refresh_publish_state_label then
    panel_sets.refresh_publish_state_label(image, acc, photo_id)
  end
  -- Writing image.title/description updates the darktable database, but the
  -- editable "metadata editor" module does not re-read until the selection
  -- changes, so the pulled values would otherwise only appear after the user
  -- clicks off and back. Re-emit the current selection (dt.gui.selection raises
  -- selection-changed on both its clear+select) to force that module to refresh
  -- live. Our own selection-changed handler runs force=false, so the
  -- last_remote_load guard makes this a no-op for Flickr — no extra getInfo.
  if dt.gui and dt.gui.selection then
    local sel = dt.gui.selection()
    dt.gui.selection(sel)
  end
  panel_remote_label.label = string.format(_("Flickr: pulled %s from Flickr"), table.concat(changed, ", "))
  dt.print(panel_remote_label.label)
end

-- Conflict-resolution comparison for title/description (issue #22). Reads the
-- linked photo's current title/description via flickr.photos.getInfo and shows
-- them side by side against the local image, then classifies the field group with
-- a three-way (baseline/local/remote) merge so the user is told whether to push
-- (the "sync title/description" button), pull (the "pull title/description from
-- Flickr" button), or leave it (skip). A true conflict — both the local image and
-- the Flickr photo changed since the last publish — is detected via the stored
-- title_description fingerprint, so blindly pushing or pulling no longer silently
-- clobbers the other side's edit. Read-only: it never writes locally or remotely;
-- it only reports. A panel_sets.* method (not a top-level local) to stay under the
-- main chunk's local ceiling. Live-gated (needs in-app verify).
function panel_sets.compare_remote_meta()
  local acc, photo_id, image = panel_current.account, panel_current.photo_id, panel_current.image
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image before comparing with Flickr."))
    return
  end
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before comparing with Flickr."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end
  local sync = master_sync_fields()
  if not sync.title and not sync.description then
    dt.print(_("Flickr: title/description sync disabled in Lua Options."))
    return
  end

  local body, err = __dtrmflickr_call("flickr.photos.getInfo", function()
    return rest.call(api_key, api_secret, acc, "flickr.photos.getInfo", { photo_id = photo_id })
  end, { coalesce_key = "panel-compare:" .. tostring(photo_id) })
  if not body then
    local kind = remote_pull.classify_error(err)
    if kind == "deleted" then
      panel_remote_label.label = _("Flickr: photo no longer exists on Flickr (deleted/removed)")
      dt.print(_("Flickr: this photo no longer exists on Flickr; nothing to compare."))
    else
      panel_remote_label.label = _("Flickr: compare failed")
      dt.print(string.format(_("Flickr: could not read remote photo: %s"), tostring(err)))
    end
    return
  end

  local remote = remote_pull.parse_info(body)
  if not remote then
    panel_remote_label.label = _("Flickr: compare failed")
    dt.print(_("Flickr: could not parse the remote photo info."))
    return
  end

  -- Compute fingerprints with the SAME per-field toggles the push/pull paths use, so
  -- the verdict matches what those buttons would actually do.
  local local_fp = (effective_metadata_fingerprints(image, sync) or {}).title_description
  local remote_fp = metadata.fingerprints_from_values({
    include_title_description = true,
    title = sync.title and (remote.title or "") or nil,
    description = sync.description and (remote.description or "") or nil,
  }).title_description
  local stored_fp = state.get_fingerprint(image, acc.nsid, "title_description")
  local status = remote_pull.classify_change(stored_fp, local_fp, remote_fp)

  local fields = {}
  if sync.title then
    fields[#fields + 1] = {
      label = _("title"),
      local_value = metadata.image_title(image, image and image.filename or ""),
      remote = remote.title or "",
    }
  end
  if sync.description then
    fields[#fields + 1] = {
      label = _("description"),
      local_value = image and image.description or "",
      remote = remote.description or "",
    }
  end

  panel_remote_label.label = remote_pull.conflict_summary(status, fields)
  dt.print(panel_remote_label.label)
end

-- Single-image GPS / date-taken resend (issue #18). Mirrors sync_panel_meta /
-- sync_panel_tags: pushes only the darktable GPS location and/or date-taken to
-- an already-published photo via setDates + geo.setLocation, with no pixel
-- re-upload. Each field is independently gated by its master sync toggle and by
-- whether the image actually carries that value; per-field success clears the
-- matching needs-sync reason and refreshes its stored fingerprint.
function panel_sets.sync_geo_date()
  local acc, photo_id, image = panel_current.account, panel_current.photo_id, panel_current.image
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image before syncing GPS/date."))
    return
  end
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before syncing GPS/date."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end

  local sync = master_sync_fields()
  local date_taken = sync.date_taken and metadata.image_date_taken(image) or nil
  local lat, lon = nil, nil
  if sync.gps then lat, lon = metadata.image_location(image) end

  local plan = metadata.geo_date_resend_plan(sync, date_taken, lat, lon)
  -- "strip GPS on resend" can act even when "sync GPS location" is off, so derive
  -- the geo op independently and gate on it rather than only on plan.send_gps (#23).
  local geo_action = metadata.geo_resend_action(sync.gps, sync.strip_gps, lat ~= nil and lon ~= nil)
  if not sync.date_taken and not sync.gps and not sync.strip_gps then
    dt.print(_("Flickr: GPS/date sync disabled in Lua Options."))
    return
  end
  if not plan.send_date and geo_action == "skip" then
    dt.print(_("Flickr: selected image has no GPS/date taken to sync."))
    return
  end

  local fingerprints = effective_metadata_fingerprints(image, sync)
  local done, failed = {}, {}

  if plan.send_date then
    local ok, err = __dtrmflickr_call("flickr.photos.setDates", function()
      return rest.photos_set_dates(api_key, api_secret, acc, photo_id, date_taken, 0)
    end)
    if ok then
      state.clear_reason(image, acc.nsid, "date_taken")
      store_metadata_fingerprints(image, acc.nsid, fingerprints, { "date_taken" })
      done[#done + 1] = _("date taken")
    else
      state.mark_reason(image, acc.nsid, "date_taken")
      failed[#failed + 1] = _("date taken") .. ": " .. tostring(err)
    end
  end

  if geo_action ~= "skip" then
    local geo_method = geo_action == "remove"
      and "flickr.photos.geo.removeLocation" or "flickr.photos.geo.setLocation"
    local friendly = geo_action == "remove" and _("GPS location (stripped)") or _("GPS location")
    local ok, err = __dtrmflickr_call(geo_method, function()
      if geo_action == "remove" then
        return rest.photos_geo_remove_location(api_key, api_secret, acc, photo_id)
      end
      return rest.photos_geo_set_location(api_key, api_secret, acc, photo_id, lat, lon, 16)
    end)
    if ok then
      state.clear_reason(image, acc.nsid, "gps")
      if geo_action == "send" then
        store_metadata_fingerprints(image, acc.nsid, fingerprints, { "gps" })
      end
      done[#done + 1] = friendly
    else
      state.mark_reason(image, acc.nsid, "gps")
      failed[#failed + 1] = friendly .. ": " .. tostring(err)
    end
  end

  if #done > 0 then state.set_metadata_published_at(image, acc.nsid) end
  panel_sets.refresh_publish_state_label(image, acc, photo_id)

  if #failed == 0 then
    local msg = string.format(_("Flickr: synced %s."), table.concat(done, ", "))
    panel_remote_label.label = msg
    dt.print(msg)
    load_remote_settings(api_key, api_secret, acc, photo_id)
  elseif #done == 0 then
    panel_remote_label.label = _("Flickr: GPS/date sync failed")
    dt.print(_("Flickr: GPS/date sync failed: ") .. table.concat(failed, "; "))
  else
    panel_remote_label.label = _("Flickr: GPS/date partially synced")
    dt.print(string.format(_("Flickr: synced %s; failed %s"),
      table.concat(done, ", "), table.concat(failed, "; ")))
    load_remote_settings(api_key, api_secret, acc, photo_id)
  end
end

-- Permanently delete the selected published photo from Flickr (issue #19).
--
-- Destructive and irreversible, and it needs a delete-scope token (write-only
-- tokens fail with REST code 99). Two guards before any network call: a single
-- selected published image, and the per-action "confirm permanent deletion"
-- checkbox. The checkbox is always reset afterwards so each deletion is a fresh,
-- deliberate act. On success the local mapping is fully forgotten
-- (state.clear_account) so the photo reads as unpublished; a permission failure
-- is surfaced with guidance to re-login with delete permission enabled rather
-- than as a generic error, and the local mapping is left intact because the
-- remote photo still exists.
function panel_sets.delete_selected()
  local acc, photo_id, image = panel_current.account, panel_current.photo_id, panel_current.image
  local confirm_checked = panel_sets.delete_confirm and panel_sets.delete_confirm.value
  -- Always clear the confirm gate, whatever path we take, so it never stays armed.
  if panel_sets.delete_confirm then panel_sets.delete_confirm.value = false end
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image before deleting from Flickr."))
    return
  end
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before deleting from Flickr."))
    return
  end
  if not confirm_checked then
    panel_remote_label.label = _("Flickr: check 'confirm permanent deletion' first")
    dt.print(_("Flickr: tick 'confirm permanent deletion from Flickr', then click 'delete from Flickr' again."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end

  local ok, err = __dtrmflickr_call("flickr.photos.delete", function()
    return rest.photos_delete(api_key, api_secret, acc, photo_id)
  end)
  if ok then
    state.clear_account(image, acc.nsid)
    panel_remote_label.label = string.format(_("Flickr: deleted photo %s and cleared its local link"), photo_id)
    dt.print(panel_remote_label.label)
    dt.print_log("[dtrmflickr] deleted photo " .. tostring(photo_id) .. " from Flickr")
    refresh_panel(true, false)
  else
    local _code, kind = rest.is_auth_error(err)
    if kind == "permission" then
      panel_remote_label.label = _("Flickr: delete needs delete permission — re-login enabling it")
      dt.print(_("Flickr could not delete the photo: your login lacks delete permission. "
        .. "Open Lua options, turn on 'Flickr: request delete permission on next login', then log in again."))
    else
      panel_remote_label.label = _("Flickr: delete failed")
      dt.print(_("Flickr: delete failed: ") .. tostring(err))
    end
    dt.print_log("[dtrmflickr] delete photo " .. tostring(photo_id) .. " failed: " .. tostring(err))
  end
end

-- People tagging (issues #24, #18): tag Flickr members on the selected published
-- photo. The user types one or more Flickr usernames/emails (comma- or
-- newline-separated) into panel_sets.people_entry; each is resolved to an NSID via
-- findByUsername / findByEmail, then added with flickr.photos.people.add. The
-- operation is idempotent — people already on the photo (read via
-- flickr.photos.people.getList) are skipped, and duplicate identifiers that resolve
-- to the same member collapse to a single add. Per-identifier result reporting; no
-- pixel re-upload. The pure decision logic is people.parse_identifiers / add_plan.
function panel_sets.tag_people()
  local acc, photo_id = panel_current.account, panel_current.photo_id
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one published image to tag people."))
    return
  end
  if not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before tagging people."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end

  local identifiers = people.parse_identifiers(panel_sets.people_entry and panel_sets.people_entry.text or "")
  if #identifiers == 0 then
    dt.print(_("Flickr: enter one or more Flickr usernames or emails to tag."))
    return
  end

  -- Read who is already on the photo so an idempotent re-run skips them. A failed
  -- read is non-fatal: the worst case is people.add reporting an already-tagged
  -- member as a failure, which is still surfaced per-identifier below.
  local existing = {}
  local people_list = __dtrmflickr_call("flickr.photos.people.getList", function()
    return rest.people_get_list(api_key, api_secret, acc, photo_id)
  end)
  if type(people_list) == "table" then
    for _, p in ipairs(people_list) do
      if p.nsid then existing[#existing + 1] = p.nsid end
    end
  end

  -- Resolve each identifier to an NSID via the appropriate public lookup.
  local resolved, unresolved = {}, {}
  for _, id in ipairs(identifiers) do
    local user, lookup_err
    if id.kind == "email" then
      user, lookup_err = __dtrmflickr_call("flickr.people.findByEmail", function()
        return rest.people_find_by_email(api_key, id.value)
      end)
    else
      user, lookup_err = __dtrmflickr_call("flickr.people.findByUsername", function()
        return rest.people_find_by_username(api_key, id.value)
      end)
    end
    if type(user) == "table" and user.nsid and user.nsid ~= "" then
      resolved[#resolved + 1] = { value = id.value, nsid = user.nsid }
    else
      unresolved[#unresolved + 1] = id.value .. ": " .. tostring(lookup_err or _("not found"))
    end
  end

  local plan = people.add_plan(resolved, existing)
  local added, failed = {}, {}
  for _, nsid in ipairs(plan.to_add) do
    local ok, add_err = __dtrmflickr_call("flickr.photos.people.add", function()
      return rest.people_add(api_key, api_secret, acc, photo_id, nsid)
    end)
    if ok then
      added[#added + 1] = nsid
    else
      failed[#failed + 1] = nsid .. ": " .. tostring(add_err)
    end
  end

  local parts = {}
  if #added > 0 then parts[#parts + 1] = string.format(_("tagged %d"), #added) end
  if #plan.already_present > 0 then parts[#parts + 1] = string.format(_("%d already tagged"), #plan.already_present) end
  if #unresolved > 0 then parts[#parts + 1] = string.format(_("%d not found"), #unresolved) end
  if #failed > 0 then parts[#parts + 1] = string.format(_("%d failed"), #failed) end
  local summary = #parts > 0 and table.concat(parts, ", ") or _("nothing to do")
  panel_remote_label.label = _("Flickr: people — ") .. summary
  dt.print(_("Flickr: people tagging — ") .. summary)

  local detail = {}
  for _, u in ipairs(unresolved) do detail[#detail + 1] = u end
  for _, f in ipairs(failed) do detail[#detail + 1] = f end
  if #detail > 0 then dt.print(table.concat(detail, "; ")) end

  if #added > 0 then
    panel_sets.people_entry.text = ""
    load_remote_settings(api_key, api_secret, acc, photo_id)
  end
end

----------------------------------------------------------------------
-- Tag reconciler (issue #3): side-by-side local-keyword vs Flickr-tag view
-- with explicit, confirmation-gated actions. The pure diff/plan logic lives in
-- tag_reconcile.lua; this section is only the darktable wiring.
----------------------------------------------------------------------
function panel_reconcile.reset()
  panel_reconcile.remote_tags = {}
  panel_reconcile.local_names = {}
  panel_reconcile.diff = nil
  panel_reconcile.diff_label.label = ""
  clear_widget_items(panel_reconcile.remove_widget)
  panel_reconcile.remove_widget[1] = _("(no Flickr tags)")
  panel_reconcile.remove_widget.selected = 1
end

local function reconcile_names_text(names)
  return #names > 0 and table.concat(names, ", ") or _("none")
end

function panel_reconcile.refresh(image, remote_tags)
  remote_tags = remote_tags or {}
  panel_reconcile.remote_tags = remote_tags
  local local_names = image and rules.image_keyword_names(image) or {}
  panel_reconcile.local_names = local_names
  local d = tag_reconcile.diff(local_names, remote_tags)
  panel_reconcile.diff = d
  local match_names = {}
  for _, m in ipairs(d.matching) do match_names[#match_names + 1] = m.name end
  panel_reconcile.diff_label.label = table.concat({
    string.format(_("local-only (%d): %s"), #d.local_only, reconcile_names_text(d.local_only)),
    string.format(_("Flickr-only (%d): %s"), #d.remote_only, reconcile_names_text(d.remote_only)),
    string.format(_("matching (%d): %s"), #d.matching, reconcile_names_text(match_names)),
  }, "\n")

  clear_widget_items(panel_reconcile.remove_widget)
  if #remote_tags == 0 then
    panel_reconcile.remove_widget[1] = _("(no Flickr tags)")
  else
    panel_reconcile.remove_widget[1] = _("Select a Flickr tag to remove")
    for i, name in ipairs(remote_tags) do panel_reconcile.remove_widget[i + 1] = name end
  end
  panel_reconcile.remove_widget.selected = 1
end

function panel_reconcile.target()
  local acc, photo_id, image = panel_current.account, panel_current.photo_id, panel_current.image
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image first.")); return nil
  end
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first.")); return nil
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options first.")); return nil
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret.")); return nil
  end
  return api_key, api_secret, acc, photo_id, image
end

-- Push a complete intended tag set (name list) to Flickr via setTags (a full
-- replace, hence idempotent). Then mark keyword-sync state by whether every local
-- publishable keyword ends up present on Flickr, and reload the remote view.
function panel_reconcile.apply(result_names, success_msg)
  local api_key, api_secret, acc, photo_id, image = panel_reconcile.target()
  if not api_key then return end
  local tags = tag_reconcile.encode_tags(result_names)
  local ok, err = __dtrmflickr_call("flickr.photos.setTags", function()
    return rest.photos_set_tags(api_key, api_secret, acc, photo_id, tags)
  end)
  if ok then
    state.set_metadata_published_at(image, acc.nsid)
    local present = {}
    for _, n in ipairs(result_names) do present[tag_reconcile.match_key(n)] = true end
    local all_local_present = true
    for _, n in ipairs(rules.image_keyword_names(image) or {}) do
      if not present[tag_reconcile.match_key(n)] then all_local_present = false; break end
    end
    if all_local_present then
      state.clear_reason(image, acc.nsid, "keywords")
      store_metadata_fingerprints(image, acc.nsid,
        effective_metadata_fingerprints(image, master_sync_fields()), { "keywords" })
    else
      state.mark_reason(image, acc.nsid, "keywords")
    end
    panel_sets.refresh_publish_state_label(image, acc, photo_id)
    panel_remote_label.label = success_msg
    dt.print(success_msg)
    load_remote_settings(api_key, api_secret, acc, photo_id)
  else
    state.mark_reason(image, acc.nsid, "keywords")
    panel_remote_label.label = _("Flickr: tag update failed")
    dt.print(_("Flickr: tag update failed: ") .. tostring(err))
  end
end

function panel_reconcile.add_local_only()
  local d = panel_reconcile.diff
  if not d then dt.print(_("Flickr: refresh the remote tags first.")); return end
  if #d.local_only == 0 then dt.print(_("Flickr: no local-only keywords to add.")); return end
  panel_reconcile.apply(
    tag_reconcile.plan_add_local_only(panel_reconcile.remote_tags, d.local_only),
    string.format(_("Flickr: added %d local-only keyword(s)"), #d.local_only))
end

function panel_reconcile.replace_from_local()
  local d = panel_reconcile.diff
  if not d then dt.print(_("Flickr: refresh the remote tags first.")); return end
  panel_reconcile.apply(
    tag_reconcile.plan_replace(panel_reconcile.local_names),
    _("Flickr: tags replaced from local keywords"))
end

function panel_reconcile.remove_selected()
  if not panel_reconcile.diff then dt.print(_("Flickr: refresh the remote tags first.")); return end
  local index = panel_reconcile.remove_widget.selected or 0
  local chosen = index > 1 and panel_reconcile.remote_tags[index - 1] or nil
  if not chosen then dt.print(_("Flickr: choose a Flickr tag to remove first.")); return end
  panel_reconcile.apply(
    tag_reconcile.plan_remove(panel_reconcile.remote_tags, { chosen }),
    string.format(_("Flickr: removed tag \"%s\""), chosen))
end

-- "Pull remote-only into darktable": attach the Flickr-only tags as darktable
-- keywords on the selected image. No Flickr call; explicit and additive only.
function panel_reconcile.pull_remote_only()
  local d = panel_reconcile.diff
  if not d then dt.print(_("Flickr: refresh the remote tags first.")); return end
  if (panel_current.selection_count or 0) ~= 1 or not panel_current.image then
    dt.print(_("Flickr: select exactly one image first.")); return
  end
  local names = tag_reconcile.plan_pull_remote_only(d.remote_only)
  if #names == 0 then dt.print(_("Flickr: no Flickr-only tags to pull.")); return end
  local image = panel_current.image
  local added = 0
  for _, name in ipairs(names) do
    local tag = dt.tags.find and dt.tags.find(name) or nil
    if not tag and dt.tags.create then tag = dt.tags.create(name) end
    if tag then
      if image.attach_tag then image:attach_tag(tag) else dt.tags.attach(tag, image) end
      added = added + 1
    end
  end
  panel_remote_label.label = string.format(_("Flickr: pulled %d tag(s) into darktable"), added)
  dt.print(panel_remote_label.label)
  -- Local keywords changed; recompute the diff against the same remote tags so
  -- the panel reflects the new state without a remote round trip.
  panel_reconcile.refresh(image, panel_reconcile.remote_tags)
end

function panel_sets.refresh_publish_state_label(image, acc, photo_id)
  if not image or not photo_id then
    panel_sets.publish_label.label = panel_helpers.publish_state_label("unpublished", nil, nil, _)
    if panel_sets.dashboard_label then
      panel_sets.dashboard_label.label = panel_helpers.publish_dashboard(
        { { status = "unpublished" } }, { translate = _ }).text
    end
    return "unpublished"
  end
  if not acc then
    panel_sets.publish_label.label = _("publish state: log in to evaluate")
    if panel_sets.dashboard_label then
      panel_sets.dashboard_label.label = _("Flickr dashboard: log in to evaluate")
    end
    return "unknown"
  end
  local status, published_at, _photo_id, reasons = state.evaluate_publish_state(image, acc.nsid, {
    metadata_fingerprints = effective_metadata_fingerprints and effective_metadata_fingerprints(image, master_sync_fields()) or nil,
  })
  panel_sets.publish_label.label = panel_helpers.publish_state_label(status, published_at, reasons, _)
  -- Reuse the just-computed verdict (no extra evaluate) for the single-image
  -- dashboard; the whole-selection roll-up is driven by scan_selected_publish_state.
  if panel_sets.dashboard_label then
    panel_sets.dashboard_label.label = panel_helpers.publish_dashboard({
      { status = status, reasons = reasons, published_at = published_at,
        uploaded_at = state.get_uploaded_at(image, acc.nsid) },
    }, { translate = _ }).text
  end
  return status, published_at, reasons
end

function panel_sets.mark_needs_republish()
  local acc, photo_id, image = panel_current.account, panel_current.photo_id, panel_current.image
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image before marking sync state."))
    return
  end
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before marking sync state."))
    return
  end
  state.mark_reason(image, acc.nsid, "image")
  panel_sets.publish_label.label = panel_helpers.publish_state_label("needs-republish", state.get_published_at(image, acc.nsid), state.get_reasons(image, acc.nsid), _)
  dt.print(_("Flickr: marked selected photo as needing sync."))
end

function panel_sets.clear_needs_republish()
  local acc, photo_id, image = panel_current.account, panel_current.photo_id, panel_current.image
  if (panel_current.selection_count or 0) ~= 1 then
    dt.print(_("Flickr: select exactly one image before clearing sync state."))
    return
  end
  if not image or not photo_id then
    dt.print(_("Flickr: select a published image first."))
    return
  end
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before clearing sync state."))
    return
  end
  state.set_published_at(image, acc.nsid, image.change_timestamp or nil)
  panel_sets.refresh_publish_state_label(image, acc, photo_id)
  dt.print(_("Flickr: cleared selected photo's needs-sync marker."))
end

-- "mark as published" (issue #17): re-mark the linked photo(s) in the current
-- selection as published/current without re-uploading pixels. Reconciles drifted
-- state — refreshes the publish stamps, clears needs-sync, and snapshots the
-- current metadata fingerprints so the photo stays "current" instead of drifting
-- back to needs-sync/unknown. Unlinked images are skipped and reported. Works on
-- a multi-selection, not just a single image like "clear needs sync".
function panel_sets.mark_published_selection()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection == 0 then
    dt.print(_("Flickr: select one or more linked images before marking as published."))
    return
  end
  local acc = load_token()
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before marking as published."))
    return
  end
  local sync = master_sync_fields()
  local marked, skipped = 0, 0
  for _, image in ipairs(selection) do
    local fingerprints = effective_metadata_fingerprints
      and effective_metadata_fingerprints(image, sync) or nil
    if state.mark_published(image, acc.nsid, image.change_timestamp or nil, fingerprints) then
      marked = marked + 1
    else
      skipped = skipped + 1
    end
  end
  refresh_panel(true, false)
  panel_remote_label.label = string.format(
    _("Flickr: marked %d photo(s) as published (%d not linked, skipped)"), marked, skipped)
  dt.print(panel_remote_label.label)
end

function panel_sets.scan_selected_publish_state()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection == 0 then
    dt.print(_("Flickr: select one or more images before scanning sync state."))
    return
  end
  local acc = load_token()
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before scanning sync state."))
    return
  end
  local counts = { ["needs-republish"] = 0, current = 0, unknown = 0, unpublished = 0 }
  local field_tally = {}
  local entries = {}
  local sync = master_sync_fields()
  for _, image in ipairs(selection) do
    local status, published_at, _photo_id, reasons = state.evaluate_publish_state(image, acc.nsid, {
      metadata_fingerprints = effective_metadata_fingerprints and effective_metadata_fingerprints(image, sync) or nil,
    })
    counts[status] = (counts[status] or 0) + 1
    entries[#entries + 1] = {
      status = status, reasons = reasons, published_at = published_at,
      uploaded_at = state.get_uploaded_at(image, acc.nsid),
    }
    -- Tally each distinct diff reason once per image so the per-field breakdown
    -- counts photos, not duplicate reason tags on a single photo.
    local seen = {}
    for _, reason in ipairs(reasons or {}) do
      if not seen[reason] then
        seen[reason] = true
        field_tally[reason] = (field_tally[reason] or 0) + 1
      end
    end
  end
  -- Persist the roll-up into the panel's dashboard label (issue #7) so the
  -- scan result stays visible instead of only flashing as a toast.
  if panel_sets.dashboard_label then
    panel_sets.dashboard_label.label = panel_helpers.publish_dashboard(entries, { translate = _ }).text
  end
  refresh_panel(true, false)
  dt.print(string.format(_("Flickr: scanned %d selected photo(s): %d need sync, %d current, %d unknown, %d unpublished"),
    #selection, counts["needs-republish"] or 0, counts.current or 0, counts.unknown or 0, counts.unpublished or 0))
  local breakdown = state.describe_reason_tally and state.describe_reason_tally(field_tally) or ""
  if breakdown ~= "" then
    dt.print(string.format(_("Flickr: fields needing sync: %s"), breakdown))
  end
end

-- Batch / multi-select metadata-only push (issue #18, scope folded in from #11).
-- For each selected published photo this resends only the metadata fields that
-- BOTH drifted (a needs-sync reason is present) AND are enabled by the master
-- sync toggles — title/description (setMeta), keywords (setTags), GPS
-- (geo.setLocation), date taken (setDates) — with no pixel re-upload. It mirrors
-- the single-image sync buttons but loops the selection and reports per-photo
-- outcomes plus a per-field tally. Photos with no linked Flickr id, or with
-- nothing enabled-and-changed, are skipped (never re-uploaded).
function panel_sets.push_selected_metadata()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection == 0 then
    dt.print(_("Flickr: select one or more images before pushing metadata."))
    return
  end
  local acc = load_token()
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before pushing metadata."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end
  local sync = master_sync_fields()

  local pushed, unchanged, unlinked, failed_photos = 0, 0, 0, 0
  local field_tally = {}      -- friendly field name -> photos pushed
  local fail_notes = {}

  for _, image in ipairs(selection) do
    local photo_id = state.get_photo_id(image, acc.nsid)
    if not photo_id then
      unlinked = unlinked + 1
    else
      local fingerprints = effective_metadata_fingerprints(image, sync)
      local _status, _pub, _pid, reasons = state.evaluate_publish_state(image, acc.nsid, {
        metadata_fingerprints = fingerprints,
      })
      local plan = metadata.metadata_resend_plan(sync, reasons)
      if not plan.any then
        unchanged = unchanged + 1
      else
        local photo_ok, photo_failed = false, false

        local function push(field, reason, friendly, method, fn)
          local ok, err = __dtrmflickr_call(method, fn)
          if ok then
            state.clear_reason(image, acc.nsid, reason)
            store_metadata_fingerprints(image, acc.nsid, fingerprints, { reason })
            field_tally[reason] = (field_tally[reason] or 0) + 1
            photo_ok = true
          else
            state.mark_reason(image, acc.nsid, reason)
            photo_failed = true
            fail_notes[#fail_notes + 1] = string.format("%s/%s: %s",
              tostring(photo_id), friendly, tostring(err))
          end
        end

        if plan.send_meta then
          local title = sync.title and (image.title or "") or nil
          local description = sync.description and (image.description or "") or nil
          push("title_description", "title_description", _("title/description"),
            "flickr.photos.setMeta", function()
              return rest.photos_set_meta(api_key, api_secret, acc, photo_id, title, description)
            end)
        end
        if plan.send_tags then
          local tags = rules.image_keyword_tags(image) or ""
          push("keywords", "keywords", _("keywords"),
            "flickr.photos.setTags", function()
              return rest.photos_set_tags(api_key, api_secret, acc, photo_id, tags)
            end)
        end
        if plan.send_date then
          local date_taken = metadata.image_date_taken(image)
          push("date_taken", "date_taken", _("date taken"),
            "flickr.photos.setDates", function()
              return rest.photos_set_dates(api_key, api_secret, acc, photo_id, date_taken, 0)
            end)
        end
        if plan.send_gps then
          local lat, lon = metadata.image_location(image)
          push("gps", "gps", _("GPS location"),
            "flickr.photos.geo.setLocation", function()
              return rest.photos_geo_set_location(api_key, api_secret, acc, photo_id, lat, lon, 16)
            end)
        end

        if photo_ok then
          state.set_metadata_published_at(image, acc.nsid)
          pushed = pushed + 1
        end
        if photo_failed then failed_photos = failed_photos + 1 end
      end
    end
  end

  refresh_panel(true, false)
  dt.print(string.format(
    _("Flickr: metadata push — %d updated, %d unchanged, %d not linked, %d with errors (of %d selected)"),
    pushed, unchanged, unlinked, failed_photos, #selection))
  local breakdown = state.describe_reason_tally and state.describe_reason_tally(field_tally) or ""
  if breakdown ~= "" then
    dt.print(string.format(_("Flickr: fields pushed: %s"), breakdown))
  end
  if #fail_notes > 0 then
    dt.print(_("Flickr: metadata push errors: ") .. table.concat(fail_notes, "; "))
  end
end

-- Remove the Flickr location (geo data) from every selected published photo
-- (issue #23) — the explicit per-photo "remove location" / geo-privacy override.
-- This is a deliberate one-off action, distinct from the "strip GPS on resend"
-- toggle that strips automatically on upload/resend. removeLocation is idempotent
-- (rest.photos_geo_remove_location treats Flickr error 2 "no location" as success),
-- so re-running it over a mixed selection is safe. Photos with no linked Flickr id
-- are skipped (never touched). On success the "gps" needs-sync reason is cleared.
function panel_sets.remove_geo_location()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection == 0 then
    dt.print(_("Flickr: select one or more published images before removing location."))
    return
  end
  local acc = load_token()
  if not acc then
    dt.print(_("Flickr: log in from Lua Options before removing location."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end

  local removed, unlinked, failed = 0, 0, 0
  local fail_notes = {}
  for _, image in ipairs(selection) do
    local photo_id = state.get_photo_id(image, acc.nsid)
    if not photo_id then
      unlinked = unlinked + 1
    else
      local ok, err = __dtrmflickr_call("flickr.photos.geo.removeLocation", function()
        return rest.photos_geo_remove_location(api_key, api_secret, acc, photo_id)
      end)
      if ok then
        state.clear_reason(image, acc.nsid, "gps")
        removed = removed + 1
      else
        failed = failed + 1
        fail_notes[#fail_notes + 1] = string.format("%s: %s", tostring(photo_id), tostring(err))
      end
    end
  end

  refresh_panel(true, false)
  dt.print(string.format(
    _("Flickr: remove location — %d cleared, %d not linked, %d with errors (of %d selected)"),
    removed, unlinked, failed, #selection))
  if #fail_notes > 0 then
    dt.print(_("Flickr: remove location errors: ") .. table.concat(fail_notes, "; "))
  end
end

-- Clear the ambiguous-candidate picker (issue #16).
function panel_sets.clear_candidates()
  panel_sets.candidate_ids = {}
  panel_sets.candidate_image = nil
  panel_sets.candidate_account_nsid = nil
  if panel_sets.candidate_widget then
    clear_widget_items(panel_sets.candidate_widget)
    panel_sets.candidate_widget.selected = 0
  end
end

-- Fill the picker with the ambiguous candidates for a single image so the user
-- can choose one and click "link chosen candidate" (issue #16).
function panel_sets.populate_candidates(image, account_nsid, candidates)
  panel_sets.candidate_ids = {}
  panel_sets.candidate_image = image
  panel_sets.candidate_account_nsid = account_nsid
  clear_widget_items(panel_sets.candidate_widget)
  for i, candidate in ipairs(candidates or {}) do
    panel_sets.candidate_widget[i] = claim.format_candidate_label(candidate, i)
    panel_sets.candidate_ids[i] = candidate.id
  end
  panel_sets.candidate_widget.selected = #panel_sets.candidate_ids > 0 and 1 or 0
end

-- "link chosen candidate": commit the picker selection as the image's link.
function panel_sets.link_candidate()
  local image = panel_sets.candidate_image
  local account_nsid = panel_sets.candidate_account_nsid
  local index = panel_sets.candidate_widget and panel_sets.candidate_widget.selected or 0
  local photo_id = index and panel_sets.candidate_ids[index]
  if not image or not account_nsid or not photo_id then
    dt.print(_("Flickr: no candidate selected. Click \"claim existing\" on one image first."))
    return
  end
  state.set_photo_id(image, account_nsid, photo_id)
  panel_sets.clear_candidates()
  panel_remote_label.label = string.format(_("Flickr: linked to chosen candidate %s"), photo_id)
  dt.print(panel_remote_label.label)
  refresh_panel(true, http.quiet_rest_available())
end

-- Batch claim from a pasted list of photo IDs/URLs, mapped positionally onto the
-- selected images (issue #16). Does not search Flickr; the user supplies the IDs.
function panel_sets.batch_claim_from_list()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection == 0 then
    dt.print(_("Flickr: select the images to claim, then paste their Flickr IDs/URLs in order."))
    return
  end
  local acc = load_token()
  local account_nsid = acc and acc.nsid or state.get_any_photo_id(selection[1])
  if not account_nsid or account_nsid == "" then
    dt.print(_("Flickr: log in first, or select photos that already have a Flickr link."))
    return
  end
  local ids = claim.parse_photo_id_list(panel_sets.batch_claim_entry.text)
  if #ids == 0 then
    dt.print(_("Flickr: no Flickr photo IDs or URLs found in the list."))
    return
  end
  local plan = claim.plan_batch_claim(selection, ids)
  local linked = 0
  for _, pair in ipairs(plan.pairs) do
    state.set_photo_id(pair.image, account_nsid, pair.id)
    linked = linked + 1
    dt.print(string.format(_("Flickr: linked %s to photo %s"),
      (pair.image and pair.image.filename) or "image", pair.id))
  end
  panel_sets.batch_claim_entry.text = ""
  panel_remote_label.label = string.format(
    _("Flickr: batch claim linked %d photo(s) (%d image(s) left over, %d ID(s) left over)"),
    linked, plan.leftover_images, plan.leftover_ids)
  dt.print(panel_remote_label.label)
  refresh_panel(true, false)
end

local function claim_existing_selection()
  local selection = dt.gui.selection and dt.gui.selection() or {}
  if #selection == 0 then
    dt.print(_("Flickr: select one or more images to claim existing Flickr photos."))
    return
  end
  local acc = load_token()
  if not acc then
    dt.print(_("Flickr: log in before claiming existing photos."))
    return
  end
  local api_key, api_secret = get_credentials()
  if not api_key or not api_secret then
    dt.print(_("Flickr: missing API key/secret."))
    return
  end

  -- Single image: if there is no confident unique match but Flickr returned
  -- candidates, surface them in the picker instead of silently skipping so the
  -- user can pick the right one (issue #16).
  if #selection == 1 then
    panel_sets.clear_candidates()
    local image = selection[1]
    local result = __dtrmflickr_call("flickr.photos.search", function()
      return claim.collect_candidates_for_image(api_key, api_secret, acc, image)
    end)
    if type(result) ~= "table" then
      dt.print(string.format(_("Flickr: could not search %s: %s"),
        (image and image.filename) or "image", tostring(result)))
      return
    end
    if result.match then
      state.set_photo_id(image, acc.nsid, result.match.id)
      panel_remote_label.label = string.format(_("Flickr: linked %s to photo %s (%s)"),
        (image and image.filename) or "image", result.match.id, result.reason)
      dt.print(panel_remote_label.label)
      refresh_panel(true)
      return
    end
    if result.transient then
      dt.print(string.format(_("Flickr: could not search %s: %s"),
        (image and image.filename) or "image", result.transient))
      return
    end
    if result.candidates and #result.candidates > 0 then
      panel_sets.populate_candidates(image, acc.nsid, result.candidates)
      panel_remote_label.label = string.format(
        _("Flickr: %d possible match(es) for %s (%s); choose one below and click \"link chosen candidate\""),
        #result.candidates, (image and image.filename) or "image", tostring(result.reason))
      dt.print(panel_remote_label.label)
      return
    end
    if result.errors and #result.errors > 0 then
      dt.print(string.format(_("Flickr: could not search %s: %s"),
        (image and image.filename) or "image", table.concat(result.errors, "; ")))
      return
    end
    panel_remote_label.label = string.format(_("Flickr: no match found for %s (%s)"),
      (image and image.filename) or "image", tostring(result.reason))
    dt.print(panel_remote_label.label)
    return
  end

  panel_sets.clear_candidates()
  local counts = { claimed = 0, skipped = 0, error = 0 }
  for _index, image in ipairs(selection) do
    local status, detail = __dtrmflickr_call("flickr.photos.search", function()
      return claim.claim_existing_for_image(api_key, api_secret, acc, image)
    end)
    -- The queue returns (nil, err) when a transient claim search exhausted its
    -- retries; treat that as an error rather than indexing counts[nil].
    if status == nil then status = "error" end
    counts[status] = (counts[status] or 0) + 1
    local file = image and image.filename or "image"
    if status == "claimed" then
      dt.print(string.format(_("Flickr: linked %s to photo %s"), file, detail))
    elseif status == "error" then
      dt.print(string.format(_("Flickr: could not search %s: %s"), file, detail))
    else
      dt.print(string.format(_("Flickr: skipped %s: %s"), file, detail))
    end
  end
  panel_remote_label.label = string.format(_("Flickr: claim existing done (%d linked, %d skipped, %d error(s))"),
    counts.claimed or 0, counts.skipped or 0, counts.error or 0)
  refresh_panel(true)
end

function refresh_panel(force, fetch_remote)
  if not force and not panel_is_visible() then return end
  fetch_remote = fetch_remote == true

  local selection = dt.gui.selection and dt.gui.selection() or {}
  local image = selection[1]
  -- Drop a stale ambiguous-candidate picker when the selection moves off the
  -- image it was populated for (issue #16).
  if panel_sets.candidate_image and (#selection ~= 1 or panel_sets.candidate_image ~= image) then
    panel_sets.clear_candidates()
  end
  -- The selection changed, so disarm any pending two-click batch-save confirm
  -- (issue #49) and refresh the batch-mode indicator (blank for 0/1 selected).
  panel_sets.batch_save_armed = nil
  if panel_sets.batch_indicator_label then
    panel_sets.batch_indicator_label.label = batch_apply.batch_indicator(#selection, _)
  end
  panel_current = { image = image, account = nil, photo_id = nil, selection_count = #selection, remote_loaded = false }
  if not image then
    panel_sets.update_photo_link_buttons(selection, nil, nil)
    panel_sets.refresh_url_actions(selection, nil, nil)
    panel_status_label.label = _("no image selected")
    panel_file_label.label = ""
    panel_account_label.label = ""
    panel_photo_label.label = ""
    panel_sets.publish_label.label = ""
    panel_sets_label.label = ""
    panel_sets.status_label.label = ""
    panel_sets.clear_current_choices()
    panel_reset_remote("")
    return
  end

  local acc = load_token()
  -- Header selection summary (issue #85): for >1 selected show how many are
  -- published vs not, so the batch shape is visible before a batch action. The
  -- resolver reads the stored photo id for the active account (or any account
  -- when logged out) so the count matches what a batch action would touch.
  panel_status_label.label = panel_helpers.selection_summary(selection, function(img)
    if acc then return state.get_photo_id(img, acc.nsid) end
    local _nsid, pid = state.get_any_photo_id(img)
    return pid
  end, _)
  panel_file_label.label = string.format(_("file: %s"), image.filename or "?")

  if not acc then
    local tag_account_nsid, tagged_photo_id = state.get_any_photo_id(image)
    panel_current = { image = image, account = nil, photo_id = tagged_photo_id, selection_count = #selection, remote_loaded = false }
    panel_sets.update_photo_link_buttons(selection, nil, tagged_photo_id)
    panel_sets.refresh_url_actions(selection, tag_account_nsid, nil)
    panel_account_label.label = tag_account_nsid
      and string.format(_("account: %s (not logged in)"), tag_account_nsid)
      or _("account: not logged in")
    panel_photo_label.label = tagged_photo_id
      and string.format(_("photo: %s"), tagged_photo_id)
      or _("photo: not published")
    panel_sets.refresh_publish_state_label(image, nil, tagged_photo_id)
    panel_sets_label.label = ""
    panel_sets.clear_current_choices()
    if not tagged_photo_id then
      panel_reset_remote(_("Flickr: no stored photo ID tag; nothing to fetch"))
      return
    end
    if not fetch_remote then
      panel_reset_remote(_("Flickr: stored photo ID tag found; click refresh to load remote settings"))
      return
    end
    local api_key = dt.preferences.read(PLUGIN, "api_key", "string")
    if not api_key or api_key == "" then
      panel_reset_remote(_("Flickr: API key required for public photo info"))
      return
    end
    local lr = panel_sets.last_remote_load
    if not force and lr and lr.image == image and lr.photo_id == tagged_photo_id and lr.nsid == nil then
      panel_current.remote_loaded = true  -- same photo already loaded; don't re-hit Flickr
      return
    end
    load_remote_settings(api_key, nil, nil, tagged_photo_id)
    return
  end

  local photo_id = state.get_photo_id(image, acc.nsid)
  local sets = state.get_sets(image, acc.nsid)
  panel_current = { image = image, account = acc, photo_id = photo_id, selection_count = #selection, remote_loaded = false }
  panel_sets.update_photo_link_buttons(selection, acc, photo_id)
  panel_sets.refresh_url_actions(selection, acc.nsid, acc.nsid)
  panel_account_label.label = string.format(_("account: %s"), acc.username or acc.nsid)
  panel_photo_label.label = photo_id
    and string.format(_("photo: %s"), photo_id)
    or _("photo: not published")
  panel_sets.refresh_publish_state_label(image, acc, photo_id)
  panel_sets_label.label = panel_sets.format_memberships(sets)
  panel_sets.update_current_choices(image, acc.nsid)
  if not photo_id then
    panel_reset_remote(_("Flickr: no stored photo ID; nothing to fetch"))
    return
  end
  if not fetch_remote then
    panel_reset_remote(_("Flickr: stored photo ID found; click refresh to load remote settings"))
    return
  end

  -- Skip the remote fetch when this exact (image, photo_id, account) is already
  -- loaded and the caller did not force a refresh (the explicit refresh button
  -- and post-edit refreshes pass force=true). Stops re-selecting the same
  -- published photo from re-issuing getInfo + getPerms + getContentType.
  local lr = panel_sets.last_remote_load
  if not force and lr and lr.image == image and lr.photo_id == photo_id and lr.nsid == acc.nsid then
    panel_current.remote_loaded = true
    return
  end

  local api_key, api_secret = get_credentials()
  if api_key and api_secret then
    load_remote_settings(api_key, api_secret, acc, photo_id)
  else
    panel_reset_remote(_("Flickr: missing API key/secret"))
  end
end

