----------------------------------------------------------------------
-- Storage callbacks.
----------------------------------------------------------------------
local supported_formats = { jpg = true, jpeg = true, tif = true, tiff = true, png = true, webp = true }

local function current_privacy()
  local index = privacy_widget.selected
  if not index or index == 0 then index = settings.privacy_index_from_pref(privacy_widget.value) end
  local selected = settings.privacy_values[index] or settings.privacy_values[1]
  return {
    pref = selected.pref,
    is_public = selected.is_public,
    is_friend = selected.is_friend,
    is_family = selected.is_family,
  }
end

local function current_safety()
  local index = safety_widget.selected
  if not index or index == 0 then index = settings.safety_index_from_pref(safety_widget.value) end
  local selected = settings.safety_values[index] or settings.safety_values[1]
  return {
    pref = selected.pref,
    flickr_value = selected.flickr_value,
  }
end

local function current_content_type()
  local index = content_type_widget.selected
  if not index or index == 0 then index = settings.content_type_index_from_pref(content_type_widget.value) end
  local selected = settings.content_type_values[index] or settings.content_type_values[1]
  return {
    pref = selected.pref,
    flickr_value = selected.flickr_value,
  }
end

local function current_license()
  local index = license_widget.selected
  if not index or index == 0 then index = settings.license_index_from_pref(license_widget.value) end
  local selected = settings.license_values[index] or settings.license_values[1]
  return {
    pref = selected.pref,
    flickr_value = selected.flickr_value,
  }
end

local function current_permissions()
  local comment_index = comment_perm_widget.selected
  if not comment_index or comment_index == 0 then comment_index = settings.permission_index_from_pref(comment_perm_widget.value) end
  local addmeta_index = addmeta_perm_widget.selected
  if not addmeta_index or addmeta_index == 0 then addmeta_index = settings.permission_index_from_pref(addmeta_perm_widget.value) end
  local comment = settings.permission_values[comment_index] or settings.permission_values[4]
  local addmeta = settings.permission_values[addmeta_index] or settings.permission_values[4]
  return {
    comment_pref = comment.pref,
    addmeta_pref = addmeta.pref,
    perm_comment = comment.flickr_value,
    perm_addmeta = addmeta.flickr_value,
  }
end

-- Resolve the album field(s) into a list of photoset targets for finalize.
-- Both the "existing album" and "create new album" fields accept a
-- comma-separated list, so a single export can land in several albums at once
-- (issue #27). Returns { mode, targets, errors } where targets are deduped and
-- errors lists unresolved/ambiguous existing-album references.
local function current_album()
  local mode = album_mode_widget.selected or 1
  if mode == 2 then
    local existing_value = album_input_value()
    if existing_value == "" then return { mode = "none", targets = {}, errors = {} } end
    local targets, errors = albums.resolve_existing(existing_value, function(part)
      return albums.find_match(album_cache, part)
    end)
    return { mode = "multi", targets = targets, errors = errors }
  end
  if mode == 3 then
    local new_value = trim(album_new_entry.text or "")
    if new_value == "" then return { mode = "none", targets = {}, errors = {} } end
    local targets, errors = albums.resolve_create(new_value, function(title)
      return albums.find_exact(album_cache, title)
    end)
    return { mode = "multi", targets = targets, errors = errors }
  end
  return { mode = "none", targets = {}, errors = {} }
end

local function supported(storage, format)
  return supported_formats[format.extension] == true
end

local function initialize(storage, format, images, high_quality, extra_data)
  -- Start each export with a clean queue scoreboard so the panel's
  -- "queue: N ok/failed/retried - throttled Nx - waited X.Xs total" reflects
  -- THIS export rather than every Flickr call since darktable launched. Without
  -- this the cumulative session stats made a single earlier throttled batch
  -- haunt the panel for the rest of the session. Reset here (an export-batch
  -- boundary) rather than per queue call, so a claim/album fan-out still
  -- aggregates correctly.
  if __dtrmflickr_queue and __dtrmflickr_queue.reset_stats then
    __dtrmflickr_queue:reset_stats()
  end
  extra_data.uploaded = {}
  extra_data.failed   = {}
  extra_data.skipped  = {}
  extra_data.account  = load_token()
  extra_data.api_key, extra_data.api_secret = get_credentials()
  extra_data.privacy = current_privacy()
  extra_data.safety = current_safety()
  extra_data.content_type = current_content_type()
  extra_data.license = current_license()
  extra_data.permissions = current_permissions()
  extra_data.sync = current_sync_fields()
  extra_data.post_errors = {}
  extra_data.keyword_conflicts = {}
  extra_data.keyword_conflict_seen = {}
  extra_data.publish_stamp = state.now_stamp()
  local album_mode = album_mode_widget.selected or 1
  local wants_album = (album_mode == 2 and album_input_value() ~= "")
    or (album_mode == 3 and trim(album_new_entry.text or "") ~= "")
  if album_mode ~= 1 and wants_album and extra_data.account then
    local _sets, album_refresh_err = refresh_album_cache_for_export(extra_data.api_key, extra_data.api_secret,
      extra_data.account, { use_cache = true })
    if album_refresh_err then
      dt.print(string.format(_("Flickr: could not refresh albums before export: %s"), tostring(album_refresh_err)))
      dt.print_log(string.format("[dtrmflickr] initialize: album refresh failed: %s", tostring(album_refresh_err)))
    end
  end
  extra_data.album = current_album()
  -- Show a progress bar in darktable's background-jobs area for the whole batch
  -- (issue #2). darktable calls store() once per image in order, so the bar can
  -- fill as images complete; the per-image dt.print toast scrolls away on a
  -- large batch, this persists. No cancel button: darktable drives the export
  -- loop in C and we cannot abort it mid-batch from Lua, so offering a cancel
  -- would falsely imply we could stop the upload.
  extra_data.progress_total = #images
  if dt.gui and dt.gui.create_job then
    extra_data.progress_job = dt.gui.create_job(
      string.format(_("Flickr: uploading %d image(s)"), #images), true)
  end
  dt.print_log(string.format("[dtrmflickr] initialize: %d image(s), transport=%s, %s",
    #images, TRANSPORT, extra_data.account and ("nsid=" .. tostring(extra_data.account.nsid)) or "NOT logged in"))
  return nil
end

function effective_metadata_fingerprints(image, sync, opts)
  opts = opts or {}
  sync = sync or master_sync_fields()
  local privacy = opts.privacy or current_privacy()
  local safety = opts.safety or current_safety()
  local content_type = opts.content_type or current_content_type()
  local license = opts.license or current_license()
  local permissions = opts.permissions or current_permissions()
  local tag_names = opts.tag_names or metadata.image_tag_names(image)
  local forced = opts.forced or {}
  if not opts.skip_keyword_overrides then
    privacy, safety, content_type, license, forced = rules.apply_keyword_overrides(tag_names, privacy, safety, content_type, license)
    local private_rating_threshold = rules.should_force_private_by_rating(image)
    local private_label = rules.should_force_private_by_color_label(image)
    if private_rating_threshold or private_label then
      privacy = settings.privacy_values[1]
      forced.privacy = true
    end
  end
  local tags = sync.tags and (opts.tags ~= nil and opts.tags or rules.image_keyword_tags(image, tag_names)) or nil
  local lat, lon = nil, nil
  if sync.gps then lat, lon = metadata.image_location(image) end
  return metadata.fingerprints_from_values({
    include_keywords = sync.tags,
    include_title_description = sync.title or sync.description,
    include_gps = sync.gps,
    include_date_taken = sync.date_taken,
    title = sync.title and metadata.image_title(image, image and image.filename or "") or nil,
    description = sync.description and image and image.description or nil,
    tags = tags,
    date_taken = sync.date_taken and metadata.image_date_taken(image) or nil,
    lat = lat,
    lon = lon,
    privacy = (sync.privacy or forced.privacy) and privacy or nil,
    safety = (sync.safety or forced.safety) and safety or nil,
    content_type = (sync.content_type or forced.content_type) and content_type or nil,
    license = (sync.license or forced.license) and license or nil,
    permissions = sync.permissions and permissions or nil,
  })
end

function store_metadata_fingerprints(image, account_nsid, fingerprints, fields)
  if not image or not account_nsid or not fingerprints then return 0 end
  local selected = {}
  for _, field in ipairs(fields or state.metadata_reasons()) do
    if fingerprints[field] ~= nil then selected[field] = fingerprints[field] end
  end
  return state.set_fingerprints(image, account_nsid, selected)
end

local function should_skip_upload_by_keyword(tag_names)
  return rules.first_matching_keyword_filter(tag_names,
    rules.split_filter_list(dt.preferences.read(PLUGIN, "skip_upload_keyword_filters", "string")))
end

local function record_tag_limit_warning(extra_data, image, truncated_count)
  if not extra_data or not truncated_count or truncated_count <= 0 then return end
  extra_data.tag_limit_warnings = extra_data.tag_limit_warnings or {}
  extra_data.tag_limit_warnings[#extra_data.tag_limit_warnings + 1] = {
    image = image,
    truncated_count = truncated_count,
  }
  dt.print(string.format(_("Flickr: %s has more than %d publishable keywords; skipped %d extra tag(s)"),
    image and image.filename or "image", FLICKR_TAG_LIMIT, truncated_count))
end

local function record_post_error(extra_data, image, photo_id, action, err)
  extra_data.post_errors = extra_data.post_errors or {}
  extra_data.post_errors[#extra_data.post_errors + 1] = {
    image = image, photo_id = photo_id, error = err, action = action,
  }
  dt.print(string.format(_("Flickr: uploaded %s, but %s update failed: %s"),
    image.filename or "image", action, tostring(err)))
  dt.print_log(string.format("[dtrmflickr] store: %s update failed photo_id=%s: %s",
    action, tostring(photo_id), tostring(err)))
end

local function store(storage, image, format, filename, number, total, high_quality, extra_data)
  -- Advance the batch progress bar to "images before this one are done". Placed
  -- before the early-return guards (skip/credential) so the bar still moves for
  -- images that never upload. finalize() fills it to 100% and destroys it.
  if extra_data.progress_job and extra_data.progress_job.valid and total and total > 0 then
    extra_data.progress_job.percent = (number - 1) / total
  end
  if not extra_data.account then
    local err = _("not logged in to Flickr")
    extra_data.failed[#extra_data.failed + 1] = { image = image, filename = filename, error = err }
    dt.print(_("Flickr upload skipped: ") .. err)
    dt.print_log("[dtrmflickr] store: skipped, no account")
    return
  end
  if not extra_data.api_key or not extra_data.api_secret then
    local err = _("missing Flickr API key/secret")
    extra_data.failed[#extra_data.failed + 1] = { image = image, filename = filename, error = err }
    dt.print(_("Flickr upload skipped: ") .. err)
    dt.print_log("[dtrmflickr] store: skipped, missing API credentials")
    return
  end

  local privacy = extra_data.privacy or current_privacy()
  local safety = extra_data.safety or current_safety()
  local content_type = extra_data.content_type or current_content_type()
  local license = extra_data.license or current_license()
  local permissions = extra_data.permissions or current_permissions()
  local sync = extra_data.sync or current_sync_fields()
  local tag_names = metadata.image_tag_names(image)
  local skip_filter, skip_tag = should_skip_upload_by_keyword(tag_names)
  if skip_filter then
    extra_data.skipped = extra_data.skipped or {}
    extra_data.skipped[#extra_data.skipped + 1] = {
      image = image,
      filename = filename,
      filter = skip_filter,
      tag = skip_tag,
    }
    dt.print(string.format(_("Flickr: skipped %s because keyword '%s' matched skip-upload rule '%s'"),
      image and image.filename or "image", tostring(skip_tag or ""), tostring(skip_filter or "")))
    dt.print_log(string.format("[dtrmflickr] store: skipped by keyword file='%s' tag='%s' filter='%s'",
      tostring(filename), tostring(skip_tag or ""), tostring(skip_filter or "")))
    return
  end
  local skip_rating_threshold, skip_rating = rules.should_skip_upload_by_rating(image)
  if skip_rating_threshold then
    extra_data.skipped = extra_data.skipped or {}
    extra_data.skipped[#extra_data.skipped + 1] = {
      image = image,
      filename = filename,
      reason = "rating",
      threshold = skip_rating_threshold,
      rating = skip_rating,
    }
    dt.print(string.format(_("Flickr: skipped %s because rating %s is below upload threshold %s"),
      image and image.filename or "image", tostring(skip_rating), tostring(skip_rating_threshold)))
    dt.print_log(string.format("[dtrmflickr] store: skipped by rating file='%s' rating='%s' threshold='%s'",
      tostring(filename), tostring(skip_rating), tostring(skip_rating_threshold)))
    return
  end
  local skip_label = rules.should_skip_upload_by_color_label(image)
  if skip_label then
    extra_data.skipped = extra_data.skipped or {}
    extra_data.skipped[#extra_data.skipped + 1] = {
      image = image,
      filename = filename,
      reason = "color_label",
      label = skip_label,
    }
    dt.print(string.format(_("Flickr: skipped %s because color label '%s' matched skip-upload rule"),
      image and image.filename or "image", tostring(skip_label)))
    dt.print_log(string.format("[dtrmflickr] store: skipped by color label file='%s' label='%s'",
      tostring(filename), tostring(skip_label)))
    return
  end
  local forced, conflicts
  privacy, safety, content_type, license, forced, conflicts = rules.apply_keyword_overrides(tag_names, privacy, safety, content_type, license)
  for _, conflict in ipairs(conflicts or {}) do rules.record_keyword_conflict(extra_data, conflict) end
  local private_rating_threshold, private_rating = rules.should_force_private_by_rating(image)
  local private_label = rules.should_force_private_by_color_label(image)
  if private_rating_threshold or private_label then
    privacy = settings.privacy_values[1]
    forced.privacy = true
    if private_rating_threshold then
      dt.print_log(string.format("[dtrmflickr] store: forcing private by rating file='%s' rating='%s' threshold='%s'",
        tostring(filename), tostring(private_rating), tostring(private_rating_threshold)))
    end
    if private_label then
      dt.print_log(string.format("[dtrmflickr] store: forcing private by color label file='%s' label='%s'",
        tostring(filename), tostring(private_label)))
    end
  end
  local tags, truncated_tags = nil, 0
  if sync.tags then
    tags, truncated_tags = rules.image_keyword_tags(image)
    record_tag_limit_warning(extra_data, image, truncated_tags)
  end
  -- If this image already carries a stored Flickr photo id for the active
  -- account, a re-export must UPDATE that photo in place (Flickr replace
  -- endpoint) instead of uploading a fresh copy, which would duplicate it.
  -- Replace keeps the id/URL/comments/faves/stats; the current darktable
  -- metadata is pushed via REST below so the existing photo ends up matching
  -- what a fresh upload of this image now would produce.
  local existing_photo_id = state.get_photo_id(image, extra_data.account.nsid)
  local is_replace = existing_photo_id ~= nil and existing_photo_id ~= ""
  -- Do NOT auto-retry the pixel op. Flickr's upload endpoint is not idempotent
  -- and exposes no dedupe key, so a transient timeout *after* the pixels reached
  -- Flickr would create a duplicate photo on retry. We cannot tell "never sent"
  -- from "sent but the ack was lost" from the error string, so the safe choice
  -- is one attempt: a transient failure fails just this image (reported, the
  -- batch continues) and the user re-exports it. Replace targets a fixed
  -- photo_id and cannot duplicate, but a partial transfer is still ambiguous, so
  -- it also keeps a single attempt. The idempotent post-upload REST calls below
  -- keep their normal retry/backoff. A sleep_fn lets either endpoint resolve an
  -- async ticket via the idempotent checkTickets poll rather than reporting a
  -- false failure that would invite a duplicate-creating re-export.
  local function pixel_sleep(ms)
    if dt.control and dt.control.sleep then dt.control.sleep(math.floor(tonumber(ms) or 0)) end
  end
  local photo_id, err
  if is_replace then
    dt.print(string.format(_("Flickr: updating %d/%d — %s (photo %s)"),
      number, total, image.filename or "?", existing_photo_id))
    photo_id, err = __dtrmflickr_call("flickr.replace", function()
      return upload.replace_photo(extra_data.api_key, extra_data.api_secret,
        extra_data.account, filename, existing_photo_id, { sleep_fn = pixel_sleep })
    end, { max_attempts = 1 })
  else
    dt.print(string.format(_("Flickr: uploading %d/%d — %s"), number, total, image.filename or "?"))
    photo_id, err = __dtrmflickr_call("flickr.upload", function()
      return upload.upload_photo(extra_data.api_key, extra_data.api_secret, extra_data.account, filename, {
        title = sync.title and metadata.image_title(image, filename) or nil,
        description = sync.description and image and image.description or nil,
        tags = tags,
        is_public = (sync.privacy or forced.privacy) and privacy.is_public or nil,
        is_friend = (sync.privacy or forced.privacy) and privacy.is_friend or nil,
        is_family = (sync.privacy or forced.privacy) and privacy.is_family or nil,
        safety_level = (sync.safety or forced.safety) and safety.flickr_value or nil,
        content_type = (sync.content_type or forced.content_type) and content_type.flickr_value or nil,
        perm_comment = sync.permissions and permissions.perm_comment or nil,
        perm_addmeta = sync.permissions and permissions.perm_addmeta or nil,
        sleep_fn = pixel_sleep,
      })
    end, { max_attempts = 1 })
  end
  -- Track the worst (max) attempt count across this image's upload and its
  -- post-upload setters so the per-image result row can report how many tries
  -- the image took. Upload is max_attempts=1 (always 1); a retry only shows up
  -- when an idempotent post-upload setter rode out a transient/rate-limit error.
  local image_attempts = __dtrmflickr_queue:last_attempts()
  if photo_id then
    state.set_photo_id(image, extra_data.account.nsid, photo_id)
    state.set_image_published_at(image, extra_data.account.nsid, extra_data.publish_stamp)
    -- Record the Flickr upload date/time (issue #21). A fresh upload's
    -- authoritative dateuploaded is, within seconds, the moment we just sent it,
    -- so seed it from the local publish stamp; the panel's load-remote path later
    -- refines it with Flickr's exact value. A replace keeps the original photo's
    -- upload date on Flickr, so do NOT overwrite the stored stamp there.
    if not is_replace then
      state.set_uploaded_at(image, extra_data.account.nsid, extra_data.publish_stamp)
    end
    -- (#78) Register a durable resume record now that the photo's pixels are on
    -- Flickr (photo_id known + persisted in state.lua tags). A quit/crash before
    -- the idempotent metadata setters below finish then leaves a reconstructable
    -- remainder the next startup replays — without ever re-uploading the
    -- non-idempotent pixels (the temp file is gone and re-upload risks a
    -- duplicate). Removed once this image's metadata is confirmed clean below.
    -- Guarded: a resume-store hiccup must never break a working export.
    if __dtrmflickr_resume and __dtrmflickr_resume.add_pending then
      pcall(function()
        local ur = require("dtrmflickr.upload_resume")
        -- Seed the record with the EXISTING-album target id(s) (known up front),
        -- so a quit during the store loop (before finalize files albums) still
        -- leaves a record that re-files this already-uploaded photo into its
        -- intended sets (issue #79). A pure "create" target has no id yet and is
        -- folded in later by finalize once the photoset exists.
        local rec = ur.build_record(ur.image_key(image), extra_data.account.nsid,
          image and image.filename or filename, ur.existing_set_ids(extra_data.album))
        if rec then __dtrmflickr_resume.add_pending(rec) end
      end)
    end
    local post_failed = false
    local failed_metadata_fields = {}
    -- A replace carries no metadata (the endpoint only accepts the photo id and
    -- pixels), so push the current darktable values to the existing photo via
    -- REST, gated by the same sync/forced flags a fresh upload uses. The REST
    -- layer omits nil params, so an unsynced field is left untouched on Flickr.
    -- A fresh upload already sent these inline in its multipart body, so this
    -- block runs only for the replace path. Each push folds into the same
    -- post_failed / failed_metadata_fields / reason bookkeeping as the
    -- license/date/geo setters below.
    local function push_meta(method, reasons, action_label, fn)
      local ok, perr = __dtrmflickr_call(method, fn)
      image_attempts = math.max(image_attempts, __dtrmflickr_queue:last_attempts())
      for _, reason in ipairs(reasons) do
        if not ok then
          failed_metadata_fields[reason] = true
          state.mark_reason(image, extra_data.account.nsid, reason)
        else
          state.clear_reason(image, extra_data.account.nsid, reason)
        end
      end
      if not ok then
        post_failed = true
        record_post_error(extra_data, image, photo_id, action_label, perr)
      end
    end
    if is_replace then
      local meta_title = sync.title and metadata.image_title(image, filename) or nil
      local meta_desc = sync.description and image and image.description or nil
      if meta_title ~= nil or meta_desc ~= nil then
        push_meta("flickr.photos.setMeta", { "title_description" }, "title/description", function()
          return rest.photos_set_meta(extra_data.api_key, extra_data.api_secret,
            extra_data.account, photo_id, meta_title, meta_desc)
        end)
      end
      if sync.tags then
        push_meta("flickr.photos.setTags", { "keywords" }, "tags", function()
          return rest.photos_set_tags(extra_data.api_key, extra_data.api_secret,
            extra_data.account, photo_id, tags or "")
        end)
      end
      if sync.privacy or forced.privacy then
        -- setPerms requires the privacy triple, so it can only run when privacy
        -- is being synced; the comment/addmeta perms ride along when their own
        -- sync flag is on (nil otherwise leaves them untouched).
        local perm_reasons = { "visibility" }
        if sync.permissions then perm_reasons[#perm_reasons + 1] = "permissions" end
        push_meta("flickr.photos.setPerms", perm_reasons, "privacy/permissions", function()
          return rest.photos_set_perms(extra_data.api_key, extra_data.api_secret,
            extra_data.account, photo_id, privacy.is_public, privacy.is_friend, privacy.is_family,
            sync.permissions and permissions.perm_comment or nil,
            sync.permissions and permissions.perm_addmeta or nil)
        end)
      end
      -- A replace carries no metadata, so re-assert the safety level via
      -- setSafetyLevel, gated by the same sync/forced flag a fresh upload uses.
      local want_safety = sync.safety or forced.safety
      if want_safety then
        push_meta("flickr.photos.setSafetyLevel", { "safety" }, "safety", function()
          return rest.photos_set_safety_level(extra_data.api_key, extra_data.api_secret,
            extra_data.account, photo_id, safety.flickr_value)
        end)
      end
      if sync.content_type or forced.content_type then
        push_meta("flickr.photos.setContentType", { "content_type" }, "content type", function()
          return rest.photos_set_content_type(extra_data.api_key, extra_data.api_secret,
            extra_data.account, photo_id, content_type.flickr_value)
        end)
      end
    end
    if sync.license or forced.license then
      local license_ok, license_err = __dtrmflickr_call("flickr.photos.licenses.setLicense", function()
        return rest.photos_licenses_set_license(extra_data.api_key, extra_data.api_secret,
          extra_data.account, photo_id, license.flickr_value)
      end)
      image_attempts = math.max(image_attempts, __dtrmflickr_queue:last_attempts())
      if not license_ok then
        post_failed = true
        failed_metadata_fields.license = true
        state.mark_reason(image, extra_data.account.nsid, "license")
        record_post_error(extra_data, image, photo_id, "license", license_err)
      else
        state.clear_reason(image, extra_data.account.nsid, "license")
      end
    end

    local date_taken = sync.date_taken and metadata.image_date_taken(image) or nil
    if date_taken then
      local dates_ok, dates_err = __dtrmflickr_call("flickr.photos.setDates", function()
        return rest.photos_set_dates(extra_data.api_key, extra_data.api_secret,
          extra_data.account, photo_id, date_taken, 0)
      end)
      image_attempts = math.max(image_attempts, __dtrmflickr_queue:last_attempts())
      if not dates_ok then
        post_failed = true
        failed_metadata_fields.date_taken = true
        state.mark_reason(image, extra_data.account.nsid, "date_taken")
        record_post_error(extra_data, image, photo_id, "date", dates_err)
      else
        state.clear_reason(image, extra_data.account.nsid, "date_taken")
      end
    end

    local lat, lon = nil, nil
    if sync.gps then lat, lon = metadata.image_location(image) end
    -- Privacy-first: "strip GPS on resend" wins over "sync GPS location", so after
    -- a (re)upload we remove any location Flickr may have auto-geotagged from the
    -- file's EXIF rather than sending coordinates (issue #23).
    local geo_action = metadata.geo_resend_action(sync.gps, sync.strip_gps, lat ~= nil and lon ~= nil)
    if geo_action ~= "skip" then
      local geo_method = geo_action == "remove"
        and "flickr.photos.geo.removeLocation" or "flickr.photos.geo.setLocation"
      local geo_ok, geo_err = __dtrmflickr_call(geo_method, function()
        if geo_action == "remove" then
          return rest.photos_geo_remove_location(extra_data.api_key, extra_data.api_secret,
            extra_data.account, photo_id)
        end
        return rest.photos_geo_set_location(extra_data.api_key, extra_data.api_secret,
          extra_data.account, photo_id, lat, lon, 16)
      end)
      image_attempts = math.max(image_attempts, __dtrmflickr_queue:last_attempts())
      if not geo_ok then
        post_failed = true
        failed_metadata_fields.gps = true
        state.mark_reason(image, extra_data.account.nsid, "gps")
        record_post_error(extra_data, image, photo_id,
          geo_action == "remove" and "strip location" or "location", geo_err)
      else
        state.clear_reason(image, extra_data.account.nsid, "gps")
      end
    end
    local upload_fingerprints = effective_metadata_fingerprints(image, sync, {
      privacy = privacy,
      safety = safety,
      content_type = content_type,
      license = license,
      permissions = permissions,
      tag_names = tag_names,
      tags = tags,
      forced = forced,
      skip_keyword_overrides = true,
    })
    if post_failed then
      local published_fields = {}
      for _, field in ipairs(state.metadata_reasons()) do
        if not failed_metadata_fields[field] then published_fields[#published_fields + 1] = field end
      end
      store_metadata_fingerprints(image, extra_data.account.nsid, upload_fingerprints, published_fields)
    else
      state.set_published_at(image, extra_data.account.nsid, extra_data.publish_stamp)
      store_metadata_fingerprints(image, extra_data.account.nsid, upload_fingerprints)
    end
    -- (#78/#79) Metadata remainder confirmed for this image. Drop its resume
    -- record ONLY when the metadata is clean AND this batch has no album targets:
    -- album filing happens later in finalize, so when the export wants albums the
    -- record must survive the store loop to carry the album remainder (finalize
    -- removes it once the photo is filed). A post_failed image likewise KEEPS its
    -- record so the failed idempotent setters replay at the next startup. Guarded
    -- so it can never break the export.
    local has_album_targets = extra_data.album and extra_data.album.targets
      and #extra_data.album.targets > 0
    if not post_failed and not has_album_targets
       and __dtrmflickr_resume and __dtrmflickr_resume.remove_pending then
      pcall(function()
        local ur = require("dtrmflickr.upload_resume")
        __dtrmflickr_resume.remove_pending(ur.image_key(image), extra_data.account.nsid)
      end)
    end
    extra_data.uploaded[#extra_data.uploaded + 1] = { image = image, filename = filename, photo_id = photo_id, attempts = image_attempts, replaced = is_replace, post_failed = post_failed }
    if is_replace then
      dt.print(string.format(_("Flickr: updated %s (photo %s) in place"), image.filename or "image", photo_id))
      dt.print_log(string.format("[dtrmflickr] store: replaced '%s' -> photo_id=%s", filename, photo_id))
    else
      dt.print(string.format(_("Flickr: uploaded %s as photo %s"), image.filename or "image", photo_id))
      dt.print_log(string.format("[dtrmflickr] store: uploaded '%s' -> photo_id=%s", filename, photo_id))
    end
  else
    extra_data.failed[#extra_data.failed + 1] = { image = image, filename = filename, error = err, attempts = image_attempts }
    dt.print(string.format(_("Flickr: upload failed for %s: %s"), image.filename or "image", tostring(err)))
    dt.print_log(string.format("[dtrmflickr] store: upload failed for '%s': %s", filename, tostring(err)))
  end
end

local function finalize(storage, image_table, extra_data)
  local total = 0
  for _img in pairs(image_table) do total = total + 1 end
  local uploaded = #(extra_data.uploaded or {})
  local failed = #(extra_data.failed or {})
  local skipped = #(extra_data.skipped or {})
  local post_errors = #(extra_data.post_errors or {})
  local keyword_conflicts = #(extra_data.keyword_conflicts or {})
  local tag_limit_warnings = #(extra_data.tag_limit_warnings or {})
  local album = extra_data.album or { mode = "none", targets = {}, errors = {} }
  local album_errors = 0

  -- Unresolved / ambiguous existing-album references: only surfaced once
  -- something actually uploaded (otherwise there is nothing to file anyway).
  if uploaded > 0 then
    for _ei, e in ipairs(album.errors or {}) do
      album_errors = album_errors + 1
      dt.print(string.format(_("Flickr: album not applied for '%s': %s"), tostring(e.query or ""), tostring(e.reason or "")))
      dt.print_log(string.format("[dtrmflickr] finalize: album not applied query='%s': %s",
        tostring(e.query or ""), tostring(e.reason or "")))
    end
  end

  -- Add the uploaded photos to every resolved album target (issue #27: one
  -- export can land in multiple albums). Each target is independent: create
  -- targets make a fresh photoset (first upload as primary), existing targets
  -- add all uploads. A failure against one album does not abort the others.
  if uploaded > 0 then
    local first = extra_data.uploaded[1]
    -- (#79) Every photoset id this batch resolves (existing up front, created
    -- below). Used by the resume-record bookkeeping: fold each id into every
    -- uploaded image's resume record BEFORE its addPhoto runs (so a quit inside
    -- the loop resumes filing), and after the loop drop a record only once its
    -- image is confirmed in every batch set (and its metadata is clean).
    local batch_set_ids = {}
    -- Fold a now-known photoset id into each uploaded image's pending resume
    -- record so the album remainder is reconstructable across a restart. Guarded:
    -- a resume-store hiccup must never break album filing.
    local function fold_set_into_records(set_id)
      if not (__dtrmflickr_resume and __dtrmflickr_resume.add_pending) then return end
      pcall(function()
        local ur = require("dtrmflickr.upload_resume")
        for _, it in ipairs(extra_data.uploaded) do
          local key = ur.image_key(it.image)
          if key then
            local rec = (__dtrmflickr_resume.pending_record
              and __dtrmflickr_resume.pending_record(key, extra_data.account.nsid))
              or ur.build_record(key, extra_data.account.nsid, it.image and it.image.filename or it.filename)
            if rec then
              rec.sets = ur.normalize_sets(rec.sets, set_id)
              __dtrmflickr_resume.add_pending(rec)
            end
          end
        end
      end)
    end
    for _ti, target in ipairs(album.targets or {}) do
      local photoset_id = target.photoset_id
      if target.kind == "create" then
        -- max_attempts = 1: photosets.create is non-idempotent (see panel_sets.create);
        -- a lost-ack retry would create a duplicate album. addPhoto below stays
        -- retryable because replaying it converges (Flickr returns "already in set").
        local created_id, err = __dtrmflickr_call("flickr.photosets.create", function()
          return rest.photosets_create(extra_data.api_key, extra_data.api_secret, extra_data.account,
            target.title, first.photo_id)
        end, { max_attempts = 1 })
        photoset_id = created_id
        if photoset_id then
          state.add_set(first.image, extra_data.account.nsid, photoset_id)
          dt.print(string.format(_("Flickr: created album '%s'"), target.title))
          dt.print_log(string.format("[dtrmflickr] finalize: created photoset=%s title='%s'", photoset_id, target.title))
        else
          album_errors = album_errors + 1
          dt.print(string.format(_("Flickr: album create failed: %s"), tostring(err)))
          dt.print_log(string.format("[dtrmflickr] finalize: photoset create failed: %s", tostring(err)))
        end
      elseif target.duplicate_create and photoset_id and photoset_id ~= "" then
        dt.print(string.format(_("Flickr: album '%s' already exists; adding photos to existing album"), tostring(target.title or photoset_id)))
        dt.print_log(string.format("[dtrmflickr] finalize: create matched existing photoset=%s title='%s'",
          tostring(photoset_id), tostring(target.title or "")))
      end

      if photoset_id and photoset_id ~= "" then
        -- (#79) Persist the album intent for every uploaded image BEFORE filing,
        -- so a quit mid-loop leaves a record that re-files the not-yet-added
        -- photos into this set on restart (addPhoto is idempotent, so an already-
        -- filed photo just no-ops). Record the id for the post-loop cleanup.
        batch_set_ids[#batch_set_ids + 1] = tostring(photoset_id)
        fold_set_into_records(photoset_id)
        local start = target.kind == "create" and 2 or 1
        for i = start, uploaded do
          local item = extra_data.uploaded[i]
          local ok, err = __dtrmflickr_call("flickr.photosets.addPhoto", function()
            return rest.photosets_add_photo(extra_data.api_key, extra_data.api_secret, extra_data.account,
              photoset_id, item.photo_id)
          end)
          if ok or photoset_add_is_already_present(err) then
            state.add_set(item.image, extra_data.account.nsid, photoset_id)
          else
            album_errors = album_errors + 1
            dt.print(string.format(_("Flickr: could not add photo %s to album: %s"), tostring(item.photo_id), tostring(err)))
            dt.print_log(string.format("[dtrmflickr] finalize: add photo_id=%s photoset=%s failed: %s",
              tostring(item.photo_id), tostring(photoset_id), tostring(err)))
          end
        end
      end
    end

    -- (#79) Album filing done: drop the resume record for every uploaded image
    -- whose metadata is clean AND which is now confirmed in every batch set (so a
    -- clean batch leaves an EMPTY blob, matching #78). An image that failed a
    -- setter (post_failed) keeps its record for the metadata replay; an image not
    -- in some batch set (a failed addPhoto, or a never-created album) keeps its
    -- record so resume re-files the remainder. Guarded so it never breaks finalize.
    if __dtrmflickr_resume and __dtrmflickr_resume.remove_pending then
      pcall(function()
        local ur = require("dtrmflickr.upload_resume")
        for _, item in ipairs(extra_data.uploaded) do
          if not item.post_failed then
            local member = {}
            for _, sid in ipairs(state.get_sets(item.image, extra_data.account.nsid) or {}) do
              member[tostring(sid)] = true
            end
            local all_filed = true
            for _, sid in ipairs(batch_set_ids) do
              if not member[sid] then all_filed = false break end
            end
            if all_filed then
              __dtrmflickr_resume.remove_pending(ur.image_key(item.image), extra_data.account.nsid)
            end
          end
        end
      end)
    end
  end

  for _, conflict in ipairs(extra_data.keyword_conflicts or {}) do
    dt.print(rules.format_keyword_conflict(conflict))
  end

  -- Split uploads into freshly-created vs replaced-in-place so a mixed batch
  -- reads "3 uploaded, 2 updated" rather than folding replaces into the
  -- uploaded count (issue #60). When nothing was replaced the summary keeps its
  -- historical single-count shape.
  local fresh_uploads, replaced_uploads = report.uploaded_counts(extra_data)
  dt.print(report.finalize_summary({
    uploaded = fresh_uploads, updated = replaced_uploads, skipped = skipped,
    failed = failed, post_errors = post_errors, album_errors = album_errors, total = total,
  }, { translate = _ }))
  -- Name *which* images failed/were skipped, not just how many. The per-image
  -- dt.print messages emitted during store scroll out of view on a large batch,
  -- so without this the count line is the only end-state the user sees.
  for _, line in ipairs(report.finalize_detail_lines(extra_data, { translate = _ })) do
    dt.print(line)
  end
  -- Show where each upload landed: the public Flickr photo URL (issue #37).
  -- Capped to keep the transient toast readable; the full set is in the
  -- per-image result table logged below.
  local report_owner = extra_data.account and extra_data.account.nsid
  for _, line in ipairs(report.uploaded_url_lines(extra_data, { translate = _, owner = report_owner })) do
    dt.print(line)
  end
  if keyword_conflicts > 0 then
    dt.print(string.format(_("Flickr: %d keyword rule conflict(s); see messages above"), keyword_conflicts))
  end
  if tag_limit_warnings > 0 then
    dt.print(string.format(_("Flickr: %d image(s) had keywords truncated to Flickr's %d-tag limit"),
      tag_limit_warnings, FLICKR_TAG_LIMIT))
  end
  dt.print_log(string.format("[dtrmflickr] finalize: uploaded=%d updated=%d skipped=%d failed=%d post_errors=%d album_errors=%d keyword_conflicts=%d tag_limit_warnings=%d total=%d",
    fresh_uploads, replaced_uploads, skipped, failed, post_errors, album_errors, keyword_conflicts, tag_limit_warnings, total))
  -- Full per-image result grid (status + id/reason/error per row) goes to the
  -- log rather than the transient panel toast: it is the complete record for a
  -- large batch, where a multi-line grid in a toast would be unreadable. The
  -- compact named lines above are the panel-facing summary.
  for _, line in ipairs(report.result_table_lines(extra_data, { translate = _, owner = report_owner })) do
    dt.print_log("[dtrmflickr] " .. line)
  end
  -- Surface the same result as a clear, persistent table in the export panel
  -- (issue #40): the toast above is transient and the log is buried, so the
  -- panel keeps the summary + a capped per-image grid visible after the export.
  upload_result_label.label = report.result_panel_text({
    uploaded = fresh_uploads, updated = replaced_uploads, skipped = skipped,
    failed = failed, post_errors = post_errors, album_errors = album_errors, total = total,
  }, extra_data, { translate = _, owner = report_owner })
  -- darktable labels are not clickable, so stash this batch's uploaded Flickr
  -- URLs for the export panel's open/copy buttons and enable them when there is
  -- at least one (issue #40 follow-up).
  last_upload_links = report.uploaded_links(extra_data, report_owner)
  local has_upload_links = #last_upload_links > 0
  upload_open_button.sensitive = has_upload_links
  upload_copy_button.sensitive = has_upload_links
  -- Fill the batch progress bar and remove it from the background-jobs area.
  -- Guarded against an absent/invalidated job (older darktable, or a cancel).
  if extra_data.progress_job and extra_data.progress_job.valid then
    extra_data.progress_job.percent = 1
    extra_data.progress_job.valid = false
  end
  extra_data.progress_job = nil
end

----------------------------------------------------------------------
-- script_manager integration + registration.
----------------------------------------------------------------------
local script_data = {}
script_data.metadata = {
  name = "Flickr",
  purpose = _("export images to Flickr"),
  author = "dtrmflickr",
}
script_data.destroy_method = "hide"
function script_data.destroy()
  -- Capture any still-pending async work into the durable store before teardown
  -- (issue #55). On a clean drain the on_event hook has already cleared the blob;
  -- this only writes when live records remain, so a script reload / darktable
  -- quit mid-pump leaves a resumable blob for the next start to classify.
  if __dtrmflickr_resume then __dtrmflickr_resume.persist() end
  dt.destroy_storage(STORAGE)
  if dt.destroy_event then dt.destroy_event(PLUGIN .. "_selection_changed", "selection-changed") end
  if dt.gui.libs and dt.gui.libs[PANEL] then dt.gui.libs[PANEL].visible = false end
end
function script_data.restart()
  if dt.gui.libs and dt.gui.libs[PANEL] then
    dt.gui.libs[PANEL].visible = true
    refresh_panel(true, false)
  end
end
script_data.show = script_data.restart
